/* AUTO-GENERATED — South Carolina Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["SC"] = {"code":"SC","name":"South Carolina","agency":"South Carolina SCDMV","agencyShort":"SCDMV","handbook":"https://dmv.sc.gov/sites/scdmv/files/media/Files/CDL-Manual.pdf","links":{},"en":[{"q":"On South Carolina highways, what is the maximum total outside width of a vehicle or its load, exclusive of approved safety devices?","options":["96 inches","102 inches","108 inches","120 inches"],"answer":1,"explanation":"South Carolina Code 56-5-4030 sets the maximum total outside width of a vehicle or load at 102 inches (8 feet 6 inches), excluding approved safety devices. This matches the federal standard adopted statewide. Source: SC Code 56-5-4030 (Width of vehicles).","handbook":"","hbref":""},{"q":"What is the maximum height for most vehicles, unladen or loaded, on South Carolina highways?","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"answer":1,"explanation":"South Carolina Code 56-5-4060 limits vehicle height to 13 feet 6 inches. A narrow exception allows 14 feet for an automobile transporter unit or saddle-mount combination with a valid SCDOT routing permit. Source: SC Code 56-5-4060 (Height of vehicles).","handbook":"","hbref":""},{"q":"What is the maximum length for a single motor vehicle (such as a straight truck) in South Carolina, including bumpers and load?","options":["35 feet","40 feet","45 feet","48 feet"],"answer":1,"explanation":"South Carolina Code 56-5-4070 limits a single motor vehicle to 40 feet extreme overall length, inclusive of front and rear bumpers and load. Buses and certain motor homes are treated separately. Source: SC Code 56-5-4070 (Length of vehicles).","handbook":"","hbref":""},{"q":"In a two-unit truck tractor-semitrailer combination, what is the maximum length of the trailer or semitrailer (including load) in South Carolina?","options":["48 feet","50 feet","53 feet","57 feet"],"answer":2,"explanation":"South Carolina Code 56-5-4070 allows a trailer or semitrailer in a two-unit truck tractor combination to be up to 53 feet, inclusive of the load. A 53-foot trailer must have a rear underride guard. Source: SC Code 56-5-4070.","handbook":"","hbref":""},{"q":"In South Carolina, what is the maximum gross weight a single axle may impose on the highway?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"answer":1,"explanation":"South Carolina Code 56-5-4140 limits the gross weight on any one axle to 20,000 pounds. This is the same as the federal single-axle limit. Source: SC Code 56-5-4140 (Gross weight of vehicles).","handbook":"","hbref":""},{"q":"What is the maximum overall gross vehicle weight allowed in South Carolina without a special permit?","options":["73,280 pounds","76,000 pounds","80,000 pounds","88,000 pounds"],"answer":2,"explanation":"South Carolina Code 56-5-4140 caps overall gross weight at 80,000 pounds except for vehicles issued special permits by SCDOT. This mirrors the federal interstate maximum. Source: SC Code 56-5-4140.","handbook":"","hbref":""},{"q":"On South Carolina Interstate highways, what is the maximum gross weight allowed on a tandem axle group (including enforcement tolerance)?","options":["32,000 pounds","34,000 pounds","35,200 pounds","36,000 pounds"],"answer":2,"explanation":"On the Interstate system, South Carolina allows a tandem-axle gross weight of 35,200 pounds, which includes the state's enforcement tolerance over the 34,000-pound federal base. Source: SC Code 56-5-4140; SCDMV/SCDOT size-weight guidance.","handbook":"","hbref":""},{"q":"On South Carolina non-Interstate (state) highways, what is the maximum gross weight permitted on a tandem axle group spaced 40 to 96 inches apart?","options":["34,000 pounds","35,200 pounds","36,000 pounds","40,000 pounds"],"answer":2,"explanation":"South Carolina Code 56-5-4140 allows up to 36,000 pounds on a tandem axle (two or more consecutive axles spaced 40 to 96 inches apart) on highways other than the Interstate. The Interstate tandem limit is lower at 35,200 pounds. Source: SC Code 56-5-4140.","handbook":"","hbref":""},{"q":"What formula does South Carolina use to determine the allowable gross weight on a group of axles based on the spacing between them?","options":["The Federal Bridge Formula (Formula B)","The Gross Combination Weight Rating formula","The Davis rolling-resistance formula","The single-axle tolerance formula"],"answer":0,"explanation":"South Carolina applies the Federal Bridge Formula (Bridge Formula B) to set the maximum weight on any group of two or more consecutive axles based on axle spacing and number of axles, consistent with 23 U.S.C. 127. Source: SC Code 56-5-4140; FHWA Federal Bridge Formula.","handbook":"","hbref":""},{"q":"Which South Carolina state agency issues oversize/overweight (OSOW) permits for vehicles and loads exceeding legal limits?","options":["The SC Department of Motor Vehicles (SCDMV)","The SC Department of Public Safety (SCDPS)","The SC Department of Transportation (SCDOT)","The SC Department of Revenue (SCDOR)"],"answer":2,"explanation":"The South Carolina Department of Transportation (SCDOT) Oversize/Overweight Permit Office issues OSOW permits at its discretion for loads that exceed legal size or weight limits. Source: SCDOT Oversize/Overweight Permits program.","handbook":"","hbref":""},{"q":"When is an oversize permit generally required in South Carolina for a load's width?","options":["When width exceeds 96 inches","When width exceeds 102 inches (8'6\")","When width exceeds 120 inches (10')","When width exceeds 144 inches (12')"],"answer":1,"explanation":"Because South Carolina's legal width limit is 102 inches (8 feet 6 inches), any load wider than that requires an SCDOT oversize permit. Source: SC Code 56-5-4030; SCDOT OSOW permit guidelines.","handbook":"","hbref":""},{"q":"How can a carrier apply for a South Carolina oversize/overweight permit?","options":["Only by mailing a paper form to the SCDMV","Through SCDOT's online SafeHaul system (or by phone/mail/email)","Only in person at a county courthouse","Through the FMCSA national portal"],"answer":1,"explanation":"Carriers obtain OSOW permits through SCDOT's online SafeHaul (iHaul) system, or by contacting the SCDOT OSOW Permit Office by phone, mail, or email. Source: SCDOT Oversize/Overweight Permits page (SafeHaul).","handbook":"","hbref":""},{"q":"Under South Carolina's farm/forestry exemption, self-propelled farming equipment and forestry machinery may move without an oversize permit during daylight provided they do not exceed which width?","options":["8 feet 6 inches","10 feet","12 feet","14 feet"],"answer":2,"explanation":"South Carolina allows farming equipment, forestry machinery, and similar equipment to move during daylight without a permit if it does not exceed 12 feet wide, 13 feet 6 inches high, or 90,000 pounds. Source: SCDOT OSOW guidelines (agricultural/forestry exemption).","handbook":"","hbref":""},{"q":"On a South Carolina two-lane highway, at what width does a permitted load begin to require a front escort (pilot) vehicle?","options":["Over 10 feet","Over 12 feet","Over 14 feet","Over 16 feet"],"answer":1,"explanation":"On two-lane highways, South Carolina requires a front escort for loads exceeding 12 feet up to 14 feet wide; loads over 14 feet up to 16 feet require front and rear escorts. Source: SCDOT OSOW escort/pilot-car requirements.","handbook":"","hbref":""},{"q":"For a 53-foot semitrailer in South Carolina, the distance from the kingpin to the center of the rear axle (or rear tandem assembly) may not exceed what value?","options":["37 feet","41 feet","43 feet","46 feet"],"answer":1,"explanation":"South Carolina Code 56-5-4070 requires that on a 53-foot trailer the kingpin-to-rear-axle (or rear tandem center) distance be no greater than 41 feet. Source: SC Code 56-5-4070.","handbook":"","hbref":""},{"q":"What enforcement tolerance does South Carolina generally apply to weight limits on non-Interstate highways?","options":["5 percent","10 percent","15 percent","No tolerance is allowed"],"answer":1,"explanation":"South Carolina applies a 10% enforcement tolerance on weight limits for non-Interstate (state and supplemental) highways. Interstate weights are enforced more strictly within stated tolerances. Source: SCDOT/SCDMV size-weight guidance; SC Code 56-5-4140.","handbook":"","hbref":""},{"q":"Under the 14-foot height exception in South Carolina, an automobile transporter or saddle-mount combination must additionally have what?","options":["A waiver from the FMCSA","A valid routing permit issued by SCDOT","A hazardous materials endorsement","Written approval from the county sheriff"],"answer":1,"explanation":"South Carolina Code 56-5-4060 allows up to 14 feet for an auto transporter unit or saddle-mount combination only if the owner/operator holds a valid routing permit issued by SCDOT. Source: SC Code 56-5-4060.","handbook":"","hbref":""},{"q":"What is the maximum length allowed for a motor home in South Carolina, provided its turning radius is 48 feet or less?","options":["40 feet","42 feet","45 feet","48 feet"],"answer":2,"explanation":"South Carolina Code 56-5-4070 permits a motor home up to 45 feet in length if its turning radius is 48 feet or less, an exception to the general 40-foot single-vehicle limit. Source: SC Code 56-5-4070.","handbook":"","hbref":""},{"q":"Appurtenances on motor homes, travel trailers, and truck campers in noncommercial use may extend beyond the legal width by how much in South Carolina?","options":["Up to 3 inches on each side","Up to 6 inches on one side and 4 inches on the other","Up to 12 inches on one side only","No extension beyond legal width is allowed"],"answer":1,"explanation":"South Carolina Code 56-5-4030 allows appurtenances on noncommercial motor homes, travel trailers, and truck campers to extend a maximum of 6 inches on one side and 4 inches on the other beyond the 102-inch width limit. Source: SC Code 56-5-4030.","handbook":"","hbref":""},{"q":"A typical single-trip SCDOT oversize/overweight permit for a standard wide load costs approximately how much?","options":["$10","$30","$75","$150"],"answer":1,"explanation":"SCDOT charges about $30 for a standard single-trip OSOW permit, with an annual (multiple-trip) permit around $100; higher fees apply to extreme widths over 16 feet. Source: SCDOT Oversize/Overweight Permits fee schedule.","handbook":"","hbref":""},{"q":"In South Carolina, which CDL class is required to operate a combination of vehicles with a Gross Combination Weight Rating (GCWR) of 26,001 pounds or more where the towed unit has a GVWR over 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"South Carolina (SCDMV, Classes A, B, and C) defines a Class A CDL as any combination of vehicles with a GCWR of 26,001 lbs or more, provided the GVWR of the vehicle being towed is more than 10,000 lbs. Source: SCDMV Commercial Licenses, Classes A, B, and C.","handbook":"","hbref":""},{"q":"Per the SCDMV, a single-unit vehicle with a GVWR of 26,001 pounds or more (towing nothing over 10,000 lbs) requires which CDL class?","options":["Class C","Class B","Class A","Class E"],"answer":1,"explanation":"South Carolina defines a Class B CDL as any single-unit vehicle with a GVWR of 26,001 lbs or more, or such a vehicle towing a unit that does not weigh more than 10,000 lbs. Source: SCDMV Commercial Licenses, Classes A, B, and C.","handbook":"","hbref":""},{"q":"Under South Carolina rules, a vehicle that does not meet Class A or B weight thresholds but is designed to transport 16 or more people (including the driver) requires which CDL class?","options":["Class A","Class B","Class C","No CDL is required"],"answer":2,"explanation":"South Carolina defines a Class C CDL as any single vehicle, or combination, that is not Class A or B but is designed to carry 16 or more people including the driver, or is used to transport placarded hazardous materials. Source: SCDMV Commercial Licenses, Classes A, B, and C.","handbook":"","hbref":""},{"q":"In South Carolina, what is the minimum age to obtain a CDL for INTRASTATE driving (operating only within the state)?","options":["16 years old","17 years old","18 years old","21 years old"],"answer":2,"explanation":"SCDMV requires applicants to be at least 18 to drive commercially within South Carolina (intrastate). Drivers under 21 may not drive outside the state. Source: SCDMV, Getting Your First CDL.","handbook":"","hbref":""},{"q":"What is the minimum age in South Carolina to hold a CDL valid for INTERSTATE driving (across state lines)?","options":["18 years old","19 years old","21 years old","25 years old"],"answer":2,"explanation":"SCDMV requires drivers to be at least 21 to operate a commercial vehicle outside South Carolina (interstate). Drivers 18-20 are restricted to intrastate operation. Source: SCDMV, Getting Your First CDL.","handbook":"","hbref":""},{"q":"Before a South Carolina applicant may take the CDL skills (road) test, how long must they hold their Commercial Learner Permit (CLP)?","options":["At least 7 calendar days","At least 14 calendar days","At least 30 calendar days","At least 60 calendar days"],"answer":1,"explanation":"South Carolina follows the federal rule requiring a CLP to be held for at least 14 calendar days before the applicant may take the CDL skills test. Source: SCDMV, Getting Your First CDL (49 CFR 383.25).","handbook":"","hbref":""},{"q":"Which endorsement code does South Carolina use for authorization to operate a vehicle transporting placarded hazardous materials?","options":["N","T","H","P"],"answer":2,"explanation":"The H endorsement covers hazardous materials requiring placards. South Carolina uses the standard federal endorsement codes: H (HazMat), N (Tank), T (Doubles/Triples), P (Passenger), S (School Bus). Source: SCDMV Commercial Licenses.","handbook":"","hbref":""},{"q":"In South Carolina, before a HazMat (H) endorsement can be issued or renewed, an applicant must pass which additional screening?","options":["A TSA security threat assessment (background check and fingerprinting)","A physical agility and lifting test","A defensive driving course certification","A vision exam administered by SCDMV"],"answer":0,"explanation":"South Carolina requires HazMat (H) applicants to pass a federal Transportation Security Administration (TSA) security threat assessment, which includes fingerprinting and a background check, for both original and renewal endorsements. Source: SCDMV; 49 CFR 1572.","handbook":"","hbref":""},{"q":"Which endorsement is required in South Carolina to drive a commercial vehicle designed to transport liquids or gases in a bulk tank?","options":["P (Passenger)","N (Tank Vehicle)","T (Doubles/Triples)","S (School Bus)"],"answer":1,"explanation":"The N (Tank Vehicle) endorsement is required to operate a vehicle hauling liquids or gases in bulk tanks meeting the federal definition. Source: SCDMV Commercial Licenses; 49 CFR 383.93.","handbook":"","hbref":""},{"q":"In South Carolina, which endorsement is required to pull double or triple trailers?","options":["T endorsement","N endorsement","H endorsement","X endorsement"],"answer":0,"explanation":"The T endorsement authorizes operation of double and triple trailers. South Carolina uses the standard federal codes. Source: SCDMV Commercial Licenses; 49 CFR 383.93.","handbook":"","hbref":""},{"q":"Which endorsement must a South Carolina driver obtain to operate a commercial bus or van designed to carry the required threshold number of passengers?","options":["S (School Bus)","P (Passenger)","N (Tank)","T (Doubles/Triples)"],"answer":1,"explanation":"The P (Passenger) endorsement is required to operate a vehicle designed to transport 16 or more people including the driver. A separate S endorsement is needed for school buses. Source: SCDMV Commercial Licenses.","handbook":"","hbref":""},{"q":"In South Carolina, what does a driver need to operate a school bus that requires a CDL?","options":["Only the P (Passenger) endorsement","Both the P (Passenger) and S (School Bus) endorsements","Only the H (HazMat) endorsement","No endorsement, just a Class B CDL"],"answer":1,"explanation":"To drive a school bus in South Carolina, a driver must hold both the P (Passenger) and S (School Bus) endorsements, and pass the school bus knowledge and skills tests. Source: SCDMV Commercial Licenses; 49 CFR 383.93.","handbook":"","hbref":""},{"q":"For a South Carolina CLP/CDL applicant who got their permit on or after February 7, 2022, what training must be completed before the skills test for a first CDL?","options":["A state-only SCDMV classroom course","FMCSA-approved Entry-Level Driver Training (ELDT) from a registered provider","A 160-hour apprenticeship logged with SCDMV","No training is required, only the skills test"],"answer":1,"explanation":"South Carolina requires applicants who obtained a CLP on or after Feb 7, 2022 to complete FMCSA-approved Entry-Level Driver Training (ELDT) from a provider listed on the FMCSA Training Provider Registry before taking the skills test. Source: SCDMV, Getting Your First CDL; FMCSA ELDT rule.","handbook":"","hbref":""},{"q":"Under the federal ELDT rule applied in South Carolina, ELDT is required for a first CDL and for which set of endorsements?","options":["H (HazMat), P (Passenger), and S (School Bus)","N (Tank), T (Doubles/Triples), and H (HazMat)","P (Passenger), N (Tank), and T (Doubles/Triples)","All five endorsements (H, N, T, P, S)"],"answer":0,"explanation":"ELDT is required for an initial Class A or B CDL, an upgrade, and for the HazMat (H), Passenger (P), and School Bus (S) endorsements. It is not required for the N (Tank) or T (Doubles/Triples) endorsements. Source: FMCSA ELDT rule; SCDMV.","handbook":"","hbref":""},{"q":"How many medical self-certification categories must a South Carolina CDL applicant choose from when certifying the type of commerce they operate in?","options":["Two","Three","Four","Five"],"answer":2,"explanation":"Federal rules adopted by South Carolina require CDL holders to self-certify into one of four categories: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, or Excepted Intrastate. Source: SCDMV; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"A South Carolina CDL driver who hauls freight across state lines and must meet federal DOT physical standards should self-certify in which category?","options":["Excepted Interstate","Non-Excepted Interstate","Non-Excepted Intrastate","Excepted Intrastate"],"answer":1,"explanation":"A driver operating in interstate commerce who is subject to and must meet the federal physical qualification standards (49 CFR Part 391) certifies as Non-Excepted Interstate and must keep a valid medical examiner's certificate. Source: SCDMV; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Which document is NOT among those the SCDMV requires a first-time CDL applicant to provide for identity, Social Security, residency, and lawful presence verification?","options":["Proof of identity and date of birth","Proof of Social Security number","Two proofs of South Carolina residency","A signed letter of employment from a trucking company"],"answer":3,"explanation":"SCDMV requires proof of identity/lawful presence, a Social Security number, and South Carolina residency (per the document checklist, e.g., Form MV-93). An employer letter is not a required identity/residency document. Source: SCDMV, Getting Your First CDL document checklist.","handbook":"","hbref":""},{"q":"In South Carolina, which applicants are eligible to apply for a CDL HazMat (H) endorsement?","options":["Any CDL holder regardless of citizenship","Only U.S. citizens and lawful permanent residents","Only drivers age 25 and older","Only drivers who already hold the X combined endorsement"],"answer":1,"explanation":"Because of the TSA security threat assessment, only U.S. citizens and lawful permanent residents are eligible for a CDL HazMat (H) endorsement in South Carolina. Source: SCDMV; TSA HME program (49 CFR 1572).","handbook":"","hbref":""},{"q":"Which endorsements may a South Carolina driver obtain while still holding only a Commercial Learner Permit (CLP)?","options":["H (HazMat) and T (Doubles/Triples) only","N (Tank), P (Passenger), and S (School Bus) only","All five endorsements","None - no endorsements are allowed on a CLP"],"answer":1,"explanation":"A South Carolina CLP may carry only the N (Tank, restricted to empty tanks), P (Passenger, no passengers besides trainers/examiners), and S (School Bus) endorsements. The H and T endorsements cannot be held on a CLP. Source: SCDMV, Getting Your First CDL; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"In South Carolina, what does the combined 'X' endorsement on a CDL signify?","options":["Authorization for both Tank (N) and HazMat (H) operations","Authorization for Doubles/Triples (T) and Passenger (P)","A restriction prohibiting interstate driving","A school bus operator certification"],"answer":0,"explanation":"The X endorsement is a combined code indicating the driver holds both the Tank (N) and HazMat (H) endorsements, allowing transport of hazardous materials in a tank vehicle. Source: SCDMV Commercial Licenses; 49 CFR 383.153.","handbook":"","hbref":""},{"q":"In South Carolina, what is the maximum blood alcohol concentration (BAC) at which it is legal to operate a commercial motor vehicle (CMV)?","options":["Below 0.04%","Below 0.08%","Below 0.02%","Below 0.05%"],"answer":0,"explanation":"South Carolina follows the federal CMV standard: it is illegal to operate a CMV if your BAC is 0.04% or more, so legal operation requires a BAC below 0.04%. Source: SCDMV Commercial Driver's License Manual, Section 1.3.2 (49 CFR 383.51).","handbook":"","hbref":""},{"q":"Under South Carolina's implied-consent rule for CMV operators, what happens if a driver has a detectable amount of alcohol that is below 0.04%?","options":["Placed out-of-service for 24 hours","Disqualified for 60 days","Disqualified for one year","Issued only a warning with no action"],"answer":0,"explanation":"South Carolina places a CMV driver out-of-service for 24 hours if any detectable amount of alcohol under 0.04% is found. A BAC of 0.04% or higher triggers a disqualification instead. Source: SCDMV CDL Manual, Section 1.3.2.","handbook":"","hbref":""},{"q":"By operating a CMV in South Carolina, a driver is automatically deemed to have done what regarding chemical testing?","options":["Given consent to alcohol testing","Waived the right to a hearing","Agreed to annual drug screening","Consented to a vehicle search"],"answer":0,"explanation":"Under implied consent, anyone who operates a CMV in South Carolina is deemed to have given consent to alcohol testing. Source: SCDMV CDL Manual, Section 1.3.2.","handbook":"","hbref":""},{"q":"What is the minimum disqualification period in South Carolina for a CMV driver's first major offense, such as a DUI or driving a CMV with a BAC of 0.04% or higher?","options":["1 year","60 days","6 months","3 years"],"answer":0,"explanation":"A first major offense (DUI, 0.04%+ BAC in a CMV, test refusal, leaving the scene, etc.) carries a minimum disqualification of at least one year in South Carolina. Source: SCDMV CDL Manual, Section 1.3.2 (49 CFR 383.51).","handbook":"","hbref":""},{"q":"In South Carolina, if a major offense (such as a DUI) occurs while the driver is operating a CMV placarded for hazardous materials, what is the minimum disqualification period?","options":["3 years","1 year","5 years","18 months"],"answer":0,"explanation":"South Carolina increases the first-offense disqualification to at least three years when the major offense occurs while operating a CMV placarded for hazardous materials. Source: SCDMV CDL Manual, Section 1.3.2 (49 CFR 383.51).","handbook":"","hbref":""},{"q":"What is the disqualification period in South Carolina for a CMV driver's second major offense?","options":["Life","10 years","5 years","3 years"],"answer":0,"explanation":"A second major offense results in loss of the CDL for life in South Carolina. Source: SCDMV CDL Manual, Section 1.3.2 (49 CFR 383.51).","handbook":"","hbref":""},{"q":"In South Carolina, refusing to undergo blood alcohol testing as a CMV operator is treated as which type of offense for disqualification purposes?","options":["A major offense (at least 1 year)","A serious traffic violation (60 days)","An out-of-service violation (90 days)","A minor offense with no disqualification"],"answer":0,"explanation":"Refusing to undergo blood alcohol testing is listed as a major offense in South Carolina and carries a minimum one-year disqualification for a first offense, the same as a DUI. Source: SCDMV CDL Manual, Section 1.3.2.","handbook":"","hbref":""},{"q":"Under South Carolina rules, a CMV driver loses the CDL for life for a first offense if a CMV is used to commit which type of crime?","options":["A felony involving controlled substances","Any felony of any kind","A felony involving theft","Reckless driving causing injury"],"answer":0,"explanation":"Using a CMV to commit a felony involving controlled substances results in lifetime disqualification on the first offense, with no possibility of the 10-year reinstatement available for other lifetime cases. Source: SCDMV CDL Manual, Section 1.3.2.","handbook":"","hbref":""},{"q":"In South Carolina, how fast over the posted speed limit must a CMV driver be going for the violation to count as the 'excessive speeding' type of serious traffic violation?","options":["15 mph or more over the limit","10 mph or more over the limit","20 mph or more over the limit","5 mph or more over the limit"],"answer":0,"explanation":"South Carolina defines excessive speeding as a serious traffic violation when the driver is 15 mph or more above the posted speed limit. Source: SCDMV CDL Manual, Section 1.3.3.","handbook":"","hbref":""},{"q":"Which of the following is classified as a serious traffic violation for a CMV driver in South Carolina?","options":["Improper or erratic lane changes","Driving with a BAC of 0.04% or higher","Refusing a chemical test","Violating an out-of-service order"],"answer":0,"explanation":"Serious traffic violations include excessive speeding (15+ mph over), reckless driving, improper or erratic lane changes, following too closely, and certain CDL-possession offenses. The other choices are major or out-of-service offenses. Source: SCDMV CDL Manual, Section 1.3.3.","handbook":"","hbref":""},{"q":"In South Carolina, what is the minimum disqualification for committing two serious traffic violations in a CMV within a three-year period?","options":["60 days","30 days","120 days","90 days"],"answer":0,"explanation":"Two serious traffic violations within three years involving a CMV result in a disqualification of at least 60 days. Source: SCDMV CDL Manual, Section 1.3.3 (49 CFR 383.51).","handbook":"","hbref":""},{"q":"In South Carolina, what is the minimum disqualification for three or more serious traffic violations in a CMV within a three-year period?","options":["120 days","60 days","180 days","1 year"],"answer":0,"explanation":"Three or more serious traffic violations within three years involving a CMV result in a disqualification of at least 120 days. Source: SCDMV CDL Manual, Section 1.3.3 (49 CFR 383.51).","handbook":"","hbref":""},{"q":"What is the minimum disqualification in South Carolina for a driver's first violation of an out-of-service order?","options":["90 days","60 days","180 days","1 year"],"answer":0,"explanation":"A first violation of an out-of-service order carries a minimum 90-day disqualification in South Carolina. Source: SCDMV CDL Manual, Section 1.3.4 (49 CFR 383.51).","handbook":"","hbref":""},{"q":"In South Carolina, what is the minimum disqualification for a second violation of an out-of-service order within a ten-year period?","options":["1 year","90 days","120 days","3 years"],"answer":0,"explanation":"A second out-of-service order violation within a ten-year period results in a disqualification of at least one year. Source: SCDMV CDL Manual, Section 1.3.4.","handbook":"","hbref":""},{"q":"In South Carolina, what is the minimum disqualification for three or more out-of-service order violations within a ten-year period?","options":["3 years","1 year","5 years","Life"],"answer":0,"explanation":"Three or more out-of-service order violations within a ten-year period result in a disqualification of at least three years. Source: SCDMV CDL Manual, Section 1.3.4.","handbook":"","hbref":""},{"q":"What is the minimum disqualification in South Carolina for a CMV driver's first railroad-highway grade crossing violation?","options":["60 days","90 days","30 days","120 days"],"answer":0,"explanation":"A first railroad-highway grade crossing violation results in a disqualification of at least 60 days in South Carolina. Source: SCDMV CDL Manual, Section 1.3.5 (49 CFR 383.51).","handbook":"","hbref":""},{"q":"In South Carolina, what is the minimum disqualification for a second railroad-highway grade crossing violation within a three-year period?","options":["120 days","60 days","90 days","1 year"],"answer":0,"explanation":"A second railroad-highway grade crossing violation within three years results in a disqualification of at least 120 days. Source: SCDMV CDL Manual, Section 1.3.5.","handbook":"","hbref":""},{"q":"In South Carolina, what is the minimum disqualification for a third railroad-highway grade crossing violation within a three-year period?","options":["1 year","120 days","180 days","3 years"],"answer":0,"explanation":"A third railroad-highway grade crossing violation within three years results in a disqualification of at least one year. Source: SCDMV CDL Manual, Section 1.3.5.","handbook":"","hbref":""},{"q":"Under South Carolina rules, a CMV driver's CDL is disqualified for how long after a second conviction within three years for texting while operating a CMV?","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"Two or more convictions for texting while operating a CMV trigger disqualification: 60 days for the second offense within three years and 120 days for three or more within three years. Drivers also face civil penalties up to $2,750. Source: SCDMV CDL Manual, Sections 2.9.6 and 2.9.5.","handbook":"","hbref":""},{"q":"Under South Carolina's Hands-Free and Distracted Driving Act, what is the fine for a first offense of holding a mobile device while driving?","options":["$100 plus court fees","$25 plus court fees","$200 plus court fees","$500 plus court fees"],"answer":0,"explanation":"South Carolina's Hands-Free and Distracted Driving Act (S.C. Code Section 56-5-3890) sets a $100 fine plus court fees for a first offense and $200 plus two points for a second offense within three years; for CMV drivers two convictions within three years also bring a 60-day disqualification. Source: SCDPS Hands Free SC; S.C. Code 56-5-3890.","handbook":"","hbref":""},{"q":"On a South Carolina interstate, what is the maximum speed limit for a commercial truck that is not otherwise posted lower?","options":["65 mph, because trucks have a lower limit than cars","70 mph, the same as for other vehicles","60 mph on all sections of the interstate","55 mph for any vehicle over 26,001 lbs"],"answer":1,"explanation":"South Carolina does NOT set a separate, lower truck speed limit. Under S.C. Code 56-5-1520, the maximum on the interstate highway system is 70 mph, and large trucks are bound by the same posted limit. Source: S.C. Code 56-5-1520; SCDMV CDL Manual.","handbook":"","hbref":""},{"q":"Under South Carolina law, what is the maximum speed limit on a multilane divided primary highway (not an interstate) unless otherwise posted?","options":["55 mph","65 mph","60 mph","70 mph"],"answer":2,"explanation":"S.C. Code 56-5-1520 sets 60 mph as the maximum on multilane divided primary highways, 70 mph on the interstate system, and 55 mph on other (undivided) highways. Source: S.C. Code 56-5-1520.","handbook":"","hbref":""},{"q":"South Carolina's 'Move Over' law (S.C. Code 56-5-1538) requires a driver approaching a stopped emergency vehicle displaying flashing lights to do what FIRST, if it can be done safely?","options":["Come to a complete stop until the emergency vehicle leaves","Vacate the lane nearest the emergency vehicle by changing into a non-adjacent lane","Sound the horn and continue at the posted speed","Pull onto the shoulder behind the emergency vehicle"],"answer":1,"explanation":"Under S.C. Code 56-5-1538, the driver must yield by changing into a lane not adjacent to the stopped authorized emergency vehicle (ambulance, police, fire, rescue, recovery, or towing vehicle) when it is safe to do so. Source: S.C. Code 56-5-1538; SCDPS.","handbook":"","hbref":""},{"q":"Under South Carolina's Move Over law, what must a driver do if changing lanes away from a stopped emergency vehicle is not possible or not safe?","options":["Stop completely in the current lane","Maintain the posted speed but turn on the four-way flashers","Proceed with caution and significantly reduce speed","Exit at the nearest ramp and take an alternate route"],"answer":2,"explanation":"S.C. Code 56-5-1538 requires a driver who cannot safely change lanes to proceed with due caution and significantly reduce the vehicle's speed, maintaining a safe speed for road conditions. Source: S.C. Code 56-5-1538; SCDPS.","handbook":"","hbref":""},{"q":"When a placarded vehicle stops at a railroad crossing in South Carolina, where must it stop relative to the nearest rail?","options":["Between 15 and 50 feet from the nearest rail","Between 10 and 25 feet from the nearest rail","Between 50 and 100 feet from the nearest rail","Within 15 feet of the nearest rail"],"answer":0,"explanation":"The SCDMV CDL Manual and S.C. Code 56-5-2720 require a placarded vehicle to stop within 50 feet but not less than 15 feet from the nearest rail. Source: SCDMV CDL Manual 9.6.12; S.C. Code 56-5-2720.","handbook":"","hbref":""},{"q":"Which of the following vehicles must always stop at every railroad crossing in South Carolina (unless the crossing is exempt)?","options":["A loaded dump truck","A bus carrying passengers","An empty flatbed trailer","A pickup pulling a utility trailer"],"answer":1,"explanation":"A bus transporting passengers, a school bus, and any placarded/hazardous-cargo vehicle must stop at every railroad crossing (15 to 50 feet from the nearest rail) and look and listen. Source: SCDMV CDL Manual; S.C. Code 56-5-2720.","handbook":"","hbref":""},{"q":"While any part of your commercial vehicle is crossing the railroad tracks in South Carolina, the CDL Manual instructs you NOT to do which of the following?","options":["Keep your hands on the wheel","Look both directions along the track","Shift or change gears","Watch for a second train"],"answer":2,"explanation":"The SCDMV CDL Manual states: do not stop, change gears, or change lanes while any part of your vehicle is crossing the tracks. Pick a gear that will let you clear the tracks without shifting. Source: SCDMV CDL Manual 2.15.4 / 13.1.8.","handbook":"","hbref":""},{"q":"In South Carolina, a driver meeting a stopped school bus that is displaying flashing red lights is NOT required to stop when traveling in the opposite direction on which kind of roadway?","options":["Any two-lane road with a center turn lane","A multi-lane highway","Any road with a posted limit above 45 mph","A road with a painted (non-raised) median stripe"],"answer":1,"explanation":"Under S.C. Code 56-5-2770, a driver need not stop upon meeting a stopped school bus when traveling in the opposite direction on a multi-lane highway. Drivers in the same direction, and on two-lane roads, must still stop. Source: S.C. Code 56-5-2770.","handbook":"","hbref":""},{"q":"A driver traveling in the SAME direction behind a South Carolina school bus that has activated its flashing red lights and stop arm must do what?","options":["Slow to 15 mph and pass with caution","Stop and remain stopped until the bus moves or the red lights stop flashing","Pass only on the left if no children are visible","Stop only if the bus is on an undivided two-lane road"],"answer":1,"explanation":"S.C. Code 56-5-2770 requires a vehicle approaching from either direction (other than the opposite-direction multi-lane exception) to stop before reaching a school bus with flashing red lights and not proceed until the bus resumes motion or the red lights are no longer actuated. Source: S.C. Code 56-5-2770.","handbook":"","hbref":""},{"q":"When a CMV is stopped on a two-lane road carrying traffic in both directions in South Carolina, where should the three warning triangles be placed?","options":["All three within 10 feet of the rear of the vehicle","Within 10 feet of the vehicle, plus 100 feet behind and 100 feet ahead","10 feet, 200 feet, and 500 feet behind the vehicle","One at the vehicle and two side by side 50 feet behind"],"answer":1,"explanation":"On a two-way/undivided road the SCDMV CDL Manual directs placing one triangle within 10 feet of the front or rear, and one 100 feet behind and one 100 feet ahead of the vehicle. Source: SCDMV CDL Manual 2.5 (Warning Devices).","handbook":"","hbref":""},{"q":"When a CMV is stopped on a one-way or divided highway in South Carolina, the warning devices should be placed at what distances back toward approaching traffic?","options":["10 feet, 100 feet, and 200 feet","10 feet, 50 feet, and 100 feet","25 feet, 100 feet, and 300 feet","100 feet, 200 feet, and 300 feet"],"answer":0,"explanation":"On a one-way or divided highway the SCDMV CDL Manual directs placing the three reflective triangles at 10 feet, 100 feet, and 200 feet toward the approaching traffic. Source: SCDMV CDL Manual 2.5.","handbook":"","hbref":""},{"q":"After stopping on the shoulder of a South Carolina highway, within how many minutes must a CMV driver put out the emergency warning devices?","options":["5 minutes","10 minutes","15 minutes","30 minutes"],"answer":1,"explanation":"The SCDMV CDL Manual states that if you must stop on a road or shoulder you must put out your emergency warning devices within 10 minutes. Source: SCDMV CDL Manual 2.5.","handbook":"","hbref":""},{"q":"South Carolina's left-lane ('Move Right') law for controlled-access highways generally restricts the far left lane to which use?","options":["Vehicles traveling at or above the posted limit","Overtaking and passing another vehicle","Vehicles under 10,000 lbs only","Carpool and transit vehicles"],"answer":1,"explanation":"Under S.C. Code 56-5-1885, drivers may use the farthest left lane of a controlled-access highway only when overtaking and passing. Source: S.C. Code 56-5-1885; SCDPS Move Right Law.","handbook":"","hbref":""},{"q":"South Carolina's left-lane law gives a specific exemption to a commercial motor vehicle that cannot move out of the left lane safely because of what condition?","options":["A passenger asleep in the sleeper berth","A highway grade, or another vehicle passing on the right","Carrying a hazardous-materials placard","Operating at night with reduced visibility"],"answer":1,"explanation":"Under S.C. Code 56-5-1885, a CMV driver is excused from the left-lane restriction when unable to safely merge right due to a highway grade or because another vehicle is overtaking/passing on the right. Source: S.C. Code 56-5-1885; SCDPS.","handbook":"","hbref":""},{"q":"Driving a bus in South Carolina, you approach a drawbridge that has NO signal light and NO traffic-control attendant. What must you do?","options":["Cross at reduced speed without stopping","Stop at least 50 feet before the draw and confirm it is fully closed","Stop 15 to 50 feet before the draw","Stop only if the warning bell is ringing"],"answer":1,"explanation":"The SCDMV CDL Manual (4.3.6) directs bus drivers to stop at drawbridges that have no signal light or attendant, stopping at least 50 feet before the draw and confirming it is completely closed before crossing. Source: SCDMV CDL Manual 4.3.6.","handbook":"","hbref":""},{"q":"Which violation list triggers a first South Carolina CDL disqualification of at least 60 days?","options":["Following too closely","A railroad-highway grade crossing violation","An overweight axle citation","Failure to display a required placard"],"answer":1,"explanation":"The SCDMV CDL Manual states a CDL holder loses the CDL for at least 60 days for a first railroad-highway grade crossing violation, 120 days for a second within three years, and one year for a third. Source: SCDMV CDL Manual 1.3.5; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In South Carolina, what is the standard maximum legal vehicle/load WIDTH before an oversize permit is required?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"answer":1,"explanation":"South Carolina's legal width limit is 8 feet 6 inches (102 inches); loads wider than this require an SCDOT oversize permit. Maximum legal height is 13 feet 6 inches. Source: SCDOT Oversize/Overweight Permits.","handbook":"","hbref":""},{"q":"Without a permit, what is the maximum legal HEIGHT for a commercial vehicle and load in South Carolina?","options":["13 feet 6 inches","14 feet 0 inches","12 feet 6 inches","13 feet 0 inches"],"answer":0,"explanation":"South Carolina's legal maximum height is 13 feet 6 inches; anything taller requires an SCDOT over-height permit and routing review for overpass clearance. Source: SCDOT Oversize/Overweight Permits.","handbook":"","hbref":""},{"q":"Under SCDOT permit rules, oversize loads in South Carolina are generally allowed to move during what times?","options":["24 hours a day, any day","From one-half hour after sunrise to one-half hour before sunset, Monday through Saturday","Only between 9 p.m. and 5 a.m. to avoid traffic","Weekdays only, with no movement allowed on Saturday"],"answer":1,"explanation":"SCDOT generally restricts oversize-load movement to one-half hour after sunrise to one-half hour before sunset, Monday through Saturday, with no Sunday or designated-holiday travel, plus added restrictions for very wide loads. Source: SCDOT Oversize/Overweight Permits.","handbook":"","hbref":""},{"q":"A driver who unlawfully passes a stopped South Carolina school bus and a vehicle approaching a stopped emergency vehicle under the Move Over law are both subject to penalties. Which statement is correct about the Move Over law violation?","options":["It is only a $25 civil fine with no court costs","It is a misdemeanor carrying a fine in the $300 to $500 range","It carries an automatic lifetime CDL disqualification","It is a warning-only offense for the first year"],"answer":1,"explanation":"A violation of the South Carolina Move Over law (S.C. Code 56-5-1538) is a misdemeanor punishable by a fine generally in the $300-$500 range; by contrast, the left-lane 'Move Right' violation (56-5-1885) is a $25 civil fine. Source: S.C. Code 56-5-1538; SCDPS.","handbook":"","hbref":""},{"q":"Which agency issues Commercial Driver Licenses (CDLs) in South Carolina?","options":["The South Carolina Department of Motor Vehicles (SCDMV)","The South Carolina Department of Transportation (SCDOT)","The Federal Motor Carrier Safety Administration (FMCSA)","The South Carolina Highway Patrol"],"answer":0,"explanation":"South Carolina CDLs are issued by the South Carolina Department of Motor Vehicles (SCDMV). FMCSA sets federal CDL standards but does not issue the license; SCDOT handles roads/permits, not licensing. Source: SCDMV Commercial Licenses page (dmv.sc.gov).","handbook":"","hbref":""},{"q":"In South Carolina, what is the standard form used to apply for a Commercial Learner's Permit (CLP) or CDL?","options":["SCDMV Form 447-CDL","SCDMV Form DL-405A","SCDMV Form MV-93","FMCSA Form MCSA-5876"],"answer":0,"explanation":"The application for a CLP and CDL in South Carolina is SCDMV Form 447-CDL. DL-405A is the medical self-certification form, MV-93 is the identity-document checklist, and MCSA-5876 is the federal medical examiner's certificate. Source: SCDMV Getting Your First CDL (dmv.sc.gov).","handbook":"","hbref":""},{"q":"How long is a South Carolina Commercial Learner's Permit (CLP) valid before it expires?","options":["One year","180 days","Six months","Two years"],"answer":0,"explanation":"In South Carolina the CLP carries a one-year expiration date. Source: SCDMV Getting Your First CDL (dmv.sc.gov). (The federal rule allows a CLP valid up to one year, which South Carolina applies.)","handbook":"","hbref":""},{"q":"After being issued a Commercial Learner's Permit in South Carolina, how long must you hold it before you are eligible to take the CDL skills test?","options":["At least 14 days","At least 30 days","At least 10 days","At least 7 days"],"answer":0,"explanation":"You must hold the CLP for a minimum of 14 days before you may take the skills test. Source: SCDMV Getting Your First CDL (dmv.sc.gov); this mirrors the federal 14-day CLP hold (49 CFR 383.25).","handbook":"","hbref":""},{"q":"Under South Carolina's CDL self-certification, how many categories of operation must a driver choose from?","options":["Four","Two","Three","Five"],"answer":0,"explanation":"There are four self-certification categories: non-excepted interstate, excepted interstate, non-excepted intrastate, and excepted intrastate. Drivers certify their category to the SCDMV. Source: SCDMV / Form DL-405A (dmv.sc.gov).","handbook":"","hbref":""},{"q":"Which South Carolina form is used to self-certify your type of commerce and submit medical certification status to the SCDMV?","options":["Form DL-405A (CDL Holder's Medical Certification)","Form 447-CDL (CDL Application)","Form MV-93 (Citizen's Checklist)","Form MCSA-5875 (Medical Examination Report)"],"answer":0,"explanation":"South Carolina uses Form DL-405A for the CDL holder's self-certification and medical certification. Form 447-CDL is the license application, MV-93 the ID checklist, and MCSA-5875 the federal exam report. Source: SCDMV Renew or Upgrade Your CDL (dmv.sc.gov).","handbook":"","hbref":""},{"q":"Which self-certification category requires a South Carolina CDL holder to provide a valid DOT medical examiner's certificate?","options":["Non-excepted interstate","Excepted interstate","Excepted intrastate","No category requires a medical certificate"],"answer":0,"explanation":"Non-excepted interstate drivers must maintain a valid DOT medical examiner's certificate that meets FMCSA standards. Drivers in the excepted categories are not required to submit one. Source: SCDMV / Form DL-405A (dmv.sc.gov); 49 CFR 391.41.","handbook":"","hbref":""},{"q":"Who is authorized to perform the physical examination and issue the medical examiner's certificate that a South Carolina non-excepted CDL driver must hold?","options":["A medical professional listed on FMCSA's National Registry of Certified Medical Examiners","Any licensed physician of the driver's choosing","An SCDMV examiner at the branch office","A physician approved by the South Carolina Department of Transportation"],"answer":0,"explanation":"The exam must be performed and the certificate issued by a medical professional listed on FMCSA's National Registry of Certified Medical Examiners. Source: SCDMV Commercial Licenses (dmv.sc.gov); 49 CFR 390.103.","handbook":"","hbref":""},{"q":"Before taking the CDL skills test in South Carolina, which requirement applies to applicants who received their CLP after February 7, 2022?","options":["Complete an FMCSA-approved Entry-Level Driver Training (ELDT) program","Hold a clean driving record for five consecutive years","Complete 160 hours of behind-the-wheel time with the SCDMV","Pass a separate SCDMV defensive driving course"],"answer":0,"explanation":"Applicants whose CLP was issued after February 7, 2022, must complete an FMCSA-approved ELDT program with a registered training provider before taking the skills test. Source: SCDMV Getting Your First CDL (dmv.sc.gov); 49 CFR Part 380 Subpart F.","handbook":"","hbref":""},{"q":"The South Carolina CDL skills test is divided into three parts. Which set correctly lists those three parts?","options":["Pre-trip inspection, basic vehicle control, and on-road driving","Written knowledge, vision screening, and on-road driving","Pre-trip inspection, hazardous materials, and night driving","Air brake check, parallel parking, and freeway merging"],"answer":0,"explanation":"The CDL skills test has three components: the pre-trip inspection, basic vehicle (off-road) control, and the on-road driving test. Source: SCDMV Getting Your First CDL (dmv.sc.gov); 49 CFR 383.113.","handbook":"","hbref":""},{"q":"What is the standard validity period of a South Carolina CDL before it must be renewed?","options":["8 years","5 years","4 years","10 years"],"answer":0,"explanation":"A South Carolina CDL is valid for 8 years and expires on the holder's birthday in the final year of the cycle. Source: SCDMV (dmv.sc.gov). (A HazMat endorsement is limited by the separate 5-year TSA Security Threat Assessment cycle.)","handbook":"","hbref":""},{"q":"A South Carolina CDL with a hazardous materials (HazMat) endorsement is limited by which separate timeframe?","options":["The 5-year TSA Security Threat Assessment cycle","A 2-year HazMat-only renewal cycle","A 10-year federal HazMat certification","A 1-year SCDMV HazMat review"],"answer":0,"explanation":"Even though the CDL itself is valid 8 years, the HazMat endorsement is tied to the TSA Security Threat Assessment, which must be renewed on a 5-year cycle. Source: SCDMV Commercial Licenses (dmv.sc.gov); 49 CFR 1572.","handbook":"","hbref":""},{"q":"When must a South Carolina CDL holder submit proof of medical qualification (self-certification/medical certificate) to the SCDMV?","options":["Each time they apply for, renew, upgrade, change the address on, or duplicate the CDL","Only once, when first obtaining the CDL","Only at the 8-year renewal","Only when adding a HazMat endorsement"],"answer":0,"explanation":"Drivers must submit proof of medical qualification every time they apply for a CLP/CDL, upgrade, renew, change address, or request a duplicate. Source: SCDMV Commercial Licenses (dmv.sc.gov).","handbook":"","hbref":""},{"q":"What is the minimum age to be issued a CDL in South Carolina to drive a commercial vehicle only within the state (intrastate)?","options":["18 years old","19 years old","21 years old","20 years old"],"answer":0,"explanation":"You must be at least 18 to hold a CDL for intrastate driving within South Carolina, and at least 21 to drive interstate. Source: SCDMV Getting Your First CDL (dmv.sc.gov).","handbook":"","hbref":""},{"q":"What minimum age does South Carolina require to operate a commercial motor vehicle in interstate commerce (across state lines)?","options":["21 years old","18 years old","19 years old","25 years old"],"answer":0,"explanation":"A driver must be at least 21 to operate a CMV in interstate commerce; ages 18-20 are limited to intrastate operation. Source: SCDMV Getting Your First CDL (dmv.sc.gov); 49 CFR 391.11.","handbook":"","hbref":""},{"q":"How is a non-excepted interstate driver's medical examiner's certificate typically verified once submitted to the SCDMV?","options":["It is verified electronically/posted to the driving record","It must be notarized at the SCDMV branch","It is mailed to FMCSA for manual approval","It is verified only by the medical examiner, not the state"],"answer":0,"explanation":"For non-excepted drivers the medical certificate information is verified electronically and the medical status is added to the CDL driving record. Source: SCDMV Commercial Licenses (dmv.sc.gov); 49 CFR 383.71/383.73.","handbook":"","hbref":""},{"q":"Before applying for a CDL or CLP, South Carolina requires an applicant to already hold which credential?","options":["A valid, unexpired South Carolina driver's license","A valid passport","A federal TWIC card","A South Carolina business license"],"answer":0,"explanation":"Applicants must hold a valid, unexpired South Carolina (regular) driver's license before applying for a CLP/CDL. Source: SCDMV Getting Your First CDL (dmv.sc.gov).","handbook":"","hbref":""},{"q":"At a South Carolina CDL renewal, which item must be presented in addition to the application and medical/self-certification?","options":["Automobile liability insurance information from a company licensed in South Carolina","A notarized employer affidavit","Proof of completion of a new ELDT course","A new TSA fingerprint check for all endorsements"],"answer":0,"explanation":"South Carolina requires automobile liability insurance information from an SC-licensed insurer at CDL renewal, along with Form 447-CDL and Form DL-405A medical certification as applicable. Source: SCDMV Renew or Upgrade Your CDL (dmv.sc.gov).","handbook":"","hbref":""},{"q":"If a South Carolina CDL holder lets the federally required medical examiner's certificate expire while certified non-excepted, what is the consequence to the CDL?","options":["The CDL is downgraded so commercial privileges are lost until a valid certificate is on file","Nothing changes until the 8-year renewal","The CDL is permanently revoked with no path to reinstatement","Only the HazMat endorsement is affected"],"answer":0,"explanation":"When a non-excepted driver's medical certificate lapses or is not on file, the state must downgrade the CDL (removing commercial driving privileges) until a current certificate is submitted. Source: SCDMV / FMCSA medical certification rules (dmv.sc.gov); 49 CFR 383.73.","handbook":"","hbref":""},{"q":"When renewing a South Carolina CDL, the medical self-certification (Form DL-405A) generally must be resubmitted in which situation?","options":["If it has not already been submitted or if the type of commerce being operated has changed","Only if the driver has moved to another state","Only if the driver is over age 65","Never, because it is a one-time filing"],"answer":0,"explanation":"South Carolina requires the DL-405A self-certification at renewal if it has not already been submitted or if the driver's type of commerce (self-certification category) has changed. Source: SCDMV Renew or Upgrade Your CDL (dmv.sc.gov).","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная общая внешняя ширина транспортного средства или его груза на автомагистралях Южной Каролины, не считая разрешённых устройств безопасности?","options":["96 inches","102 inches","108 inches","120 inches"],"explanation":"South Carolina Code 56-5-4030 устанавливает максимальную общую внешнюю ширину транспортного средства или груза в 102 inches (8 feet 6 inches), не считая разрешённых устройств безопасности. Это соответствует федеральному стандарту, принятому по всему штату. Источник: SC Code 56-5-4030 (Width of vehicles)."},"1":{"q":"Какова максимальная высота для большинства транспортных средств, порожних или гружёных, на автомагистралях Южной Каролины?","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"explanation":"South Carolina Code 56-5-4060 ограничивает высоту транспортного средства до 13 feet 6 inches. Узкое исключение допускает 14 feet для автовоза или составной сцепки на седельной опоре при наличии действующего маршрутного разрешения SCDOT. Источник: SC Code 56-5-4060 (Height of vehicles)."},"2":{"q":"Какова максимальная длина одиночного автотранспортного средства (например, грузовика-фургона без прицепа) в Южной Каролине, включая бамперы и груз?","options":["35 feet","40 feet","45 feet","48 feet"],"explanation":"South Carolina Code 56-5-4070 ограничивает одиночное автотранспортное средство до 40 feet предельной общей длины, включая передний и задний бамперы и груз. Автобусы и определённые автодома рассматриваются отдельно. Источник: SC Code 56-5-4070 (Length of vehicles)."},"3":{"q":"Какова максимальная длина прицепа или полуприцепа (включая груз) в двухзвенной сцепке тягач–полуприцеп в Южной Каролине?","options":["48 feet","50 feet","53 feet","57 feet"],"explanation":"South Carolina Code 56-5-4070 допускает длину прицепа или полуприцепа в двухзвенной сцепке с тягачом до 53 feet, включая груз. Прицеп длиной 53-foot должен иметь заднее противоподкатное ограждение. Источник: SC Code 56-5-4070."},"4":{"q":"Какова максимальная полная масса, которую одиночная ось может передавать на дорогу в Южной Каролине?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"South Carolina Code 56-5-4140 ограничивает полную массу на любую одиночную ось до 20,000 pounds. Это совпадает с федеральным пределом для одиночной оси. Источник: SC Code 56-5-4140 (Gross weight of vehicles)."},"5":{"q":"Какова максимальная полная масса транспортного средства, разрешённая в Южной Каролине без специального разрешения?","options":["73,280 pounds","76,000 pounds","80,000 pounds","88,000 pounds"],"explanation":"South Carolina Code 56-5-4140 ограничивает общую полную массу до 80,000 pounds, за исключением транспортных средств, которым SCDOT выдал специальные разрешения. Это отражает федеральный максимум для межштатных автомагистралей. Источник: SC Code 56-5-4140."},"6":{"q":"Какова максимальная полная масса, разрешённая на группу спаренных осей (включая допуск контроля) на межштатных автомагистралях Южной Каролины?","options":["32,000 pounds","34,000 pounds","35,200 pounds","36,000 pounds"],"explanation":"На системе межштатных автомагистралей Южная Каролина допускает полную массу на спаренную ось 35,200 pounds, что включает допуск контроля штата сверх федеральной базы в 34,000-pound. Источник: SC Code 56-5-4140; рекомендации SCDMV/SCDOT по габаритам и весу."},"7":{"q":"Какова максимальная полная масса, разрешённая на группу спаренных осей с расстоянием от 40 до 96 inches, на немежштатных (региональных) автомагистралях Южной Каролины?","options":["34,000 pounds","35,200 pounds","36,000 pounds","40,000 pounds"],"explanation":"South Carolina Code 56-5-4140 допускает до 36,000 pounds на спаренную ось (две или более последовательных осей с расстоянием от 40 до 96 inches) на автомагистралях, кроме межштатных. Предел для спаренной оси на межштатных автомагистралях ниже — 35,200 pounds. Источник: SC Code 56-5-4140."},"8":{"q":"Какую формулу использует Южная Каролина для определения допустимой полной массы на группу осей в зависимости от расстояния между ними?","options":["Федеральную мостовую формулу (Formula B)","Формулу полной массы автопоезда (GCWR)","Формулу сопротивления качению Дэвиса","Формулу допуска для одиночной оси"],"explanation":"Южная Каролина применяет Федеральную мостовую формулу (Bridge Formula B) для определения максимальной массы на любую группу из двух или более последовательных осей в зависимости от расстояния между осями и их количества, в соответствии с 23 U.S.C. 127. Источник: SC Code 56-5-4140; Федеральная мостовая формула FHWA."},"9":{"q":"Какое ведомство штата Южная Каролина выдаёт разрешения на негабаритный/сверхнормативный груз (OSOW) для транспортных средств и грузов, превышающих установленные пределы?","options":["Департамент транспортных средств Южной Каролины (SCDMV)","Департамент общественной безопасности Южной Каролины (SCDPS)","Департамент транспорта Южной Каролины (SCDOT)","Департамент доходов Южной Каролины (SCDOR)"],"explanation":"Управление по разрешениям на негабаритные/сверхнормативные грузы Департамента транспорта Южной Каролины (SCDOT) по своему усмотрению выдаёт разрешения OSOW для грузов, превышающих установленные пределы габаритов или веса. Источник: программа разрешений SCDOT Oversize/Overweight Permits."},"10":{"q":"Когда в Южной Каролине обычно требуется разрешение на негабарит по ширине груза?","options":["Когда ширина превышает 96 inches","Когда ширина превышает 102 inches (8'6\")","Когда ширина превышает 120 inches (10')","Когда ширина превышает 144 inches (12')"],"explanation":"Поскольку установленный предел ширины в Южной Каролине составляет 102 inches (8 feet 6 inches), любой груз шире этого требует разрешения SCDOT на негабарит. Источник: SC Code 56-5-4030; рекомендации SCDOT по разрешениям OSOW."},"11":{"q":"Как перевозчик может подать заявку на разрешение на негабаритный/сверхнормативный груз в Южной Каролине?","options":["Только отправив бумажную форму по почте в SCDMV","Через онлайн-систему SCDOT SafeHaul (или по телефону/почте/электронной почте)","Только лично в окружном суде","Через национальный портал FMCSA"],"explanation":"Перевозчики получают разрешения OSOW через онлайн-систему SCDOT SafeHaul (iHaul) или обращаясь в Управление по разрешениям OSOW SCDOT по телефону, почте или электронной почте. Источник: страница SCDOT Oversize/Overweight Permits (SafeHaul)."},"12":{"q":"Согласно сельскохозяйственному/лесному исключению Южной Каролины, самоходная сельскохозяйственная техника и лесная техника могут двигаться без разрешения на негабарит в светлое время суток при условии, что они не превышают какую ширину?","options":["8 feet 6 inches","10 feet","12 feet","14 feet"],"explanation":"Южная Каролина разрешает сельскохозяйственной технике, лесной технике и аналогичному оборудованию двигаться в светлое время суток без разрешения, если оно не превышает 12 feet в ширину, 13 feet 6 inches в высоту или 90,000 pounds. Источник: рекомендации SCDOT OSOW (сельскохозяйственное/лесное исключение)."},"13":{"q":"На двухполосной автомагистрали Южной Каролины при какой ширине для разрешённого груза начинает требоваться передний автомобиль сопровождения (пилот)?","options":["Свыше 10 feet","Свыше 12 feet","Свыше 14 feet","Свыше 16 feet"],"explanation":"На двухполосных автомагистралях Южная Каролина требует переднего сопровождения для грузов шириной свыше 12 feet и до 14 feet; грузы шириной свыше 14 feet и до 16 feet требуют переднего и заднего сопровождения. Источник: требования SCDOT OSOW к сопровождению/автомобилям-пилотам."},"14":{"q":"Для полуприцепа длиной 53-foot в Южной Каролине расстояние от шкворня до центра задней оси (или задней спаренной оси) не может превышать какое значение?","options":["37 feet","41 feet","43 feet","46 feet"],"explanation":"South Carolina Code 56-5-4070 требует, чтобы на прицепе длиной 53-foot расстояние от шкворня до задней оси (или центра задней спаренной оси) было не более 41 feet. Источник: SC Code 56-5-4070."},"15":{"q":"Какой допуск контроля Южная Каролина обычно применяет к ограничениям по весу на немежштатных автомагистралях?","options":["5 percent","10 percent","15 percent","Допуск не разрешён"],"explanation":"Южная Каролина применяет допуск контроля 10% к ограничениям по весу на немежштатных (региональных и вспомогательных) автомагистралях. Вес на межштатных автомагистралях контролируется строже в пределах указанных допусков. Источник: рекомендации SCDOT/SCDMV по габаритам и весу; SC Code 56-5-4140."},"16":{"q":"Согласно исключению по высоте 14 feet в Южной Каролине, автовоз или составная сцепка на седельной опоре должны дополнительно иметь что?","options":["Освобождение от FMCSA","Действующее маршрутное разрешение, выданное SCDOT","Допуск на перевозку опасных материалов","Письменное одобрение окружного шерифа"],"explanation":"South Carolina Code 56-5-4060 допускает высоту до 14 feet для автовоза или составной сцепки на седельной опоре только при условии, что владелец/оператор имеет действующее маршрутное разрешение, выданное SCDOT. Источник: SC Code 56-5-4060."},"17":{"q":"Какова максимальная длина, разрешённая для автодома в Южной Каролине, при условии что его радиус разворота составляет 48 feet или менее?","options":["40 feet","42 feet","45 feet","48 feet"],"explanation":"South Carolina Code 56-5-4070 допускает автодом длиной до 45 feet, если его радиус разворота составляет 48 feet или менее, что является исключением из общего предела в 40 feet для одиночного транспортного средства. Источник: SC Code 56-5-4070."},"18":{"q":"Насколько навесные элементы на автодомах, жилых прицепах и кемперах на пикапах в некоммерческом использовании могут выступать за установленную ширину в Южной Каролине?","options":["До 3 inches с каждой стороны","До 6 inches с одной стороны и 4 inches с другой","До 12 inches только с одной стороны","Выступ за установленную ширину не допускается"],"explanation":"South Carolina Code 56-5-4030 допускает, чтобы навесные элементы на некоммерческих автодомах, жилых прицепах и кемперах на пикапах выступали максимум на 6 inches с одной стороны и на 4 inches с другой за предел ширины в 102-inch. Источник: SC Code 56-5-4030."},"19":{"q":"Типичное разовое разрешение SCDOT на негабаритный/сверхнормативный груз для стандартного широкого груза стоит примерно сколько?","options":["$10","$30","$75","$150"],"explanation":"SCDOT взимает около $30 за стандартное разовое разрешение OSOW, при этом годовое (многократное) разрешение стоит около $100; более высокие сборы применяются для экстремальной ширины свыше 16 feet. Источник: тарифная сетка SCDOT Oversize/Overweight Permits."},"20":{"q":"В Южной Каролине какой класс CDL требуется для управления сцепкой транспортных средств с полной массой автопоезда (GCWR) 26,001 pounds или более, где буксируемое звено имеет GVWR свыше 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"explanation":"Южная Каролина (SCDMV, Classes A, B и C) определяет CDL Class A как любую сцепку транспортных средств с GCWR 26,001 lbs или более, при условии что GVWR буксируемого транспортного средства превышает 10,000 lbs. Источник: SCDMV Commercial Licenses, Classes A, B и C."},"21":{"q":"Согласно SCDMV, одиночное транспортное средство с GVWR 26,001 pounds или более (не буксирующее ничего тяжелее 10,000 lbs) требует какого класса CDL?","options":["Class C","Class B","Class A","Class E"],"explanation":"Южная Каролина определяет CDL Class B как любое одиночное транспортное средство с GVWR 26,001 lbs или более, либо такое транспортное средство, буксирующее звено массой не более 10,000 lbs. Источник: SCDMV Commercial Licenses, Classes A, B и C."},"22":{"q":"Согласно правилам Южной Каролины, транспортное средство, которое не соответствует весовым порогам Class A или B, но рассчитано на перевозку 16 или более человек (включая водителя), требует какого класса CDL?","options":["Class A","Class B","Class C","CDL не требуется"],"explanation":"Южная Каролина определяет CDL Class C как любое одиночное транспортное средство или сцепку, которая не является Class A или B, но рассчитана на перевозку 16 или более человек, включая водителя, либо используется для перевозки опасных материалов, требующих установки знаков. Источник: SCDMV Commercial Licenses, Classes A, B и C."},"23":{"q":"В Южной Каролине каков минимальный возраст для получения CDL для ВНУТРИШТАТНОГО вождения (управление только в пределах штата)?","options":["16 лет","17 лет","18 лет","21 год"],"explanation":"SCDMV требует, чтобы заявителям было не менее 18 лет для коммерческого вождения в пределах Южной Каролины (внутри штата). Водители младше 21 года не могут водить за пределами штата. Источник: SCDMV, Getting Your First CDL."},"24":{"q":"Каков минимальный возраст в Южной Каролине для получения CDL, действительного для МЕЖШТАТНОГО вождения (через границы штатов)?","options":["18 лет","19 лет","21 год","25 лет"],"explanation":"SCDMV требует, чтобы водителям было не менее 21 года для управления коммерческим транспортным средством за пределами Южной Каролины (между штатами). Водители 18-20 лет ограничены внутриштатной эксплуатацией. Источник: SCDMV, Getting Your First CDL."},"25":{"q":"Прежде чем заявитель в Южной Каролине сможет сдать экзамен по навыкам вождения CDL (дорожный тест), как долго он должен иметь коммерческое ученическое разрешение (CLP)?","options":["Не менее 7 календарных дней","Не менее 14 календарных дней","Не менее 30 календарных дней","Не менее 60 календарных дней"],"explanation":"Южная Каролина следует федеральному правилу, требующему, чтобы CLP удерживался не менее 14 календарных дней, прежде чем заявитель сможет сдать экзамен по навыкам вождения CDL. Источник: SCDMV, Getting Your First CDL (49 CFR 383.25)."},"26":{"q":"Какой код допуска использует Южная Каролина для разрешения на управление транспортным средством, перевозящим опасные материалы, требующие установки знаков?","options":["N","T","H","P"],"explanation":"Допуск H охватывает опасные материалы, требующие установки знаков. Южная Каролина использует стандартные федеральные коды допусков: H (HazMat), N (цистерна), T (двойные/тройные прицепы), P (пассажиры), S (школьный автобус). Источник: SCDMV Commercial Licenses."},"27":{"q":"В Южной Каролине, прежде чем допуск HazMat (H) может быть выдан или продлён, заявитель должен пройти какую дополнительную проверку?","options":["Оценку угрозы безопасности TSA (проверка биографии и снятие отпечатков пальцев)","Тест на физическую ловкость и поднятие тяжестей","Сертификацию курса безопасного вождения","Проверку зрения, проводимую SCDMV"],"explanation":"Южная Каролина требует, чтобы заявители на допуск HazMat (H) проходили федеральную оценку угрозы безопасности Управления транспортной безопасности (TSA), которая включает снятие отпечатков пальцев и проверку биографии, как для первичных, так и для продлеваемых допусков. Источник: SCDMV; 49 CFR 1572."},"28":{"q":"Какой допуск требуется в Южной Каролине для управления коммерческим транспортным средством, предназначенным для перевозки жидкостей или газов в наливной цистерне?","options":["P (пассажиры)","N (транспортное средство-цистерна)","T (двойные/тройные прицепы)","S (школьный автобус)"],"explanation":"Допуск N (транспортное средство-цистерна) требуется для управления транспортным средством, перевозящим жидкости или газы в наливных цистернах, соответствующих федеральному определению. Источник: SCDMV Commercial Licenses; 49 CFR 383.93."},"29":{"q":"В Южной Каролине какой допуск требуется для буксировки двойных или тройных прицепов?","options":["Допуск T","Допуск N","Допуск H","Допуск X"],"explanation":"Допуск T разрешает управление двойными и тройными прицепами. Южная Каролина использует стандартные федеральные коды. Источник: SCDMV Commercial Licenses; 49 CFR 383.93."},"30":{"q":"Какой допуск должен получить водитель в Южной Каролине для управления коммерческим автобусом или микроавтобусом, рассчитанным на перевозку требуемого порогового числа пассажиров?","options":["S (школьный автобус)","P (пассажиры)","N (цистерна)","T (двойные/тройные прицепы)"],"explanation":"Допуск P (пассажиры) требуется для управления транспортным средством, рассчитанным на перевозку 16 или более человек, включая водителя. Для школьных автобусов необходим отдельный допуск S. Источник: SCDMV Commercial Licenses."},"31":{"q":"В Южной Каролине что необходимо водителю для управления школьным автобусом, требующим CDL?","options":["Только допуск P (пассажиры)","Оба допуска: P (пассажиры) и S (школьный автобус)","Только допуск H (HazMat)","Никакого допуска, только CDL Class B"],"explanation":"Для управления школьным автобусом в Южной Каролине водитель должен иметь оба допуска: P (пассажиры) и S (школьный автобус), а также сдать теоретический и практический экзамены по школьному автобусу. Источник: SCDMV Commercial Licenses; 49 CFR 383.93."},"32":{"q":"Для заявителя на CLP/CDL в Южной Каролине, получившего разрешение 7 февраля 2022 года или позже, какое обучение должно быть завершено перед экзаменом по навыкам для первого CDL?","options":["Аудиторный курс только штата SCDMV","Утверждённое FMCSA обучение водителей начального уровня (ELDT) от зарегистрированного провайдера","160-часовое ученичество, зарегистрированное в SCDMV","Обучение не требуется, только экзамен по навыкам"],"explanation":"Южная Каролина требует, чтобы заявители, получившие CLP 7 февраля 2022 года или позже, прошли утверждённое FMCSA обучение водителей начального уровня (ELDT) у провайдера, включённого в Реестр провайдеров обучения FMCSA, перед сдачей экзамена по навыкам. Источник: SCDMV, Getting Your First CDL; правило FMCSA ELDT."},"33":{"q":"Согласно федеральному правилу ELDT, применяемому в Южной Каролине, ELDT требуется для первого CDL и для какого набора допусков?","options":["H (HazMat), P (пассажиры) и S (школьный автобус)","N (цистерна), T (двойные/тройные прицепы) и H (HazMat)","P (пассажиры), N (цистерна) и T (двойные/тройные прицепы)","Всех пяти допусков (H, N, T, P, S)"],"explanation":"ELDT требуется для первичного CDL Class A или B, для повышения класса, а также для допусков HazMat (H), Passenger (P) и School Bus (S). Оно не требуется для допусков N (цистерна) или T (двойные/тройные прицепы). Источник: правило FMCSA ELDT; SCDMV."},"34":{"q":"Из скольких категорий медицинской самосертификации должен выбрать заявитель на CDL в Южной Каролине при сертификации типа коммерции, в которой он работает?","options":["Двух","Трёх","Четырёх","Пяти"],"explanation":"Федеральные правила, принятые Южной Каролиной, требуют, чтобы держатели CDL самосертифицировались в одну из четырёх категорий: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate или Excepted Intrastate. Источник: SCDMV; 49 CFR 383.71."},"35":{"q":"Водитель CDL в Южной Каролине, который перевозит грузы через границы штатов и должен соответствовать федеральным медицинским стандартам DOT, должен самосертифицироваться в какой категории?","options":["Excepted Interstate","Non-Excepted Interstate","Non-Excepted Intrastate","Excepted Intrastate"],"explanation":"Водитель, работающий в межштатной коммерции, который подпадает под федеральные стандарты медицинской пригодности (49 CFR Part 391) и должен им соответствовать, сертифицируется как Non-Excepted Interstate и должен иметь действующее свидетельство медицинского эксперта. Источник: SCDMV; 49 CFR 383.71."},"36":{"q":"Какой документ НЕ входит в число тех, которые SCDMV требует от впервые подающего заявку на CDL для подтверждения личности, номера социального страхования, места жительства и законности нахождения?","options":["Подтверждение личности и даты рождения","Подтверждение номера социального страхования","Два подтверждения проживания в Южной Каролине","Подписанное письмо о трудоустройстве от транспортной компании"],"explanation":"SCDMV требует подтверждения личности/законности нахождения, номера социального страхования и проживания в Южной Каролине (согласно контрольному списку документов, например, Form MV-93). Письмо от работодателя не является обязательным документом для подтверждения личности/места жительства. Источник: контрольный список документов SCDMV, Getting Your First CDL."},"37":{"q":"В Южной Каролине какие заявители имеют право подавать заявку на допуск CDL HazMat (H)?","options":["Любой держатель CDL независимо от гражданства","Только граждане США и законные постоянные жители","Только водители в возрасте 25 лет и старше","Только водители, которые уже имеют объединённый допуск X"],"explanation":"Из-за оценки угрозы безопасности TSA только граждане США и законные постоянные жители имеют право на допуск CDL HazMat (H) в Южной Каролине. Источник: SCDMV; программа TSA HME (49 CFR 1572)."},"38":{"q":"Какие допуски может получить водитель в Южной Каролине, имея только коммерческое ученическое разрешение (CLP)?","options":["Только H (HazMat) и T (двойные/тройные прицепы)","Только N (цистерна), P (пассажиры) и S (школьный автобус)","Все пять допусков","Никакие — на CLP допуски не разрешены"],"explanation":"CLP в Южной Каролине может иметь только допуски N (цистерна, с ограничением на пустые цистерны), P (пассажиры, без пассажиров кроме инструкторов/экзаменаторов) и S (школьный автобус). Допуски H и T не могут быть на CLP. Источник: SCDMV, Getting Your First CDL; 49 CFR 383.25."},"39":{"q":"В Южной Каролине что означает объединённый допуск 'X' на CDL?","options":["Разрешение на операции как с цистерной (N), так и с HazMat (H)","Разрешение на двойные/тройные прицепы (T) и пассажиров (P)","Ограничение, запрещающее межштатное вождение","Сертификацию оператора школьного автобуса"],"explanation":"Допуск X — это объединённый код, указывающий, что водитель имеет оба допуска: Tank (N) и HazMat (H), что позволяет перевозить опасные материалы в транспортном средстве-цистерне. Источник: SCDMV Commercial Licenses; 49 CFR 383.153."},"40":{"q":"В Южной Каролине какова максимальная концентрация алкоголя в крови (BAC), при которой законно управлять коммерческим автотранспортным средством (CMV)?","options":["Ниже 0.04%","Ниже 0.08%","Ниже 0.02%","Ниже 0.05%"],"explanation":"Южная Каролина следует федеральному стандарту для CMV: незаконно управлять CMV, если ваш BAC составляет 0.04% или более, поэтому законное управление требует BAC ниже 0.04%. Источник: SCDMV Commercial Driver's License Manual, Section 1.3.2 (49 CFR 383.51)."},"41":{"q":"Согласно правилу подразумеваемого согласия Южной Каролины для операторов CMV, что происходит, если у водителя обнаружено заметное количество алкоголя ниже 0.04%?","options":["Отстранение от работы на 24 hours","Дисквалификация на 60 days","Дисквалификация на один год","Выносится только предупреждение без каких-либо мер"],"explanation":"Южная Каролина отстраняет водителя CMV от работы на 24 hours, если обнаружено любое заметное количество алкоголя ниже 0.04%. BAC 0.04% или выше вместо этого влечёт дисквалификацию. Источник: SCDMV CDL Manual, Section 1.3.2."},"42":{"q":"Управляя CMV в Южной Каролине, водитель автоматически считается давшим что в отношении химического тестирования?","options":["Согласие на тестирование на алкоголь","Отказ от права на слушание","Согласие на ежегодный скрининг на наркотики","Согласие на обыск транспортного средства"],"explanation":"Согласно подразумеваемому согласию, любой, кто управляет CMV в Южной Каролине, считается давшим согласие на тестирование на алкоголь. Источник: SCDMV CDL Manual, Section 1.3.2."},"43":{"q":"Каков минимальный срок дисквалификации в Южной Каролине за первое серьёзное нарушение водителя CMV, такое как DUI или управление CMV с BAC 0.04% или выше?","options":["1 год","60 days","6 месяцев","3 года"],"explanation":"Первое серьёзное нарушение (DUI, BAC 0.04%+ в CMV, отказ от теста, оставление места происшествия и т. д.) влечёт минимальную дисквалификацию не менее одного года в Южной Каролине. Источник: SCDMV CDL Manual, Section 1.3.2 (49 CFR 383.51)."},"44":{"q":"В Южной Каролине, если серьёзное нарушение (такое как DUI) происходит во время управления водителем CMV со знаками опасности при перевозке опасных материалов, каков минимальный срок дисквалификации?","options":["3 года","1 год","5 лет","18 месяцев"],"explanation":"Южная Каролина увеличивает дисквалификацию за первое нарушение до не менее трёх лет, когда серьёзное нарушение происходит во время управления CMV со знаками опасности при перевозке опасных материалов. Источник: SCDMV CDL Manual, Section 1.3.2 (49 CFR 383.51)."},"45":{"q":"Каков срок дисквалификации в Южной Каролине за второе серьёзное нарушение водителя CMV?","options":["Пожизненно","10 лет","5 лет","3 года"],"explanation":"Второе серьёзное нарушение влечёт пожизненную потерю CDL в Южной Каролине. Источник: SCDMV CDL Manual, Section 1.3.2 (49 CFR 383.51)."},"46":{"q":"В Южной Каролине отказ оператора CMV от прохождения теста на содержание алкоголя в крови рассматривается как какой тип нарушения для целей дисквалификации?","options":["Серьёзное нарушение (не менее 1 года)","Серьёзное нарушение ПДД (60 days)","Нарушение приказа об отстранении от работы (90 days)","Незначительное нарушение без дисквалификации"],"explanation":"Отказ от прохождения теста на содержание алкоголя в крови указан как серьёзное нарушение в Южной Каролине и влечёт минимальную дисквалификацию на один год за первое нарушение, так же как DUI. Источник: SCDMV CDL Manual, Section 1.3.2."},"47":{"q":"Согласно правилам Южной Каролины, водитель CMV пожизненно теряет CDL за первое нарушение, если CMV используется для совершения какого типа преступления?","options":["Тяжкого преступления, связанного с контролируемыми веществами","Любого тяжкого преступления любого рода","Тяжкого преступления, связанного с кражей","Безрассудного вождения, причинившего травму"],"explanation":"Использование CMV для совершения тяжкого преступления, связанного с контролируемыми веществами, влечёт пожизненную дисквалификацию за первое нарушение, без возможности восстановления через 10 лет, доступного для других пожизненных случаев. Источник: SCDMV CDL Manual, Section 1.3.2."},"48":{"q":"В Южной Каролине насколько выше установленного ограничения скорости должен ехать водитель CMV, чтобы нарушение засчитывалось как тип серьёзного нарушения ПДД 'превышение скорости'?","options":["15 mph или более сверх ограничения","10 mph или более сверх ограничения","20 mph или более сверх ограничения","5 mph или более сверх ограничения"],"explanation":"Южная Каролина определяет превышение скорости как серьёзное нарушение ПДД, когда водитель едет на 15 mph или более выше установленного ограничения скорости. Источник: SCDMV CDL Manual, Section 1.3.3."},"49":{"q":"Что из перечисленного классифицируется как серьёзное нарушение ПДД для водителя CMV в Южной Каролине?","options":["Неправильная или беспорядочная смена полос движения","Управление с BAC 0.04% или выше","Отказ от химического теста","Нарушение приказа об отстранении от работы"],"explanation":"Серьёзные нарушения ПДД включают превышение скорости (на 15+ mph сверх ограничения), безрассудное вождение, неправильную или беспорядочную смену полос, слишком близкое следование и определённые нарушения, связанные с владением CDL. Остальные варианты являются серьёзными нарушениями или нарушениями приказа об отстранении от работы. Источник: SCDMV CDL Manual, Section 1.3.3."},"50":{"q":"В Южной Каролине какова минимальная дисквалификация за совершение двух серьёзных нарушений ПДД на CMV в течение трёхлетнего периода?","options":["60 days","30 days","120 days","90 days"],"explanation":"Два серьёзных нарушения ПДД в течение трёх лет с участием CMV влекут дисквалификацию не менее чем на 60 days. Источник: SCDMV CDL Manual, Section 1.3.3 (49 CFR 383.51)."},"51":{"q":"В Южной Каролине какова минимальная дисквалификация за три или более серьёзных нарушений ПДД на CMV в течение трёхлетнего периода?","options":["120 days","60 days","180 days","1 год"],"explanation":"Три или более серьёзных нарушений ПДД в течение трёх лет с участием CMV влекут дисквалификацию не менее чем на 120 days. Источник: SCDMV CDL Manual, Section 1.3.3 (49 CFR 383.51)."},"52":{"q":"Какова минимальная дисквалификация в Южной Каролине за первое нарушение водителем приказа об отстранении от работы?","options":["90 days","60 days","180 days","1 год"],"explanation":"Первое нарушение приказа об отстранении от работы влечёт минимальную дисквалификацию на 90 days в Южной Каролине. Источник: SCDMV CDL Manual, Section 1.3.4 (49 CFR 383.51)."},"53":{"q":"В Южной Каролине какова минимальная дисквалификация за второе нарушение приказа об отстранении от работы в течение десятилетнего периода?","options":["1 год","90 days","120 days","3 года"],"explanation":"Второе нарушение приказа об отстранении от работы в течение десятилетнего периода влечёт дисквалификацию не менее чем на один год. Источник: SCDMV CDL Manual, Section 1.3.4."},"54":{"q":"В Южной Каролине какова минимальная дисквалификация за три или более нарушений приказа об отстранении от работы в течение десятилетнего периода?","options":["3 года","1 год","5 лет","Пожизненно"],"explanation":"Три или более нарушений приказа об отстранении от работы в течение десятилетнего периода влекут дисквалификацию не менее чем на три года. Источник: SCDMV CDL Manual, Section 1.3.4."},"55":{"q":"Какова минимальная дисквалификация в Южной Каролине за первое нарушение водителем CMV правил на железнодорожном переезде?","options":["60 days","90 days","30 days","120 days"],"explanation":"Первое нарушение правил на железнодорожном переезде влечёт дисквалификацию не менее чем на 60 days в Южной Каролине. Источник: SCDMV CDL Manual, Section 1.3.5 (49 CFR 383.51)."},"56":{"q":"В Южной Каролине какова минимальная дисквалификация за второе нарушение правил на железнодорожном переезде в течение трёхлетнего периода?","options":["120 days","60 days","90 days","1 год"],"explanation":"Второе нарушение правил на железнодорожном переезде в течение трёх лет влечёт дисквалификацию не менее чем на 120 days. Источник: SCDMV CDL Manual, Section 1.3.5."},"57":{"q":"В Южной Каролине какова минимальная дисквалификация за третье нарушение правил на железнодорожном переезде в течение трёхлетнего периода?","options":["1 год","120 days","180 days","3 года"],"explanation":"Третье нарушение правил на железнодорожном переезде в течение трёх лет влечёт дисквалификацию не менее чем на один год. Источник: SCDMV CDL Manual, Section 1.3.5."},"58":{"q":"Согласно правилам Южной Каролины, на какой срок дисквалифицируется CDL водителя CMV после второго осуждения в течение трёх лет за отправку текстовых сообщений во время управления CMV?","options":["60 days","30 days","120 days","1 год"],"explanation":"Два или более осуждений за отправку текстовых сообщений во время управления CMV влекут дисквалификацию: 60 days за второе нарушение в течение трёх лет и 120 days за три или более в течение трёх лет. Водители также подвергаются гражданским штрафам до $2,750. Источник: SCDMV CDL Manual, Sections 2.9.6 и 2.9.5."},"59":{"q":"Согласно Закону Южной Каролины о вождении без рук и без отвлечения внимания (Hands-Free and Distracted Driving Act), каков штраф за первое нарушение, связанное с удержанием мобильного устройства в руках во время вождения?","options":["$100 плюс судебные сборы","$25 плюс судебные сборы","$200 плюс судебные сборы","$500 плюс судебные сборы"],"explanation":"Закон Южной Каролины о вождении без рук и без отвлечения внимания (S.C. Code Section 56-5-3890) устанавливает штраф $100 плюс судебные сборы за первое нарушение и $200 плюс два балла за второе нарушение в течение трёх лет; для водителей CMV два осуждения в течение трёх лет также влекут дисквалификацию на 60 days. Источник: SCDPS Hands Free SC; S.C. Code 56-5-3890."},"60":{"q":"На межштатной автомагистрали в Южной Каролине какова максимальная разрешённая скорость для коммерческого грузовика, если иное не обозначено более низким значением?","options":["65 mph, поскольку для грузовиков установлен более низкий лимит, чем для легковых автомобилей","70 mph, столько же, сколько и для других транспортных средств","60 mph на всех участках межштатной автомагистрали","55 mph для любого транспортного средства массой более 26,001 lbs"],"explanation":"В Южной Каролине НЕ устанавливается отдельный, более низкий лимит скорости для грузовиков. Согласно S.C. Code 56-5-1520, максимальная скорость в системе межштатных автомагистралей составляет 70 mph, и крупные грузовики подчиняются тому же обозначенному лимиту. Источник: S.C. Code 56-5-1520; SCDMV CDL Manual."},"61":{"q":"Согласно законодательству Южной Каролины, какова максимальная разрешённая скорость на многополосном первичном шоссе с разделительной полосой (не межштатной автомагистрали), если иное не обозначено?","options":["55 mph","65 mph","60 mph","70 mph"],"explanation":"S.C. Code 56-5-1520 устанавливает 60 mph как максимум на многополосных первичных шоссе с разделительной полосой, 70 mph в системе межштатных автомагистралей и 55 mph на прочих (неразделённых) шоссе. Источник: S.C. Code 56-5-1520."},"62":{"q":"Закон Южной Каролины «Move Over» (S.C. Code 56-5-1538) требует от водителя, приближающегося к остановившемуся аварийному транспортному средству с включёнными проблесковыми маячками, в ПЕРВУЮ очередь сделать что, если это можно выполнить безопасно?","options":["Полностью остановиться и ждать, пока аварийное транспортное средство не уедет","Освободить полосу, ближайшую к аварийному транспортному средству, перестроившись в несмежную полосу","Подать звуковой сигнал и продолжить движение с обозначенной скоростью","Съехать на обочину позади аварийного транспортного средства"],"explanation":"Согласно S.C. Code 56-5-1538, водитель должен уступить, перестроившись в полосу, не смежную с остановившимся уполномоченным аварийным транспортным средством (скорая помощь, полиция, пожарная, спасательная, эвакуационная или буксировочная машина), когда это безопасно сделать. Источник: S.C. Code 56-5-1538; SCDPS."},"63":{"q":"Согласно закону Южной Каролины «Move Over», что должен сделать водитель, если перестроиться в полосу подальше от остановившегося аварийного транспортного средства невозможно или небезопасно?","options":["Полностью остановиться в текущей полосе","Сохранять обозначенную скорость, но включить аварийную сигнализацию","Двигаться с осторожностью и значительно снизить скорость","Съехать на ближайшей развязке и выбрать альтернативный маршрут"],"explanation":"S.C. Code 56-5-1538 требует, чтобы водитель, который не может безопасно перестроиться, продолжал движение с должной осторожностью и значительно снизил скорость транспортного средства, поддерживая скорость, безопасную для дорожных условий. Источник: S.C. Code 56-5-1538; SCDPS."},"64":{"q":"Когда транспортное средство со знаками опасного груза останавливается на железнодорожном переезде в Южной Каролине, где оно должно остановиться относительно ближайшего рельса?","options":["Между 15 и 50 feet от ближайшего рельса","Между 10 и 25 feet от ближайшего рельса","Между 50 и 100 feet от ближайшего рельса","В пределах 15 feet от ближайшего рельса"],"explanation":"SCDMV CDL Manual и S.C. Code 56-5-2720 требуют, чтобы транспортное средство со знаками опасного груза останавливалось в пределах 50 feet, но не ближе 15 feet от ближайшего рельса. Источник: SCDMV CDL Manual 9.6.12; S.C. Code 56-5-2720."},"65":{"q":"Какое из следующих транспортных средств всегда обязано останавливаться на каждом железнодорожном переезде в Южной Каролине (если переезд не освобождён от этого требования)?","options":["Гружёный самосвал","Автобус, перевозящий пассажиров","Пустой бортовой полуприцеп","Пикап с прицепом-платформой"],"explanation":"Автобус, перевозящий пассажиров, школьный автобус и любое транспортное средство со знаками опасного груза должны останавливаться на каждом железнодорожном переезде (на расстоянии от 15 до 50 feet от ближайшего рельса), смотреть и слушать. Источник: SCDMV CDL Manual; S.C. Code 56-5-2720."},"66":{"q":"Пока какая-либо часть вашего коммерческого транспортного средства пересекает железнодорожные пути в Южной Каролине, CDL Manual предписывает НЕ делать что из следующего?","options":["Держать руки на руле","Смотреть в обе стороны вдоль путей","Переключать передачи","Следить за вторым поездом"],"explanation":"SCDMV CDL Manual гласит: не останавливайтесь, не переключайте передачи и не меняйте полосу, пока какая-либо часть вашего транспортного средства пересекает пути. Выбирайте передачу, которая позволит вам освободить пути без переключения. Источник: SCDMV CDL Manual 2.15.4 / 13.1.8."},"67":{"q":"В Южной Каролине водитель, встречающий остановившийся школьный автобус с включёнными мигающими красными огнями, НЕ обязан останавливаться при движении в противоположном направлении на каком типе проезжей части?","options":["Любая двухполосная дорога с центральной полосой для поворота","Многополосное шоссе","Любая дорога с обозначенным лимитом скорости выше 45 mph","Дорога с нарисованной (невозвышающейся) разделительной полосой"],"explanation":"Согласно S.C. Code 56-5-2770, водитель не обязан останавливаться при встрече с остановившимся школьным автобусом, двигаясь в противоположном направлении на многополосном шоссе. Водители, движущиеся в том же направлении, а также на двухполосных дорогах, всё равно обязаны останавливаться. Источник: S.C. Code 56-5-2770."},"68":{"q":"Водитель, движущийся в ТОМ ЖЕ направлении позади школьного автобуса в Южной Каролине, который включил мигающие красные огни и выдвинул знак «стоп», должен сделать что?","options":["Снизить скорость до 15 mph и проехать с осторожностью","Остановиться и оставаться на месте, пока автобус не тронется или красные огни не перестанут мигать","Проезжать только слева, если детей не видно","Останавливаться только если автобус находится на неразделённой двухполосной дороге"],"explanation":"S.C. Code 56-5-2770 требует, чтобы транспортное средство, приближающееся с любого направления (кроме исключения для встречного движения на многополосной дороге), остановилось, не доезжая до школьного автобуса с мигающими красными огнями, и не продолжало движение, пока автобус не возобновит движение или красные огни не будут отключены. Источник: S.C. Code 56-5-2770."},"69":{"q":"Когда CMV остановился на двухполосной дороге, по которой движется транспорт в обоих направлениях, в Южной Каролине, где следует разместить три предупреждающих треугольника?","options":["Все три в пределах 10 feet от задней части транспортного средства","В пределах 10 feet от транспортного средства, плюс 100 feet позади и 100 feet впереди","На 10 feet, 200 feet и 500 feet позади транспортного средства","Один у транспортного средства и два рядом на расстоянии 50 feet позади"],"explanation":"На двусторонней/неразделённой дороге SCDMV CDL Manual предписывает разместить один треугольник в пределах 10 feet от передней или задней части, один на расстоянии 100 feet позади и один на расстоянии 100 feet впереди транспортного средства. Источник: SCDMV CDL Manual 2.5 (Warning Devices)."},"70":{"q":"Когда CMV остановился на дороге с односторонним движением или на разделённом шоссе в Южной Каролине, на каких расстояниях следует размещать предупреждающие устройства в сторону приближающегося транспорта?","options":["10 feet, 100 feet и 200 feet","10 feet, 50 feet и 100 feet","25 feet, 100 feet и 300 feet","100 feet, 200 feet и 300 feet"],"explanation":"На дороге с односторонним движением или на разделённом шоссе SCDMV CDL Manual предписывает размещать три светоотражающих треугольника на расстоянии 10 feet, 100 feet и 200 feet в сторону приближающегося транспорта. Источник: SCDMV CDL Manual 2.5."},"71":{"q":"После остановки на обочине шоссе в Южной Каролине, в течение скольких минут водитель CMV должен выставить аварийные предупреждающие устройства?","options":["5 минут","10 минут","15 минут","30 минут"],"explanation":"SCDMV CDL Manual гласит, что если вы вынуждены остановиться на дороге или обочине, вы должны выставить аварийные предупреждающие устройства в течение 10 минут. Источник: SCDMV CDL Manual 2.5."},"72":{"q":"Закон Южной Каролины о левой полосе («Move Right») для автомагистралей с контролируемым доступом, как правило, ограничивает использование крайней левой полосы каким назначением?","options":["Транспортные средства, движущиеся со скоростью, равной или выше обозначенного лимита","Обгон и опережение другого транспортного средства","Только транспортные средства массой менее 10,000 lbs","Транспортные средства с попутчиками и общественный транспорт"],"explanation":"Согласно S.C. Code 56-5-1885, водители могут использовать крайнюю левую полосу автомагистрали с контролируемым доступом только при обгоне и опережении. Источник: S.C. Code 56-5-1885; SCDPS Move Right Law."},"73":{"q":"Закон Южной Каролины о левой полосе даёт особое исключение для коммерческого транспортного средства, которое не может безопасно покинуть левую полосу из-за какого условия?","options":["Пассажир спит в спальном отсеке","Уклон дороги или другое транспортное средство, обгоняющее справа","Перевозка груза со знаком опасных материалов","Движение ночью при сниженной видимости"],"explanation":"Согласно S.C. Code 56-5-1885, водитель CMV освобождается от ограничения на левую полосу, когда он не может безопасно перестроиться вправо из-за уклона дороги или потому что другое транспортное средство обгоняет/опережает справа. Источник: S.C. Code 56-5-1885; SCDPS."},"74":{"q":"Управляя автобусом в Южной Каролине, вы приближаетесь к разводному мосту, у которого НЕТ светофора и НЕТ регулировщика движения. Что вы должны сделать?","options":["Пересечь со сниженной скоростью без остановки","Остановиться не менее чем за 50 feet перед разводной частью и убедиться, что она полностью закрыта","Остановиться за 15-50 feet перед разводной частью","Останавливаться только если звенит предупреждающий звонок"],"explanation":"SCDMV CDL Manual (4.3.6) предписывает водителям автобусов останавливаться у разводных мостов, не имеющих светофора или регулировщика, останавливаясь не менее чем за 50 feet перед разводной частью и убедившись, что она полностью закрыта, прежде чем пересекать. Источник: SCDMV CDL Manual 4.3.6."},"75":{"q":"Какой перечень нарушений влечёт за собой первое лишение CDL в Южной Каролине на срок не менее 60 дней?","options":["Слишком близкое следование за транспортным средством","Нарушение на железнодорожном переезде в одном уровне с дорогой","Штраф за превышение нагрузки на ось","Отсутствие требуемого знака опасного груза"],"explanation":"SCDMV CDL Manual гласит, что владелец CDL лишается CDL на срок не менее 60 дней за первое нарушение на железнодорожном переезде в одном уровне с дорогой, на 120 дней за второе в течение трёх лет и на один год за третье. Источник: SCDMV CDL Manual 1.3.5; 49 CFR 383.51."},"76":{"q":"В Южной Каролине какова стандартная максимальная разрешённая ШИРИНА транспортного средства/груза, до того как потребуется разрешение на негабаритный груз?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"Разрешённый предел ширины в Южной Каролине составляет 8 feet 6 inches (102 inches); грузы шире этого требуют разрешения SCDOT на негабарит. Максимальная разрешённая высота — 13 feet 6 inches. Источник: SCDOT Oversize/Overweight Permits."},"77":{"q":"Без разрешения какова максимальная разрешённая ВЫСОТА коммерческого транспортного средства с грузом в Южной Каролине?","options":["13 feet 6 inches","14 feet 0 inches","12 feet 6 inches","13 feet 0 inches"],"explanation":"Разрешённая максимальная высота в Южной Каролине составляет 13 feet 6 inches; всё, что выше, требует разрешения SCDOT на превышение высоты и проверки маршрута на предмет габарита под путепроводами. Источник: SCDOT Oversize/Overweight Permits."},"78":{"q":"Согласно правилам разрешений SCDOT, негабаритным грузам в Южной Каролине, как правило, разрешено перемещаться в какое время?","options":["24 часа в сутки, в любой день","С получаса после восхода солнца до получаса перед заходом солнца, с понедельника по субботу","Только с 9 p.m. до 5 a.m., чтобы избежать движения","Только в будние дни, без движения по субботам"],"explanation":"SCDOT, как правило, ограничивает перемещение негабаритных грузов промежутком с получаса после восхода солнца до получаса перед заходом солнца, с понедельника по субботу, без движения по воскресеньям и в установленные праздничные дни, плюс дополнительные ограничения для очень широких грузов. Источник: SCDOT Oversize/Overweight Permits."},"79":{"q":"Водитель, незаконно объезжающий остановившийся школьный автобус в Южной Каролине, и водитель, приближающийся к остановившемуся аварийному транспортному средству согласно закону «Move Over», оба подлежат наказанию. Какое утверждение верно в отношении нарушения закона «Move Over»?","options":["Это лишь гражданский штраф в $25 без судебных издержек","Это правонарушение (misdemeanor), влекущее штраф в диапазоне от $300 до $500","Оно влечёт автоматическое пожизненное лишение CDL","Это нарушение, наказуемое только предупреждением в течение первого года"],"explanation":"Нарушение закона Южной Каролины «Move Over» (S.C. Code 56-5-1538) является правонарушением (misdemeanor), наказуемым штрафом, как правило, в диапазоне $300-$500; для сравнения, нарушение закона о левой полосе «Move Right» (56-5-1885) — это гражданский штраф в $25. Источник: S.C. Code 56-5-1538; SCDPS."},"80":{"q":"Какое ведомство выдаёт коммерческие водительские удостоверения (CDL) в Южной Каролине?","options":["Департамент транспортных средств Южной Каролины (SCDMV)","Департамент транспорта Южной Каролины (SCDOT)","Федеральное управление по безопасности грузоперевозок (FMCSA)","Дорожный патруль Южной Каролины"],"explanation":"CDL в Южной Каролине выдаются Департаментом транспортных средств Южной Каролины (SCDMV). FMCSA устанавливает федеральные стандарты CDL, но не выдаёт само удостоверение; SCDOT занимается дорогами/разрешениями, а не лицензированием. Источник: страница SCDMV Commercial Licenses (dmv.sc.gov)."},"81":{"q":"В Южной Каролине какая стандартная форма используется для подачи заявления на ученическое коммерческое разрешение (CLP) или CDL?","options":["SCDMV Form 447-CDL","SCDMV Form DL-405A","SCDMV Form MV-93","FMCSA Form MCSA-5876"],"explanation":"Заявление на CLP и CDL в Южной Каролине — это SCDMV Form 447-CDL. DL-405A — это форма медицинской самосертификации, MV-93 — контрольный список документов, удостоверяющих личность, а MCSA-5876 — федеральный сертификат медицинского эксперта. Источник: SCDMV Getting Your First CDL (dmv.sc.gov)."},"82":{"q":"Как долго действует ученическое коммерческое разрешение (CLP) в Южной Каролине, прежде чем истечёт его срок?","options":["Один год","180 дней","Шесть месяцев","Два года"],"explanation":"В Южной Каролине CLP имеет срок действия один год. Источник: SCDMV Getting Your First CDL (dmv.sc.gov). (Федеральное правило допускает срок действия CLP до одного года, который применяет Южная Каролина.)"},"83":{"q":"После выдачи ученического коммерческого разрешения в Южной Каролине, как долго вы должны его иметь, прежде чем получите право сдавать экзамен по навыкам CDL?","options":["Не менее 14 дней","Не менее 30 дней","Не менее 10 дней","Не менее 7 дней"],"explanation":"Вы должны иметь CLP минимум 14 дней, прежде чем сможете сдавать экзамен по навыкам. Источник: SCDMV Getting Your First CDL (dmv.sc.gov); это отражает федеральный 14-дневный срок удержания CLP (49 CFR 383.25)."},"84":{"q":"Согласно самосертификации CDL в Южной Каролине, из скольких категорий деятельности водитель должен выбрать?","options":["Четыре","Две","Три","Пять"],"explanation":"Существует четыре категории самосертификации: межштатные неисключённые (non-excepted interstate), межштатные исключённые (excepted interstate), внутриштатные неисключённые (non-excepted intrastate) и внутриштатные исключённые (excepted intrastate). Водители удостоверяют свою категорию в SCDMV. Источник: SCDMV / Form DL-405A (dmv.sc.gov)."},"85":{"q":"Какая форма Южной Каролины используется для самостоятельного подтверждения вашего типа коммерческой деятельности и подачи статуса медицинской сертификации в SCDMV?","options":["Form DL-405A (CDL Holder's Medical Certification)","Form 447-CDL (CDL Application)","Form MV-93 (Citizen's Checklist)","Form MCSA-5875 (Medical Examination Report)"],"explanation":"Южная Каролина использует Form DL-405A для самосертификации владельца CDL и медицинской сертификации. Form 447-CDL — это заявление на удостоверение, MV-93 — контрольный список документов, удостоверяющих личность, а MCSA-5875 — федеральный отчёт об осмотре. Источник: SCDMV Renew or Upgrade Your CDL (dmv.sc.gov)."},"86":{"q":"Какая категория самосертификации требует, чтобы владелец CDL в Южной Каролине предоставил действительный сертификат медицинского эксперта DOT?","options":["Межштатные неисключённые (non-excepted interstate)","Межштатные исключённые (excepted interstate)","Внутриштатные исключённые (excepted intrastate)","Ни одна категория не требует медицинского сертификата"],"explanation":"Водители категории межштатных неисключённых (non-excepted interstate) должны иметь действительный сертификат медицинского эксперта DOT, соответствующий стандартам FMCSA. Водители исключённых категорий не обязаны его предоставлять. Источник: SCDMV / Form DL-405A (dmv.sc.gov); 49 CFR 391.41."},"87":{"q":"Кто уполномочен проводить медицинский осмотр и выдавать сертификат медицинского эксперта, который должен иметь водитель CDL категории неисключённых в Южной Каролине?","options":["Медицинский специалист, внесённый в National Registry of Certified Medical Examiners FMCSA","Любой лицензированный врач по выбору водителя","Экзаменатор SCDMV в отделении","Врач, утверждённый Департаментом транспорта Южной Каролины"],"explanation":"Осмотр должен быть проведён, а сертификат выдан медицинским специалистом, внесённым в National Registry of Certified Medical Examiners FMCSA. Источник: SCDMV Commercial Licenses (dmv.sc.gov); 49 CFR 390.103."},"88":{"q":"Перед сдачей экзамена по навыкам CDL в Южной Каролине какое требование применяется к кандидатам, получившим CLP после 7 февраля 2022 года?","options":["Пройти утверждённую FMCSA программу обучения водителей начального уровня (ELDT)","Иметь чистую водительскую историю в течение пяти лет подряд","Накатать 160 часов вождения с SCDMV","Сдать отдельный курс безопасного вождения SCDMV"],"explanation":"Кандидаты, чьё CLP было выдано после 7 февраля 2022 года, должны пройти утверждённую FMCSA программу ELDT у зарегистрированного поставщика обучения, прежде чем сдавать экзамен по навыкам. Источник: SCDMV Getting Your First CDL (dmv.sc.gov); 49 CFR Part 380 Subpart F."},"89":{"q":"Экзамен по навыкам CDL в Южной Каролине состоит из трёх частей. В каком наборе правильно перечислены эти три части?","options":["Предрейсовый осмотр, базовое управление транспортным средством и вождение по дороге","Письменный тест на знания, проверка зрения и вождение по дороге","Предрейсовый осмотр, опасные материалы и ночное вождение","Проверка пневматических тормозов, параллельная парковка и въезд на автостраду"],"explanation":"Экзамен по навыкам CDL состоит из трёх компонентов: предрейсовый осмотр, базовое управление транспортным средством (вне дороги) и тест вождения по дороге. Источник: SCDMV Getting Your First CDL (dmv.sc.gov); 49 CFR 383.113."},"90":{"q":"Каков стандартный срок действия CDL в Южной Каролине, прежде чем его нужно продлить?","options":["8 лет","5 лет","4 года","10 лет"],"explanation":"CDL в Южной Каролине действует 8 лет и истекает в день рождения владельца в последний год цикла. Источник: SCDMV (dmv.sc.gov). (Подтверждение HazMat ограничено отдельным 5-летним циклом TSA Security Threat Assessment.)"},"91":{"q":"CDL Южной Каролины с подтверждением на перевозку опасных материалов (HazMat) ограничено каким отдельным сроком?","options":["5-летний цикл TSA Security Threat Assessment","2-летний цикл продления только для HazMat","10-летняя федеральная сертификация HazMat","1-летняя проверка HazMat от SCDMV"],"explanation":"Хотя само CDL действует 8 лет, подтверждение HazMat привязано к TSA Security Threat Assessment, которое необходимо продлевать каждые 5 лет. Источник: SCDMV Commercial Licenses (dmv.sc.gov); 49 CFR 1572."},"92":{"q":"Когда владелец CDL в Южной Каролине должен предоставить в SCDMV подтверждение медицинской пригодности (самосертификацию/медицинский сертификат)?","options":["Каждый раз, когда подают заявление на CDL, продлевают, повышают категорию, меняют адрес или запрашивают дубликат CDL","Только один раз, при первом получении CDL","Только при продлении через 8 лет","Только при добавлении подтверждения HazMat"],"explanation":"Водители должны предоставлять подтверждение медицинской пригодности каждый раз, когда подают заявление на CLP/CDL, повышают категорию, продлевают, меняют адрес или запрашивают дубликат. Источник: SCDMV Commercial Licenses (dmv.sc.gov)."},"93":{"q":"Каков минимальный возраст для получения CDL в Южной Каролине для управления коммерческим транспортным средством только в пределах штата (внутриштатные перевозки)?","options":["18 лет","19 лет","21 год","20 лет"],"explanation":"Вам должно быть не менее 18 лет, чтобы иметь CDL для внутриштатного вождения в пределах Южной Каролины, и не менее 21 года для межштатного вождения. Источник: SCDMV Getting Your First CDL (dmv.sc.gov)."},"94":{"q":"Какой минимальный возраст требует Южная Каролина для управления коммерческим транспортным средством в межштатной торговле (через границы штатов)?","options":["21 год","18 лет","19 лет","25 лет"],"explanation":"Водителю должно быть не менее 21 года для управления CMV в межштатной торговле; лица в возрасте 18-20 лет ограничены внутриштатной деятельностью. Источник: SCDMV Getting Your First CDL (dmv.sc.gov); 49 CFR 391.11."},"95":{"q":"Как обычно проверяется сертификат медицинского эксперта водителя категории межштатных неисключённых после подачи в SCDMV?","options":["Он проверяется электронно/вносится в водительскую историю","Он должен быть нотариально заверен в отделении SCDMV","Он отправляется по почте в FMCSA для ручного утверждения","Он проверяется только медицинским экспертом, а не штатом"],"explanation":"Для водителей категории неисключённых информация медицинского сертификата проверяется электронно, и медицинский статус добавляется в водительскую историю CDL. Источник: SCDMV Commercial Licenses (dmv.sc.gov); 49 CFR 383.71/383.73."},"96":{"q":"Перед подачей заявления на CDL или CLP Южная Каролина требует, чтобы кандидат уже имел какой документ?","options":["Действительное непросроченное водительское удостоверение Южной Каролины","Действительный паспорт","Федеральную карту TWIC","Бизнес-лицензию Южной Каролины"],"explanation":"Кандидаты должны иметь действительное непросроченное (обычное) водительское удостоверение Южной Каролины перед подачей заявления на CLP/CDL. Источник: SCDMV Getting Your First CDL (dmv.sc.gov)."},"97":{"q":"При продлении CDL в Южной Каролине какой документ должен быть предъявлен дополнительно к заявлению и медицинской/самосертификации?","options":["Информация о страховании автогражданской ответственности от компании, лицензированной в Южной Каролине","Нотариально заверенный аффидевит работодателя","Подтверждение прохождения нового курса ELDT","Новая проверка отпечатков пальцев TSA для всех подтверждений"],"explanation":"Южная Каролина требует при продлении CDL информацию о страховании автогражданской ответственности от лицензированного в SC страховщика, наряду с Form 447-CDL и медицинской сертификацией Form DL-405A в применимых случаях. Источник: SCDMV Renew or Upgrade Your CDL (dmv.sc.gov)."},"98":{"q":"Если владелец CDL в Южной Каролине допускает истечение срока требуемого федеральным законодательством сертификата медицинского эксперта, будучи сертифицированным как неисключённый, каковы последствия для CDL?","options":["CDL понижается в категории, так что коммерческие привилегии утрачиваются до тех пор, пока действующий сертификат не будет внесён в дело","Ничего не меняется до продления через 8 лет","CDL аннулируется навсегда без возможности восстановления","Затрагивается только подтверждение HazMat"],"explanation":"Когда срок медицинского сертификата водителя категории неисключённых истекает или он отсутствует в деле, штат обязан понизить CDL в категории (лишая привилегий коммерческого вождения) до тех пор, пока не будет предоставлен действующий сертификат. Источник: правила медицинской сертификации SCDMV / FMCSA (dmv.sc.gov); 49 CFR 383.73."},"99":{"q":"При продлении CDL в Южной Каролине медицинскую самосертификацию (Form DL-405A), как правило, необходимо подавать повторно в какой ситуации?","options":["Если она ещё не была подана или если изменился тип осуществляемой коммерческой деятельности","Только если водитель переехал в другой штат","Только если водителю больше 65 лет","Никогда, поскольку это разовая подача"],"explanation":"Южная Каролина требует самосертификацию DL-405A при продлении, если она ещё не была подана или если изменился тип коммерческой деятельности водителя (категория самосертификации). Источник: SCDMV Renew or Upgrade Your CDL (dmv.sc.gov)."}},"tr":{"0":{"q":"South Carolina karayollarında, onaylı güvenlik aygıtları hariç olmak üzere, bir aracın veya yükünün toplam dış genişliği en fazla ne kadar olabilir?","options":["96 inches","102 inches","108 inches","120 inches"],"explanation":"South Carolina Code 56-5-4030, onaylı güvenlik aygıtları hariç olmak üzere, bir aracın veya yükün toplam dış genişliğini 102 inches (8 feet 6 inches) olarak belirler. Bu, eyalet genelinde benimsenen federal standartla uyumludur. Kaynak: SC Code 56-5-4030 (Araç genişliği)."},"1":{"q":"South Carolina karayollarında, çoğu araç için yüklü veya yüksüz halde maksimum yükseklik nedir?","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"explanation":"South Carolina Code 56-5-4060 araç yüksekliğini 13 feet 6 inches ile sınırlar. Dar bir istisna, geçerli bir SCDOT güzergah izni bulunan bir otomobil taşıyıcı ünitesi veya semer-montaj (saddle-mount) kombinasyonu için 14 feet'e izin verir. Kaynak: SC Code 56-5-4060 (Araç yüksekliği)."},"2":{"q":"South Carolina'da tek bir motorlu araç (örneğin düz kamyon) için tamponlar ve yük dahil maksimum uzunluk nedir?","options":["35 feet","40 feet","45 feet","48 feet"],"explanation":"South Carolina Code 56-5-4070, tek bir motorlu aracı, ön ve arka tamponlar ile yük dahil olmak üzere 40 feet azami toplam uzunlukla sınırlar. Otobüsler ve bazı motorlu karavanlar (motor home) ayrı olarak ele alınır. Kaynak: SC Code 56-5-4070 (Araç uzunluğu)."},"3":{"q":"South Carolina'da iki üniteli bir çekici-yarı römork kombinasyonunda, römork veya yarı römorkun (yük dahil) maksimum uzunluğu nedir?","options":["48 feet","50 feet","53 feet","57 feet"],"explanation":"South Carolina Code 56-5-4070, iki üniteli bir çekici kombinasyonundaki bir römork veya yarı römorkun, yük dahil 53 feet'e kadar olmasına izin verir. 53 feet'lik bir römorkun arka alttan koruma bariyeri (underride guard) bulunmalıdır. Kaynak: SC Code 56-5-4070."},"4":{"q":"South Carolina'da tek bir aks karayoluna en fazla ne kadar brüt ağırlık uygulayabilir?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"South Carolina Code 56-5-4140, herhangi bir tek aksa düşen brüt ağırlığı 20,000 pounds ile sınırlar. Bu, federal tek aks sınırıyla aynıdır. Kaynak: SC Code 56-5-4140 (Araçların brüt ağırlığı)."},"5":{"q":"South Carolina'da özel izin olmadan izin verilen maksimum toplam brüt araç ağırlığı nedir?","options":["73,280 pounds","76,000 pounds","80,000 pounds","88,000 pounds"],"explanation":"South Carolina Code 56-5-4140, SCDOT tarafından özel izin verilen araçlar dışında, toplam brüt ağırlığı 80,000 pounds ile sınırlar. Bu, federal eyaletler arası maksimum değeri yansıtır. Kaynak: SC Code 56-5-4140."},"6":{"q":"South Carolina eyaletler arası (Interstate) karayollarında, bir ikiz aks grubuna (uygulama toleransı dahil) izin verilen maksimum brüt ağırlık nedir?","options":["32,000 pounds","34,000 pounds","35,200 pounds","36,000 pounds"],"explanation":"Interstate sisteminde South Carolina, 34,000-pound'luk federal taban değerin üzerindeki eyalet uygulama toleransını da içeren 35,200 pounds'luk bir ikiz aks brüt ağırlığına izin verir. Kaynak: SC Code 56-5-4140; SCDMV/SCDOT boyut-ağırlık rehberi."},"7":{"q":"South Carolina'da eyaletler arası olmayan (eyalet) karayollarında, 40 ile 96 inches arasında aralıklı bir ikiz aks grubuna izin verilen maksimum brüt ağırlık nedir?","options":["34,000 pounds","35,200 pounds","36,000 pounds","40,000 pounds"],"explanation":"South Carolina Code 56-5-4140, Interstate dışındaki karayollarında bir ikiz aksta (40 ile 96 inches arasında aralıklı iki veya daha fazla ardışık aks) 36,000 pounds'a kadar izin verir. Interstate ikiz aks sınırı ise 35,200 pounds ile daha düşüktür. Kaynak: SC Code 56-5-4140."},"8":{"q":"South Carolina, aralar arasındaki mesafeye dayalı olarak bir aks grubunda izin verilen brüt ağırlığı belirlemek için hangi formülü kullanır?","options":["Federal Köprü Formülü (Formül B)","Brüt Kombinasyon Ağırlık Derecesi formülü","Davis yuvarlanma direnci formülü","Tek aks tolerans formülü"],"explanation":"South Carolina, 23 U.S.C. 127 ile uyumlu olarak, iki veya daha fazla ardışık aks grubundaki maksimum ağırlığı aks aralığına ve aks sayısına göre belirlemek için Federal Köprü Formülü'nü (Bridge Formula B) uygular. Kaynak: SC Code 56-5-4140; FHWA Federal Köprü Formülü."},"9":{"q":"South Carolina'da yasal sınırları aşan araçlar ve yükler için oversize/overweight (OSOW) izinlerini hangi eyalet kurumu verir?","options":["SC Motorlu Taşıtlar Dairesi (SCDMV)","SC Kamu Güvenliği Dairesi (SCDPS)","SC Ulaştırma Dairesi (SCDOT)","SC Gelir Dairesi (SCDOR)"],"explanation":"South Carolina Ulaştırma Dairesi (SCDOT) Oversize/Overweight İzin Ofisi, yasal boyut veya ağırlık sınırlarını aşan yükler için OSOW izinlerini takdir yetkisiyle verir. Kaynak: SCDOT Oversize/Overweight İzinleri programı."},"10":{"q":"South Carolina'da bir yükün genişliği için genellikle ne zaman oversize izni gereklidir?","options":["Genişlik 96 inches'i aştığında","Genişlik 102 inches'i (8'6\") aştığında","Genişlik 120 inches'i (10') aştığında","Genişlik 144 inches'i (12') aştığında"],"explanation":"South Carolina'nın yasal genişlik sınırı 102 inches (8 feet 6 inches) olduğundan, bundan daha geniş herhangi bir yük için bir SCDOT oversize izni gereklidir. Kaynak: SC Code 56-5-4030; SCDOT OSOW izin kılavuzları."},"11":{"q":"Bir taşıyıcı, South Carolina oversize/overweight iznine nasıl başvurabilir?","options":["Yalnızca SCDMV'ye kağıt form posta ile göndererek","SCDOT'un çevrimiçi SafeHaul sistemi aracılığıyla (veya telefon/posta/e-posta ile)","Yalnızca bir ilçe adliyesinde şahsen","FMCSA ulusal portalı aracılığıyla"],"explanation":"Taşıyıcılar OSOW izinlerini SCDOT'un çevrimiçi SafeHaul (iHaul) sistemi aracılığıyla veya SCDOT OSOW İzin Ofisi'ne telefon, posta ya da e-posta ile başvurarak alır. Kaynak: SCDOT Oversize/Overweight İzinleri sayfası (SafeHaul)."},"12":{"q":"South Carolina'nın çiftçilik/ormancılık istisnası kapsamında, kendinden hareketli çiftçilik ekipmanları ve ormancılık makineleri, hangi genişliği aşmamaları koşuluyla gün ışığında oversize izni olmadan hareket edebilir?","options":["8 feet 6 inches","10 feet","12 feet","14 feet"],"explanation":"South Carolina, çiftçilik ekipmanları, ormancılık makineleri ve benzeri ekipmanların; 12 feet genişliği, 13 feet 6 inches yüksekliği veya 90,000 pounds'u aşmamaları halinde gün ışığında izin olmadan hareket etmelerine izin verir. Kaynak: SCDOT OSOW kılavuzları (tarım/ormancılık istisnası)."},"13":{"q":"South Carolina'da iki şeritli bir karayolunda, izinli bir yük hangi genişlikte ön refakat (pilot) aracı gerektirmeye başlar?","options":["10 feet'in üzerinde","12 feet'in üzerinde","14 feet'in üzerinde","16 feet'in üzerinde"],"explanation":"İki şeritli karayollarında South Carolina, 12 feet'i aşıp 14 feet'e kadar genişliğindeki yükler için ön refakat aracı gerektirir; 14 feet'i aşıp 16 feet'e kadar olan yükler ise hem ön hem arka refakat aracı gerektirir. Kaynak: SCDOT OSOW refakat/pilot araç gereklilikleri."},"14":{"q":"South Carolina'da 53 feet'lik bir yarı römork için, kingpin'den arka aksın (veya arka ikiz aks grubunun) merkezine kadar olan mesafe hangi değeri aşamaz?","options":["37 feet","41 feet","43 feet","46 feet"],"explanation":"South Carolina Code 56-5-4070, 53 feet'lik bir römorkta kingpin'den arka aksa (veya arka ikiz aks merkezine) kadar olan mesafenin 41 feet'ten fazla olmamasını gerektirir. Kaynak: SC Code 56-5-4070."},"15":{"q":"South Carolina, eyaletler arası olmayan karayollarındaki ağırlık sınırlarına genellikle hangi uygulama toleransını uygular?","options":["yüzde 5","yüzde 10","yüzde 15","Hiçbir tolerans tanınmaz"],"explanation":"South Carolina, eyaletler arası olmayan (eyalet ve tamamlayıcı) karayollarındaki ağırlık sınırlarına %10'luk bir uygulama toleransı uygular. Interstate ağırlıkları, belirtilen toleranslar dahilinde daha katı şekilde uygulanır. Kaynak: SCDOT/SCDMV boyut-ağırlık rehberi; SC Code 56-5-4140."},"16":{"q":"South Carolina'daki 14 feet'lik yükseklik istisnası kapsamında, bir otomobil taşıyıcı veya semer-montaj (saddle-mount) kombinasyonunun ayrıca neye sahip olması gerekir?","options":["FMCSA'dan bir muafiyet","SCDOT tarafından verilen geçerli bir güzergah izni","Bir tehlikeli madde onayı (endorsement)","İlçe şerifinden yazılı onay"],"explanation":"South Carolina Code 56-5-4060, bir otomobil taşıyıcı ünitesi veya semer-montaj kombinasyonu için 14 feet'e kadar izni yalnızca sahibi/operatörünün SCDOT tarafından verilen geçerli bir güzergah iznine sahip olması halinde verir. Kaynak: SC Code 56-5-4060."},"17":{"q":"South Carolina'da bir motorlu karavan (motor home) için, dönüş yarıçapının 48 feet veya daha az olması koşuluyla izin verilen maksimum uzunluk nedir?","options":["40 feet","42 feet","45 feet","48 feet"],"explanation":"South Carolina Code 56-5-4070, bir motorlu karavanın dönüş yarıçapı 48 feet veya daha az ise, genel 40-foot'luk tek araç sınırına bir istisna olarak 45 feet'e kadar uzunlukta olmasına izin verir. Kaynak: SC Code 56-5-4070."},"18":{"q":"South Carolina'da ticari olmayan kullanımdaki motorlu karavanlar, seyahat römorkları ve kamyon karavanları üzerindeki aparatlar (appurtenances) yasal genişliğin ne kadar ötesine uzanabilir?","options":["Her iki tarafta da 3 inches'e kadar","Bir tarafta 6 inches ve diğer tarafta 4 inches'e kadar","Yalnızca bir tarafta 12 inches'e kadar","Yasal genişliğin ötesine hiçbir uzanmaya izin verilmez"],"explanation":"South Carolina Code 56-5-4030, ticari olmayan motorlu karavanlar, seyahat römorkları ve kamyon karavanları üzerindeki aparatların 102-inch'lik genişlik sınırının ötesine bir tarafta en fazla 6 inches ve diğer tarafta 4 inches uzanmasına izin verir. Kaynak: SC Code 56-5-4030."},"19":{"q":"Standart bir geniş yük için tipik bir tek seferlik SCDOT oversize/overweight izni yaklaşık ne kadara mal olur?","options":["$10","$30","$75","$150"],"explanation":"SCDOT, standart bir tek seferlik OSOW izni için yaklaşık $30 ücret alır; yıllık (çok seferlik) izin ise yaklaşık $100'dür; 16 feet'in üzerindeki aşırı genişlikler için daha yüksek ücretler uygulanır. Kaynak: SCDOT Oversize/Overweight İzinleri ücret tarifesi."},"20":{"q":"South Carolina'da, 26,001 pounds veya daha fazla Brüt Kombinasyon Ağırlık Derecesine (GCWR) sahip ve çekilen ünitenin GVWR'sinin 10,000 pounds'un üzerinde olduğu araç kombinasyonlarını kullanmak için hangi CDL sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"South Carolina (SCDMV, Class A, B ve C), bir Class A CDL'i, çekilen aracın GVWR'sinin 10,000 lbs'tan fazla olması koşuluyla, GCWR'si 26,001 lbs veya daha fazla olan herhangi bir araç kombinasyonu olarak tanımlar. Kaynak: SCDMV Ticari Lisanslar, Class A, B ve C."},"21":{"q":"SCDMV'ye göre, GVWR'si 26,001 pounds veya daha fazla olan tek üniteli bir araç (10,000 lbs üzerinde hiçbir şey çekmeyen) hangi CDL sınıfını gerektirir?","options":["Class C","Class B","Class A","Class E"],"explanation":"South Carolina, bir Class B CDL'i, GVWR'si 26,001 lbs veya daha fazla olan tek üniteli herhangi bir araç ya da 10,000 lbs'tan ağır olmayan bir üniteyi çeken böyle bir araç olarak tanımlar. Kaynak: SCDMV Ticari Lisanslar, Class A, B ve C."},"22":{"q":"South Carolina kuralları kapsamında, Class A veya B ağırlık eşiklerini karşılamayan ancak (sürücü dahil) 16 veya daha fazla kişi taşımak için tasarlanmış bir araç hangi CDL sınıfını gerektirir?","options":["Class A","Class B","Class C","Hiçbir CDL gerekmez"],"explanation":"South Carolina, bir Class C CDL'i, Class A veya B olmayan ancak sürücü dahil 16 veya daha fazla kişi taşımak için tasarlanmış ya da plakartlı (placarded) tehlikeli madde taşımak için kullanılan herhangi bir tek araç veya kombinasyon olarak tanımlar. Kaynak: SCDMV Ticari Lisanslar, Class A, B ve C."},"23":{"q":"South Carolina'da, eyalet İÇİ (yalnızca eyalet sınırları içinde) sürüş için bir CDL almanın asgari yaşı nedir?","options":["16 yaşında","17 yaşında","18 yaşında","21 yaşında"],"explanation":"SCDMV, başvuru sahiplerinin South Carolina içinde (eyalet içi) ticari araç kullanabilmesi için en az 18 yaşında olmasını gerektirir. 21 yaşından küçük sürücüler eyalet dışında araç kullanamaz. Kaynak: SCDMV, İlk CDL'inizi Almak."},"24":{"q":"South Carolina'da, eyaletler ARASI (eyalet sınırlarını geçen) sürüş için geçerli bir CDL'e sahip olmanın asgari yaşı nedir?","options":["18 yaşında","19 yaşında","21 yaşında","25 yaşında"],"explanation":"SCDMV, sürücülerin South Carolina dışında (eyaletler arası) ticari araç kullanabilmesi için en az 21 yaşında olmasını gerektirir. 18-20 yaş arası sürücüler yalnızca eyalet içi işletmeyle sınırlıdır. Kaynak: SCDMV, İlk CDL'inizi Almak."},"25":{"q":"Bir South Carolina başvuru sahibi CDL beceri (yol) testine girebilmeden önce, Ticari Öğrenme İznini (CLP) ne kadar süre elinde tutması gerekir?","options":["En az 7 takvim günü","En az 14 takvim günü","En az 30 takvim günü","En az 60 takvim günü"],"explanation":"South Carolina, başvuru sahibinin CDL beceri testine girebilmesi için CLP'nin en az 14 takvim günü elde tutulmasını gerektiren federal kuralı izler. Kaynak: SCDMV, İlk CDL'inizi Almak (49 CFR 383.25)."},"26":{"q":"South Carolina, plakartlı (placarded) tehlikeli madde taşıyan bir aracı kullanma yetkisi için hangi onay (endorsement) kodunu kullanır?","options":["N","T","H","P"],"explanation":"H onayı, plakart gerektiren tehlikeli maddeleri kapsar. South Carolina standart federal onay kodlarını kullanır: H (HazMat), N (Tank), T (Doubles/Triples), P (Passenger), S (School Bus). Kaynak: SCDMV Ticari Lisanslar."},"27":{"q":"South Carolina'da, bir HazMat (H) onayı verilebilmeden veya yenilenebilmeden önce, başvuru sahibinin hangi ek taramayı geçmesi gerekir?","options":["Bir TSA güvenlik tehdidi değerlendirmesi (geçmiş kontrolü ve parmak izi alınması)","Bir fiziksel çeviklik ve kaldırma testi","Bir defansif sürüş kursu sertifikası","SCDMV tarafından uygulanan bir görme muayenesi"],"explanation":"South Carolina, hem ilk hem de yenileme onayları için HazMat (H) başvuru sahiplerinin parmak izi alınmasını ve geçmiş kontrolünü içeren bir federal Ulaştırma Güvenliği İdaresi (TSA) güvenlik tehdidi değerlendirmesini geçmesini gerektirir. Kaynak: SCDMV; 49 CFR 1572."},"28":{"q":"South Carolina'da, sıvıları veya gazları toplu bir tankta taşımak için tasarlanmış bir ticari aracı kullanmak için hangi onay gereklidir?","options":["P (Passenger)","N (Tank Vehicle)","T (Doubles/Triples)","S (School Bus)"],"explanation":"N (Tank Vehicle) onayı, federal tanımı karşılayan toplu tanklarda sıvı veya gaz taşıyan bir aracı kullanmak için gereklidir. Kaynak: SCDMV Ticari Lisanslar; 49 CFR 383.93."},"29":{"q":"South Carolina'da, çift veya üç römork çekmek için hangi onay gereklidir?","options":["T onayı","N onayı","H onayı","X onayı"],"explanation":"T onayı, çift ve üç römorkun kullanımına yetki verir. South Carolina standart federal kodları kullanır. Kaynak: SCDMV Ticari Lisanslar; 49 CFR 383.93."},"30":{"q":"Bir South Carolina sürücüsünün, gerekli eşik sayıda yolcu taşımak için tasarlanmış bir ticari otobüs veya minibüsü kullanabilmesi için hangi onayı alması gerekir?","options":["S (School Bus)","P (Passenger)","N (Tank)","T (Doubles/Triples)"],"explanation":"P (Passenger) onayı, sürücü dahil 16 veya daha fazla kişi taşımak için tasarlanmış bir aracı kullanmak için gereklidir. Okul otobüsleri için ayrı bir S onayı gerekir. Kaynak: SCDMV Ticari Lisanslar."},"31":{"q":"South Carolina'da, bir sürücünün CDL gerektiren bir okul otobüsünü kullanabilmesi için neye ihtiyacı vardır?","options":["Yalnızca P (Passenger) onayı","Hem P (Passenger) hem de S (School Bus) onayları","Yalnızca H (HazMat) onayı","Onay gerekmez, sadece bir Class B CDL"],"explanation":"South Carolina'da bir okul otobüsü kullanmak için, sürücünün hem P (Passenger) hem de S (School Bus) onaylarını taşıması ve okul otobüsü bilgi ve beceri testlerini geçmesi gerekir. Kaynak: SCDMV Ticari Lisanslar; 49 CFR 383.93."},"32":{"q":"İznini 7 Şubat 2022 tarihinde veya sonrasında alan bir South Carolina CLP/CDL başvuru sahibi için, ilk CDL için beceri testinden önce hangi eğitimin tamamlanması gerekir?","options":["Yalnızca eyalete özgü bir SCDMV sınıf kursu","Kayıtlı bir sağlayıcıdan FMCSA onaylı İlk Düzey Sürücü Eğitimi (ELDT)","SCDMV'ye kaydedilen 160 saatlik bir çıraklık","Hiçbir eğitim gerekmez, yalnızca beceri testi"],"explanation":"South Carolina, 7 Şubat 2022 tarihinde veya sonrasında bir CLP alan başvuru sahiplerinin beceri testine girmeden önce FMCSA Eğitim Sağlayıcı Kayıt Sicili'nde listelenen bir sağlayıcıdan FMCSA onaylı İlk Düzey Sürücü Eğitimi'ni (ELDT) tamamlamasını gerektirir. Kaynak: SCDMV, İlk CDL'inizi Almak; FMCSA ELDT kuralı."},"33":{"q":"South Carolina'da uygulanan federal ELDT kuralı kapsamında, ELDT bir ilk CDL için ve hangi onay grubu için gereklidir?","options":["H (HazMat), P (Passenger) ve S (School Bus)","N (Tank), T (Doubles/Triples) ve H (HazMat)","P (Passenger), N (Tank) ve T (Doubles/Triples)","Beş onayın tamamı (H, N, T, P, S)"],"explanation":"ELDT; ilk bir Class A veya B CDL, bir yükseltme ve HazMat (H), Passenger (P) ve School Bus (S) onayları için gereklidir. N (Tank) veya T (Doubles/Triples) onayları için gerekli değildir. Kaynak: FMCSA ELDT kuralı; SCDMV."},"34":{"q":"Bir South Carolina CDL başvuru sahibi, faaliyet gösterdiği ticaret türünü beyan ederken kaç tıbbi öz-sertifikasyon kategorisi arasından seçim yapmalıdır?","options":["İki","Üç","Dört","Beş"],"explanation":"South Carolina tarafından benimsenen federal kurallar, CDL sahiplerinin dört kategoriden birine öz-sertifikasyon yapmasını gerektirir: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate veya Excepted Intrastate. Kaynak: SCDMV; 49 CFR 383.71."},"35":{"q":"Eyalet sınırlarını aşarak yük taşıyan ve federal DOT fiziksel standartlarını karşılaması gereken bir South Carolina CDL sürücüsü hangi kategoride öz-sertifikasyon yapmalıdır?","options":["Excepted Interstate","Non-Excepted Interstate","Non-Excepted Intrastate","Excepted Intrastate"],"explanation":"Eyaletler arası ticarette faaliyet gösteren ve federal fiziksel yeterlilik standartlarına (49 CFR Part 391) tabi olup bunları karşılaması gereken bir sürücü, Non-Excepted Interstate olarak sertifikasyon yapar ve geçerli bir tıbbi muayene sertifikası bulundurmalıdır. Kaynak: SCDMV; 49 CFR 383.71."},"36":{"q":"SCDMV'nin ilk kez CDL başvurusu yapan bir kişiden kimlik, Sosyal Güvenlik, ikamet ve yasal varlık doğrulaması için sağlamasını istediği belgeler arasında hangisi YOKTUR?","options":["Kimlik ve doğum tarihi kanıtı","Sosyal Güvenlik numarası kanıtı","İki adet South Carolina ikamet kanıtı","Bir nakliye şirketinden imzalı bir istihdam mektubu"],"explanation":"SCDMV, kimlik/yasal varlık kanıtı, bir Sosyal Güvenlik numarası ve South Carolina ikametini (belge kontrol listesine göre, örn. Form MV-93) gerektirir. Bir işveren mektubu, gerekli bir kimlik/ikamet belgesi değildir. Kaynak: SCDMV, İlk CDL'inizi Almak belge kontrol listesi."},"37":{"q":"South Carolina'da, hangi başvuru sahipleri bir CDL HazMat (H) onayı için başvurmaya uygundur?","options":["Vatandaşlık durumuna bakılmaksızın herhangi bir CDL sahibi","Yalnızca ABD vatandaşları ve yasal daimi ikametgah sahipleri","Yalnızca 25 yaş ve üzeri sürücüler","Yalnızca X birleşik onayını halihazırda taşıyan sürücüler"],"explanation":"TSA güvenlik tehdidi değerlendirmesi nedeniyle, South Carolina'da yalnızca ABD vatandaşları ve yasal daimi ikametgah sahipleri bir CDL HazMat (H) onayı için uygundur. Kaynak: SCDMV; TSA HME programı (49 CFR 1572)."},"38":{"q":"Bir South Carolina sürücüsü, yalnızca bir Ticari Öğrenme İzni (CLP) taşırken hangi onayları alabilir?","options":["Yalnızca H (HazMat) ve T (Doubles/Triples)","Yalnızca N (Tank), P (Passenger) ve S (School Bus)","Beş onayın tamamı","Hiçbiri - CLP üzerinde hiçbir onaya izin verilmez"],"explanation":"Bir South Carolina CLP'si yalnızca N (Tank, boş tanklarla sınırlı), P (Passenger, eğitmenler/sınav görevlileri dışında yolcu yok) ve S (School Bus) onaylarını taşıyabilir. H ve T onayları bir CLP üzerinde bulunamaz. Kaynak: SCDMV, İlk CDL'inizi Almak; 49 CFR 383.25."},"39":{"q":"South Carolina'da, bir CDL üzerindeki birleşik 'X' onayı neyi ifade eder?","options":["Hem Tank (N) hem de HazMat (H) işlemleri için yetki","Doubles/Triples (T) ve Passenger (P) için yetki","Eyaletler arası sürüşü yasaklayan bir kısıtlama","Bir okul otobüsü operatörü sertifikası"],"explanation":"X onayı, sürücünün hem Tank (N) hem de HazMat (H) onaylarını taşıdığını gösteren birleşik bir koddur ve bir tank aracında tehlikeli madde taşınmasına izin verir. Kaynak: SCDMV Ticari Lisanslar; 49 CFR 383.153."},"40":{"q":"South Carolina'da, bir ticari motorlu aracı (CMV) kullanmanın yasal olduğu maksimum kandaki alkol konsantrasyonu (BAC) nedir?","options":["0.04% altında","0.08% altında","0.02% altında","0.05% altında"],"explanation":"South Carolina federal CMV standardını izler: BAC'niz 0.04% veya daha fazla ise bir CMV kullanmak yasa dışıdır, dolayısıyla yasal kullanım 0.04% altında bir BAC gerektirir. Kaynak: SCDMV Ticari Sürücü Belgesi El Kitabı, Bölüm 1.3.2 (49 CFR 383.51)."},"41":{"q":"South Carolina'nın CMV operatörleri için zımni rıza (implied-consent) kuralı kapsamında, bir sürücüde 0.04% altında saptanabilir miktarda alkol bulunursa ne olur?","options":["24 saat boyunca hizmet dışı (out-of-service) bırakılır","60 gün boyunca diskalifiye edilir","Bir yıl boyunca diskalifiye edilir","Hiçbir işlem yapılmadan yalnızca uyarı verilir"],"explanation":"South Carolina, 0.04% altında herhangi bir saptanabilir miktarda alkol bulunması halinde bir CMV sürücüsünü 24 saat boyunca hizmet dışı bırakır. 0.04% veya daha yüksek bir BAC ise bunun yerine bir diskalifikasyonu tetikler. Kaynak: SCDMV CDL El Kitabı, Bölüm 1.3.2."},"42":{"q":"South Carolina'da bir CMV kullanarak, bir sürücü kimyasal test konusunda otomatik olarak neyi yapmış sayılır?","options":["Alkol testine rıza göstermiş","Bir duruşma hakkından feragat etmiş","Yıllık uyuşturucu taramasını kabul etmiş","Bir araç aramasına rıza göstermiş"],"explanation":"Zımni rıza kapsamında, South Carolina'da bir CMV kullanan herkes alkol testine rıza göstermiş sayılır. Kaynak: SCDMV CDL El Kitabı, Bölüm 1.3.2."},"43":{"q":"South Carolina'da bir CMV sürücüsünün, DUI veya bir CMV'yi 0.04% ya da daha yüksek BAC ile kullanma gibi ilk büyük ihlali için asgari diskalifikasyon süresi nedir?","options":["1 yıl","60 gün","6 ay","3 yıl"],"explanation":"İlk büyük ihlal (DUI, bir CMV'de 0.04%+ BAC, test reddi, kaza yerini terk etme vb.) South Carolina'da en az bir yıllık asgari bir diskalifikasyon taşır. Kaynak: SCDMV CDL El Kitabı, Bölüm 1.3.2 (49 CFR 383.51)."},"44":{"q":"South Carolina'da, bir büyük ihlal (örneğin bir DUI) sürücü tehlikeli madde için plakartlı bir CMV kullanırken meydana gelirse, asgari diskalifikasyon süresi nedir?","options":["3 yıl","1 yıl","5 yıl","18 ay"],"explanation":"South Carolina, büyük ihlal tehlikeli madde için plakartlı bir CMV kullanılırken meydana geldiğinde ilk ihlal diskalifikasyonunu en az üç yıla çıkarır. Kaynak: SCDMV CDL El Kitabı, Bölüm 1.3.2 (49 CFR 383.51)."},"45":{"q":"South Carolina'da bir CMV sürücüsünün ikinci büyük ihlali için diskalifikasyon süresi nedir?","options":["Ömür boyu","10 yıl","5 yıl","3 yıl"],"explanation":"İkinci bir büyük ihlal, South Carolina'da CDL'in ömür boyu kaybedilmesiyle sonuçlanır. Kaynak: SCDMV CDL El Kitabı, Bölüm 1.3.2 (49 CFR 383.51)."},"46":{"q":"South Carolina'da, bir CMV operatörü olarak kandaki alkol testini reddetmek, diskalifikasyon açısından hangi tür ihlal olarak değerlendirilir?","options":["Bir büyük ihlal (en az 1 yıl)","Bir ciddi trafik ihlali (60 gün)","Bir hizmet dışı (out-of-service) ihlali (90 gün)","Diskalifikasyon olmayan küçük bir ihlal"],"explanation":"Kandaki alkol testini reddetmek South Carolina'da bir büyük ihlal olarak listelenir ve ilk ihlal için bir DUI ile aynı şekilde asgari bir yıllık diskalifikasyon taşır. Kaynak: SCDMV CDL El Kitabı, Bölüm 1.3.2."},"47":{"q":"South Carolina kuralları kapsamında, bir CMV sürücüsü, bir CMV hangi tür suçu işlemek için kullanılırsa ilk ihlalde CDL'ini ömür boyu kaybeder?","options":["Kontrollü maddeler içeren bir ağır suç (felony)","Her türden herhangi bir ağır suç","Hırsızlık içeren bir ağır suç","Yaralanmaya neden olan dikkatsiz sürüş"],"explanation":"Kontrollü maddeler içeren bir ağır suç işlemek için bir CMV kullanmak, ilk ihlalde ömür boyu diskalifikasyonla sonuçlanır ve diğer ömür boyu vakalarda mevcut olan 10 yıllık yeniden işe alma (reinstatement) imkanı yoktur. Kaynak: SCDMV CDL El Kitabı, Bölüm 1.3.2."},"48":{"q":"South Carolina'da, ihlalin 'aşırı hız' türünde bir ciddi trafik ihlali sayılması için bir CMV sürücüsünün belirtilen hız sınırının ne kadar üzerinde gitmesi gerekir?","options":["Sınırın 15 mph veya daha fazla üzerinde","Sınırın 10 mph veya daha fazla üzerinde","Sınırın 20 mph veya daha fazla üzerinde","Sınırın 5 mph veya daha fazla üzerinde"],"explanation":"South Carolina, aşırı hızı, sürücünün belirtilen hız sınırının 15 mph veya daha fazla üzerinde olması halinde bir ciddi trafik ihlali olarak tanımlar. Kaynak: SCDMV CDL El Kitabı, Bölüm 1.3.3."},"49":{"q":"Aşağıdakilerden hangisi South Carolina'da bir CMV sürücüsü için ciddi trafik ihlali olarak sınıflandırılır?","options":["Hatalı veya düzensiz şerit değiştirme","0.04% veya daha yüksek BAC ile araç kullanma","Bir kimyasal testi reddetme","Bir hizmet dışı (out-of-service) emrini ihlal etme"],"explanation":"Ciddi trafik ihlalleri; aşırı hız (15+ mph üzeri), dikkatsiz sürüş, hatalı veya düzensiz şerit değiştirme, çok yakından takip ve belirli CDL bulundurma ihlallerini içerir. Diğer seçenekler büyük veya hizmet dışı ihlallerdir. Kaynak: SCDMV CDL El Kitabı, Bölüm 1.3.3."},"50":{"q":"South Carolina'da, üç yıllık bir süre içinde bir CMV'de iki ciddi trafik ihlali işlemenin asgari diskalifikasyonu nedir?","options":["60 gün","30 gün","120 gün","90 gün"],"explanation":"Bir CMV ile ilgili üç yıl içinde iki ciddi trafik ihlali, en az 60 günlük bir diskalifikasyonla sonuçlanır. Kaynak: SCDMV CDL El Kitabı, Bölüm 1.3.3 (49 CFR 383.51)."},"51":{"q":"South Carolina'da, üç yıllık bir süre içinde bir CMV'de üç veya daha fazla ciddi trafik ihlalinin asgari diskalifikasyonu nedir?","options":["120 gün","60 gün","180 gün","1 yıl"],"explanation":"Bir CMV ile ilgili üç yıl içinde üç veya daha fazla ciddi trafik ihlali, en az 120 günlük bir diskalifikasyonla sonuçlanır. Kaynak: SCDMV CDL El Kitabı, Bölüm 1.3.3 (49 CFR 383.51)."},"52":{"q":"South Carolina'da bir sürücünün bir hizmet dışı (out-of-service) emrini ilk ihlali için asgari diskalifikasyon nedir?","options":["90 gün","60 gün","180 gün","1 yıl"],"explanation":"Bir hizmet dışı emrinin ilk ihlali, South Carolina'da asgari 90 günlük bir diskalifikasyon taşır. Kaynak: SCDMV CDL El Kitabı, Bölüm 1.3.4 (49 CFR 383.51)."},"53":{"q":"South Carolina'da, on yıllık bir süre içinde bir hizmet dışı (out-of-service) emrinin ikinci ihlali için asgari diskalifikasyon nedir?","options":["1 yıl","90 gün","120 gün","3 yıl"],"explanation":"On yıllık bir süre içinde ikinci bir hizmet dışı emri ihlali, en az bir yıllık bir diskalifikasyonla sonuçlanır. Kaynak: SCDMV CDL El Kitabı, Bölüm 1.3.4."},"54":{"q":"South Carolina'da, on yıllık bir süre içinde üç veya daha fazla hizmet dışı (out-of-service) emri ihlali için asgari diskalifikasyon nedir?","options":["3 yıl","1 yıl","5 yıl","Ömür boyu"],"explanation":"On yıllık bir süre içinde üç veya daha fazla hizmet dışı emri ihlali, en az üç yıllık bir diskalifikasyonla sonuçlanır. Kaynak: SCDMV CDL El Kitabı, Bölüm 1.3.4."},"55":{"q":"South Carolina'da bir CMV sürücüsünün ilk demiryolu-karayolu hemzemin geçit ihlali için asgari diskalifikasyon nedir?","options":["60 gün","90 gün","30 gün","120 gün"],"explanation":"İlk bir demiryolu-karayolu hemzemin geçit ihlali, South Carolina'da en az 60 günlük bir diskalifikasyonla sonuçlanır. Kaynak: SCDMV CDL El Kitabı, Bölüm 1.3.5 (49 CFR 383.51)."},"56":{"q":"South Carolina'da, üç yıllık bir süre içinde ikinci bir demiryolu-karayolu hemzemin geçit ihlali için asgari diskalifikasyon nedir?","options":["120 gün","60 gün","90 gün","1 yıl"],"explanation":"Üç yıl içinde ikinci bir demiryolu-karayolu hemzemin geçit ihlali, en az 120 günlük bir diskalifikasyonla sonuçlanır. Kaynak: SCDMV CDL El Kitabı, Bölüm 1.3.5."},"57":{"q":"South Carolina'da, üç yıllık bir süre içinde üçüncü bir demiryolu-karayolu hemzemin geçit ihlali için asgari diskalifikasyon nedir?","options":["1 yıl","120 gün","180 gün","3 yıl"],"explanation":"Üç yıl içinde üçüncü bir demiryolu-karayolu hemzemin geçit ihlali, en az bir yıllık bir diskalifikasyonla sonuçlanır. Kaynak: SCDMV CDL El Kitabı, Bölüm 1.3.5."},"58":{"q":"South Carolina kuralları kapsamında, bir CMV kullanırken mesajlaşma nedeniyle üç yıl içinde ikinci mahkumiyetten sonra bir CMV sürücüsünün CDL'i ne kadar süreyle diskalifiye edilir?","options":["60 gün","30 gün","120 gün","1 yıl"],"explanation":"Bir CMV kullanırken mesajlaşma nedeniyle iki veya daha fazla mahkumiyet diskalifikasyonu tetikler: üç yıl içinde ikinci ihlal için 60 gün ve üç yıl içinde üç veya daha fazlası için 120 gün. Sürücüler ayrıca $2,750'ye kadar idari para cezalarıyla karşılaşır. Kaynak: SCDMV CDL El Kitabı, Bölüm 2.9.6 ve 2.9.5."},"59":{"q":"South Carolina'nın Hands-Free and Distracted Driving Act yasası kapsamında, araç kullanırken mobil cihaz tutmanın ilk ihlali için para cezası nedir?","options":["$100 artı mahkeme masrafları","$25 artı mahkeme masrafları","$200 artı mahkeme masrafları","$500 artı mahkeme masrafları"],"explanation":"South Carolina'nın Hands-Free and Distracted Driving Act yasası (S.C. Code Section 56-5-3890), ilk ihlal için $100 para cezası artı mahkeme masrafları ve üç yıl içinde ikinci ihlal için $200 artı iki ceza puanı belirler; CMV sürücüleri için üç yıl içinde iki mahkumiyet ayrıca 60 günlük bir diskalifikasyon getirir. Kaynak: SCDPS Hands Free SC; S.C. Code 56-5-3890."},"60":{"q":"Güney Carolina'da bir eyaletler arası karayolunda (interstate), daha düşük bir hız sınırı belirtilmemişse ticari bir kamyon için azami hız sınırı nedir?","options":["65 mph, çünkü kamyonların hız sınırı arabalardan daha düşüktür","70 mph, diğer araçlarla aynı","Eyaletler arası karayolunun tüm bölümlerinde 60 mph","26,001 lbs üzerindeki herhangi bir araç için 55 mph"],"explanation":"Güney Carolina, kamyonlar için ayrı, daha düşük bir hız sınırı belirlememektedir. S.C. Code 56-5-1520 uyarınca, eyaletler arası karayolu sisteminde azami hız 70 mph'dir ve büyük kamyonlar aynı belirtilen sınıra tabidir. Kaynak: S.C. Code 56-5-1520; SCDMV CDL Kılavuzu."},"61":{"q":"Güney Carolina yasalarına göre, aksi belirtilmedikçe çok şeritli bölünmüş bir ana karayolunda (eyaletler arası karayolu olmayan) azami hız sınırı nedir?","options":["55 mph","65 mph","60 mph","70 mph"],"explanation":"S.C. Code 56-5-1520, çok şeritli bölünmüş ana karayollarında azami hızı 60 mph, eyaletler arası karayolu sisteminde 70 mph ve diğer (bölünmemiş) karayollarında 55 mph olarak belirler. Kaynak: S.C. Code 56-5-1520."},"62":{"q":"Güney Carolina'nın 'Şerit Değiştir' (Move Over) yasası (S.C. Code 56-5-1538), yanıp sönen ışıklar gösteren durmuş bir acil durum aracına yaklaşan bir sürücünün, güvenli bir şekilde yapılabiliyorsa ÖNCELİKLE ne yapmasını gerektirir?","options":["Acil durum aracı ayrılana kadar tamamen durmak","Bitişik olmayan bir şeride geçerek acil durum aracına en yakın şeridi boşaltmak","Korna çalmak ve belirtilen hızda devam etmek","Acil durum aracının arkasında banketin üzerine çekmek"],"explanation":"S.C. Code 56-5-1538 uyarınca, sürücü güvenli olduğunda, durmuş yetkili acil durum aracına (ambulans, polis, itfaiye, kurtarma, çekme veya kurtarma aracı) bitişik olmayan bir şeride geçerek yol vermelidir. Kaynak: S.C. Code 56-5-1538; SCDPS."},"63":{"q":"Güney Carolina'nın Move Over yasasına göre, durmuş bir acil durum aracından uzaklaşacak şekilde şerit değiştirmek mümkün değilse veya güvenli değilse bir sürücü ne yapmalıdır?","options":["Mevcut şeritte tamamen durmak","Belirtilen hızı korumak ancak dörtlü flaşörleri açmak","Dikkatle ilerlemek ve hızı önemli ölçüde azaltmak","En yakın rampadan çıkmak ve alternatif bir güzergah kullanmak"],"explanation":"S.C. Code 56-5-1538, güvenli bir şekilde şerit değiştiremeyen bir sürücünün gereken dikkatle ilerlemesini ve aracın hızını önemli ölçüde azaltarak yol koşulları için güvenli bir hızı korumasını gerektirir. Kaynak: S.C. Code 56-5-1538; SCDPS."},"64":{"q":"Güney Carolina'da plakalı (placarded) bir araç bir demiryolu geçidinde durduğunda, en yakın raya göre nerede durmalıdır?","options":["En yakın raydan 15 ila 50 feet arasında","En yakın raydan 10 ila 25 feet arasında","En yakın raydan 50 ila 100 feet arasında","En yakın raydan 15 feet içinde"],"explanation":"SCDMV CDL Kılavuzu ve S.C. Code 56-5-2720, plakalı bir aracın en yakın raydan 50 feet'ten daha yakın olmamak ve 15 feet'ten az olmamak kaydıyla durmasını gerektirir. Kaynak: SCDMV CDL Kılavuzu 9.6.12; S.C. Code 56-5-2720."},"65":{"q":"Aşağıdaki araçlardan hangisi Güney Carolina'da her demiryolu geçidinde her zaman durmak zorundadır (geçit muaf olmadıkça)?","options":["Yüklü bir damperli kamyon","Yolcu taşıyan bir otobüs","Boş bir düz platform (flatbed) römork","Bir hizmet römorku çeken bir pikap"],"explanation":"Yolcu taşıyan bir otobüs, bir okul otobüsü ve plakalı/tehlikeli yük taşıyan herhangi bir araç, her demiryolu geçidinde durmalı (en yakın raydan 15 ila 50 feet) ve bakıp dinlemelidir. Kaynak: SCDMV CDL Kılavuzu; S.C. Code 56-5-2720."},"66":{"q":"Güney Carolina'da ticari aracınızın herhangi bir kısmı demiryolu raylarını geçerken, CDL Kılavuzu aşağıdakilerden hangisini YAPMAMANIZI talimat verir?","options":["Ellerinizi direksiyonda tutmak","Ray boyunca her iki yöne bakmak","Vites değiştirmek","İkinci bir tren için dikkatli olmak"],"explanation":"SCDMV CDL Kılavuzu şunu belirtir: aracınızın herhangi bir kısmı rayları geçerken durmayın, vites değiştirmeyin veya şerit değiştirmeyin. Vites değiştirmeden rayları temizlemenize izin verecek bir vites seçin. Kaynak: SCDMV CDL Kılavuzu 2.15.4 / 13.1.8."},"67":{"q":"Güney Carolina'da, yanıp sönen kırmızı ışıklar gösteren durmuş bir okul otobüsüyle karşı yönde ilerleyen bir sürücünün hangi tür yolda durması GEREKMEZ?","options":["Orta dönüş şeridi olan herhangi bir iki şeritli yol","Çok şeritli bir karayolu","Belirtilen sınırı 45 mph üzerinde olan herhangi bir yol","Boyalı (kabartmasız) bir orta refüj şeridi olan bir yol"],"explanation":"S.C. Code 56-5-2770 uyarınca, çok şeritli bir karayolunda karşı yönde ilerlerken durmuş bir okul otobüsüyle karşılaşan bir sürücünün durması gerekmez. Aynı yöndeki sürücüler ve iki şeritli yollardaki sürücüler yine de durmak zorundadır. Kaynak: S.C. Code 56-5-2770."},"68":{"q":"Yanıp sönen kırmızı ışıklarını ve dur kolunu (stop arm) etkinleştirmiş bir Güney Carolina okul otobüsünün arkasında AYNI yönde ilerleyen bir sürücü ne yapmalıdır?","options":["15 mph'ye yavaşlamak ve dikkatle geçmek","Durmak ve otobüs hareket edene veya kırmızı ışıklar yanıp sönmeyi durdurana kadar durmaya devam etmek","Hiçbir çocuk görünmüyorsa yalnızca soldan geçmek","Yalnızca otobüs bölünmemiş iki şeritli bir yoldaysa durmak"],"explanation":"S.C. Code 56-5-2770, her iki yönden yaklaşan bir aracın (karşı yöndeki çok şeritli istisna dışında) yanıp sönen kırmızı ışıkları olan bir okul otobüsüne ulaşmadan önce durmasını ve otobüs hareketine devam edene veya kırmızı ışıklar artık etkin olmayana kadar ilerlememesini gerektirir. Kaynak: S.C. Code 56-5-2770."},"69":{"q":"Güney Carolina'da bir CMV her iki yönde trafik taşıyan iki şeritli bir yolda durduğunda, üç uyarı üçgeni nereye yerleştirilmelidir?","options":["Üçü de aracın arkasının 10 feet içinde","Aracın 10 feet içinde, ayrıca 100 feet arkada ve 100 feet önde","Aracın 10 feet, 200 feet ve 500 feet arkasında","Biri araçta ve ikisi 50 feet arkada yan yana"],"explanation":"İki yönlü/bölünmemiş bir yolda SCDMV CDL Kılavuzu, bir üçgeni ön veya arkanın 10 feet içine, bir üçgeni aracın 100 feet arkasına ve bir üçgeni 100 feet önüne yerleştirmeyi yönlendirir. Kaynak: SCDMV CDL Kılavuzu 2.5 (Uyarı Cihazları)."},"70":{"q":"Güney Carolina'da bir CMV tek yönlü veya bölünmüş bir karayolunda durduğunda, uyarı cihazları yaklaşan trafiğe doğru hangi mesafelerde yerleştirilmelidir?","options":["10 feet, 100 feet ve 200 feet","10 feet, 50 feet ve 100 feet","25 feet, 100 feet ve 300 feet","100 feet, 200 feet ve 300 feet"],"explanation":"Tek yönlü veya bölünmüş bir karayolunda SCDMV CDL Kılavuzu, üç yansıtıcı üçgeni yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet'e yerleştirmeyi yönlendirir. Kaynak: SCDMV CDL Kılavuzu 2.5."},"71":{"q":"Güney Carolina'da bir karayolunun banketinde durduktan sonra, bir CMV sürücüsü acil durum uyarı cihazlarını kaç dakika içinde yerleştirmelidir?","options":["5 dakika","10 dakika","15 dakika","30 dakika"],"explanation":"SCDMV CDL Kılavuzu, bir yolda veya bankette durmak zorundaysanız acil durum uyarı cihazlarınızı 10 dakika içinde yerleştirmeniz gerektiğini belirtir. Kaynak: SCDMV CDL Kılavuzu 2.5."},"72":{"q":"Güney Carolina'nın kontrollü erişimli karayolları için sol şerit ('Sağa Geç' - Move Right) yasası genellikle en sol şeridi hangi kullanımla sınırlar?","options":["Belirtilen sınırda veya üzerinde ilerleyen araçlar","Başka bir aracı sollamak ve geçmek","Yalnızca 10,000 lbs altındaki araçlar","Paylaşımlı araç (carpool) ve toplu taşıma araçları"],"explanation":"S.C. Code 56-5-1885 uyarınca, sürücüler kontrollü erişimli bir karayolunun en sol şeridini yalnızca sollarken ve geçerken kullanabilir. Kaynak: S.C. Code 56-5-1885; SCDPS Move Right Yasası."},"73":{"q":"Güney Carolina'nın sol şerit yasası, hangi durum nedeniyle sol şeritten güvenli bir şekilde çıkamayan bir ticari motorlu araca belirli bir muafiyet tanır?","options":["Yatakhane (sleeper berth) bölmesinde uyuyan bir yolcu","Bir karayolu eğimi veya sağdan geçen başka bir araç","Tehlikeli madde plakası taşımak","Düşük görüş ile gece çalışmak"],"explanation":"S.C. Code 56-5-1885 uyarınca, bir CMV sürücüsü, bir karayolu eğimi nedeniyle veya başka bir araç sağdan sollarken/geçerken güvenli bir şekilde sağa geçemediğinde sol şerit kısıtlamasından muaf tutulur. Kaynak: S.C. Code 56-5-1885; SCDPS."},"74":{"q":"Güney Carolina'da bir otobüs sürerken, HİÇBİR sinyal ışığı ve HİÇBİR trafik kontrol görevlisi OLMAYAN bir açılır köprüye (drawbridge) yaklaşıyorsunuz. Ne yapmalısınız?","options":["Durmadan azaltılmış hızda geçmek","Açılır bölümden en az 50 feet önce durmak ve tamamen kapalı olduğunu doğrulamak","Açılır bölümden 15 ila 50 feet önce durmak","Yalnızca uyarı zili çalıyorsa durmak"],"explanation":"SCDMV CDL Kılavuzu (4.3.6), otobüs sürücülerine sinyal ışığı veya görevli olmayan açılır köprülerde durmalarını, açılır bölümden en az 50 feet önce durmalarını ve geçmeden önce tamamen kapalı olduğunu doğrulamalarını yönlendirir. Kaynak: SCDMV CDL Kılavuzu 4.3.6."},"75":{"q":"Hangi ihlal listesi, en az 60 günlük ilk Güney Carolina CDL diskalifiyesini tetikler?","options":["Çok yakından takip etmek","Bir demiryolu-karayolu hemzemin geçit ihlali","Aşırı ağırlık aks cezası","Gerekli bir plakayı göstermemek"],"explanation":"SCDMV CDL Kılavuzu, bir CDL sahibinin ilk demiryolu-karayolu hemzemin geçit ihlali için CDL'yi en az 60 gün, üç yıl içinde ikincisi için 120 gün ve üçüncüsü için bir yıl kaybedeceğini belirtir. Kaynak: SCDMV CDL Kılavuzu 1.3.5; 49 CFR 383.51."},"76":{"q":"Güney Carolina'da, bir aşırı boyut izni (oversize permit) gerekmeden önce standart azami yasal araç/yük GENİŞLİĞİ nedir?","options":["8 feet 0 inch","8 feet 6 inch","9 feet 0 inch","10 feet 0 inch"],"explanation":"Güney Carolina'nın yasal genişlik sınırı 8 feet 6 inch'tir (102 inches); bundan daha geniş yükler bir SCDOT aşırı boyut izni gerektirir. Azami yasal yükseklik 13 feet 6 inches'tır. Kaynak: SCDOT Aşırı Boyut/Aşırı Ağırlık İzinleri."},"77":{"q":"İzin olmadan, Güney Carolina'da bir ticari araç ve yük için azami yasal YÜKSEKLİK nedir?","options":["13 feet 6 inches","14 feet 0 inches","12 feet 6 inches","13 feet 0 inches"],"explanation":"Güney Carolina'nın yasal azami yüksekliği 13 feet 6 inches'tır; daha yüksek herhangi bir şey, bir SCDOT aşırı yükseklik izni ve üst geçit açıklığı için güzergah incelemesi gerektirir. Kaynak: SCDOT Aşırı Boyut/Aşırı Ağırlık İzinleri."},"78":{"q":"SCDOT izin kurallarına göre, Güney Carolina'da aşırı boyutlu yüklerin genellikle hangi zamanlarda hareket etmesine izin verilir?","options":["Günde 24 saat, herhangi bir gün","Gün doğumundan yarım saat sonra ile gün batımından yarım saat önce arasında, Pazartesi'den Cumartesi'ye","Trafikten kaçınmak için yalnızca akşam 9 ile sabah 5 arasında","Yalnızca hafta içi, Cumartesi günü harekete izin verilmez"],"explanation":"SCDOT genellikle aşırı boyutlu yük hareketini gün doğumundan yarım saat sonra ile gün batımından yarım saat önce arasına, Pazartesi'den Cumartesi'ye sınırlar; Pazar veya belirlenmiş tatil günlerinde seyahat yoktur, ayrıca çok geniş yükler için ek kısıtlamalar vardır. Kaynak: SCDOT Aşırı Boyut/Aşırı Ağırlık İzinleri."},"79":{"q":"Durmuş bir Güney Carolina okul otobüsünü yasadışı şekilde geçen bir sürücü ile Move Over yasası kapsamında durmuş bir acil durum aracına yaklaşan bir araç, her ikisi de cezalara tabidir. Move Over yasası ihlali hakkında hangi ifade doğrudur?","options":["Mahkeme masrafı olmadan yalnızca 25 dolarlık bir hukuki para cezasıdır","300 ila 500 dolar aralığında para cezası taşıyan bir kabahattir (misdemeanor)","Otomatik ömür boyu CDL diskalifiyesi taşır","İlk yıl için yalnızca uyarı verilen bir suçtur"],"explanation":"Güney Carolina Move Over yasasının (S.C. Code 56-5-1538) ihlali, genellikle 300-500 dolar aralığında bir para cezasıyla cezalandırılabilen bir kabahattir; buna karşılık, sol şerit 'Sağa Geç' ihlali (56-5-1885) 25 dolarlık bir hukuki para cezasıdır. Kaynak: S.C. Code 56-5-1538; SCDPS."},"80":{"q":"Güney Carolina'da Ticari Sürücü Belgelerini (CDL'ler) hangi kurum verir?","options":["South Carolina Department of Motor Vehicles (SCDMV)","South Carolina Department of Transportation (SCDOT)","Federal Motor Carrier Safety Administration (FMCSA)","South Carolina Highway Patrol"],"explanation":"Güney Carolina CDL'leri, South Carolina Department of Motor Vehicles (SCDMV) tarafından verilir. FMCSA federal CDL standartlarını belirler ancak belgeyi vermez; SCDOT yolları/izinleri yönetir, ruhsatlandırmayı değil. Kaynak: SCDMV Commercial Licenses sayfası (dmv.sc.gov)."},"81":{"q":"Güney Carolina'da, bir Ticari Öğrenci İzni (CLP) veya CDL başvurusu yapmak için kullanılan standart form nedir?","options":["SCDMV Form 447-CDL","SCDMV Form DL-405A","SCDMV Form MV-93","FMCSA Form MCSA-5876"],"explanation":"Güney Carolina'da bir CLP ve CDL başvurusu SCDMV Form 447-CDL'dir. DL-405A tıbbi öz beyan formu, MV-93 kimlik belgesi kontrol listesi ve MCSA-5876 federal tıbbi muayene uzmanı sertifikasıdır. Kaynak: SCDMV Getting Your First CDL (dmv.sc.gov)."},"82":{"q":"Bir Güney Carolina Ticari Öğrenci İzni (CLP) süresi dolmadan önce ne kadar süre geçerlidir?","options":["Bir yıl","180 gün","Altı ay","İki yıl"],"explanation":"Güney Carolina'da CLP bir yıllık bir son kullanma tarihi taşır. Kaynak: SCDMV Getting Your First CDL (dmv.sc.gov). (Federal kural, Güney Carolina'nın uyguladığı, bir yıla kadar geçerli bir CLP'ye izin verir.)"},"83":{"q":"Güney Carolina'da bir Ticari Öğrenci İzni verildikten sonra, CDL beceri testine girmeye hak kazanmadan önce onu ne kadar süre elinizde tutmanız gerekir?","options":["En az 14 gün","En az 30 gün","En az 10 gün","En az 7 gün"],"explanation":"Beceri testine girebilmeniz için CLP'yi en az 14 gün elinizde tutmanız gerekir. Kaynak: SCDMV Getting Your First CDL (dmv.sc.gov); bu, federal 14 günlük CLP bekletme süresini yansıtır (49 CFR 383.25)."},"84":{"q":"Güney Carolina'nın CDL öz beyanı kapsamında, bir sürücünün kaç çalışma kategorisi arasından seçim yapması gerekir?","options":["Dört","İki","Üç","Beş"],"explanation":"Dört öz beyan kategorisi vardır: muaf olmayan eyaletler arası (non-excepted interstate), muaf eyaletler arası (excepted interstate), muaf olmayan eyalet içi (non-excepted intrastate) ve muaf eyalet içi (excepted intrastate). Sürücüler kategorilerini SCDMV'ye beyan eder. Kaynak: SCDMV / Form DL-405A (dmv.sc.gov)."},"85":{"q":"Ticaret türünüzü öz beyan etmek ve tıbbi sertifikasyon durumunu SCDMV'ye sunmak için hangi Güney Carolina formu kullanılır?","options":["Form DL-405A (CDL Sahibinin Tıbbi Sertifikasyonu)","Form 447-CDL (CDL Başvurusu)","Form MV-93 (Vatandaş Kontrol Listesi)","Form MCSA-5875 (Tıbbi Muayene Raporu)"],"explanation":"Güney Carolina, CDL sahibinin öz beyanı ve tıbbi sertifikasyonu için Form DL-405A kullanır. Form 447-CDL belge başvurusu, MV-93 kimlik kontrol listesi ve MCSA-5875 federal muayene raporudur. Kaynak: SCDMV Renew or Upgrade Your CDL (dmv.sc.gov)."},"86":{"q":"Hangi öz beyan kategorisi, bir Güney Carolina CDL sahibinin geçerli bir DOT tıbbi muayene uzmanı sertifikası sunmasını gerektirir?","options":["Muaf olmayan eyaletler arası (non-excepted interstate)","Muaf eyaletler arası (excepted interstate)","Muaf eyalet içi (excepted intrastate)","Hiçbir kategori tıbbi sertifika gerektirmez"],"explanation":"Muaf olmayan eyaletler arası sürücüler, FMCSA standartlarını karşılayan geçerli bir DOT tıbbi muayene uzmanı sertifikası bulundurmalıdır. Muaf kategorilerdeki sürücülerin sertifika sunması gerekmez. Kaynak: SCDMV / Form DL-405A (dmv.sc.gov); 49 CFR 391.41."},"87":{"q":"Muaf olmayan bir Güney Carolina CDL sürücüsünün bulundurması gereken tıbbi muayene uzmanı sertifikasını veren ve fiziksel muayeneyi yapma yetkisine kim sahiptir?","options":["FMCSA'nın National Registry of Certified Medical Examiners listesinde yer alan bir tıp uzmanı","Sürücünün seçtiği herhangi bir lisanslı hekim","Şube ofisindeki bir SCDMV muayene görevlisi","South Carolina Department of Transportation tarafından onaylanmış bir hekim"],"explanation":"Muayene, FMCSA'nın National Registry of Certified Medical Examiners listesinde yer alan bir tıp uzmanı tarafından yapılmalı ve sertifika onun tarafından verilmelidir. Kaynak: SCDMV Commercial Licenses (dmv.sc.gov); 49 CFR 390.103."},"88":{"q":"Güney Carolina'da CDL beceri testine girmeden önce, CLP'lerini 7 Şubat 2022'den sonra alan başvuru sahipleri için hangi gereklilik geçerlidir?","options":["FMCSA onaylı bir Giriş Seviyesi Sürücü Eğitimi (ELDT) programını tamamlamak","Beş ardışık yıl boyunca temiz bir sürüş siciline sahip olmak","SCDMV ile 160 saat direksiyon başında zaman tamamlamak","Ayrı bir SCDMV defansif sürüş kursunu geçmek"],"explanation":"CLP'si 7 Şubat 2022'den sonra verilen başvuru sahipleri, beceri testine girmeden önce kayıtlı bir eğitim sağlayıcısı ile FMCSA onaylı bir ELDT programını tamamlamalıdır. Kaynak: SCDMV Getting Your First CDL (dmv.sc.gov); 49 CFR Part 380 Subpart F."},"89":{"q":"Güney Carolina CDL beceri testi üç bölüme ayrılmıştır. Hangi grup bu üç bölümü doğru şekilde listeler?","options":["Yolculuk öncesi muayene (pre-trip inspection), temel araç kontrolü ve yol sürüşü","Yazılı bilgi, görüş taraması ve yol sürüşü","Yolculuk öncesi muayene, tehlikeli maddeler ve gece sürüşü","Hava freni kontrolü, paralel park ve otoyola katılma"],"explanation":"CDL beceri testinin üç bileşeni vardır: yolculuk öncesi muayene (pre-trip inspection), temel araç (yol dışı) kontrolü ve yol sürüş testi. Kaynak: SCDMV Getting Your First CDL (dmv.sc.gov); 49 CFR 383.113."},"90":{"q":"Bir Güney Carolina CDL'sinin yenilenmesi gerekmeden önceki standart geçerlilik süresi nedir?","options":["8 yıl","5 yıl","4 yıl","10 yıl"],"explanation":"Bir Güney Carolina CDL'si 8 yıl geçerlidir ve döngünün son yılında sahibinin doğum gününde sona erer. Kaynak: SCDMV (dmv.sc.gov). (Bir HazMat onayı, ayrı 5 yıllık TSA Security Threat Assessment döngüsüyle sınırlıdır.)"},"91":{"q":"Tehlikeli madde (HazMat) onayı olan bir Güney Carolina CDL'si hangi ayrı zaman dilimiyle sınırlıdır?","options":["5 yıllık TSA Security Threat Assessment döngüsü","2 yıllık yalnızca HazMat yenileme döngüsü","10 yıllık federal HazMat sertifikasyonu","1 yıllık SCDMV HazMat incelemesi"],"explanation":"CDL'nin kendisi 8 yıl geçerli olsa da, HazMat onayı 5 yıllık bir döngüde yenilenmesi gereken TSA Security Threat Assessment'a bağlıdır. Kaynak: SCDMV Commercial Licenses (dmv.sc.gov); 49 CFR 1572."},"92":{"q":"Bir Güney Carolina CDL sahibi, tıbbi yeterlilik kanıtını (öz beyan/tıbbi sertifika) SCDMV'ye ne zaman sunmalıdır?","options":["CDL için başvurdukları, yeniledikleri, yükselttikleri, adresini değiştirdikleri veya çoğalttıkları her seferinde","Yalnızca bir kez, CDL'yi ilk aldıklarında","Yalnızca 8 yıllık yenilemede","Yalnızca bir HazMat onayı eklerken"],"explanation":"Sürücüler, bir CLP/CDL için başvurdukları, yükselttikleri, yeniledikleri, adres değiştirdikleri veya bir kopya talep ettikleri her seferinde tıbbi yeterlilik kanıtı sunmalıdır. Kaynak: SCDMV Commercial Licenses (dmv.sc.gov)."},"93":{"q":"Güney Carolina'da yalnızca eyalet içinde (intrastate) bir ticari araç sürmek için CDL verilebilmesi için asgari yaş nedir?","options":["18 yaş","19 yaş","21 yaş","20 yaş"],"explanation":"Güney Carolina içinde eyalet içi sürüş için bir CDL'ye sahip olmak için en az 18 yaşında ve eyaletler arası sürüş için en az 21 yaşında olmanız gerekir. Kaynak: SCDMV Getting Your First CDL (dmv.sc.gov)."},"94":{"q":"Güney Carolina, eyaletler arası ticarette (eyalet sınırları boyunca) bir ticari motorlu araç kullanmak için hangi asgari yaşı şart koşar?","options":["21 yaş","18 yaş","19 yaş","25 yaş"],"explanation":"Bir sürücünün eyaletler arası ticarette bir CMV kullanması için en az 21 yaşında olması gerekir; 18-20 yaş arası eyalet içi çalışmayla sınırlıdır. Kaynak: SCDMV Getting Your First CDL (dmv.sc.gov); 49 CFR 391.11."},"95":{"q":"Muaf olmayan bir eyaletler arası sürücünün tıbbi muayene uzmanı sertifikası, SCDMV'ye sunulduktan sonra tipik olarak nasıl doğrulanır?","options":["Elektronik olarak doğrulanır/sürüş siciline işlenir","SCDMV şubesinde noter onayı yapılması gerekir","Manuel onay için FMCSA'ya postalanır","Yalnızca tıbbi muayene uzmanı tarafından doğrulanır, eyalet tarafından değil"],"explanation":"Muaf olmayan sürücüler için tıbbi sertifika bilgileri elektronik olarak doğrulanır ve tıbbi durum CDL sürüş siciline eklenir. Kaynak: SCDMV Commercial Licenses (dmv.sc.gov); 49 CFR 383.71/383.73."},"96":{"q":"Bir CDL veya CLP başvurusu yapmadan önce, Güney Carolina bir başvuru sahibinin halihazırda hangi belgeye sahip olmasını şart koşar?","options":["Geçerli, süresi dolmamış bir Güney Carolina sürücü belgesi","Geçerli bir pasaport","Bir federal TWIC kartı","Bir Güney Carolina işletme ruhsatı"],"explanation":"Başvuru sahipleri, bir CLP/CDL başvurusu yapmadan önce geçerli, süresi dolmamış bir Güney Carolina (normal) sürücü belgesine sahip olmalıdır. Kaynak: SCDMV Getting Your First CDL (dmv.sc.gov)."},"97":{"q":"Bir Güney Carolina CDL yenilemesinde, başvuru ve tıbbi/öz beyana ek olarak hangi belgenin sunulması gerekir?","options":["Güney Carolina'da lisanslı bir şirketten otomobil sorumluluk sigortası bilgisi","Noter onaylı bir işveren beyannamesi","Yeni bir ELDT kursunun tamamlandığına dair kanıt","Tüm onaylar için yeni bir TSA parmak izi kontrolü"],"explanation":"Güney Carolina, CDL yenilemesinde SC lisanslı bir sigortacıdan otomobil sorumluluk sigortası bilgisi ile birlikte uygun olduğunda Form 447-CDL ve Form DL-405A tıbbi sertifikasyonunu şart koşar. Kaynak: SCDMV Renew or Upgrade Your CDL (dmv.sc.gov)."},"98":{"q":"Bir Güney Carolina CDL sahibi, muaf olmayan olarak sertifikalandırılmışken federal olarak gerekli tıbbi muayene uzmanı sertifikasının süresinin dolmasına izin verirse, CDL için sonuç ne olur?","options":["Geçerli bir sertifika dosyaya girene kadar ticari ayrıcalıklar kaybedilecek şekilde CDL düşürülür (downgrade)","8 yıllık yenilemeye kadar hiçbir şey değişmez","CDL, yeniden yürürlüğe koyma yolu olmadan kalıcı olarak iptal edilir","Yalnızca HazMat onayı etkilenir"],"explanation":"Muaf olmayan bir sürücünün tıbbi sertifikası geçersiz olduğunda veya dosyada bulunmadığında, eyalet, güncel bir sertifika sunulana kadar CDL'yi düşürmelidir (ticari sürüş ayrıcalıklarını kaldırarak). Kaynak: SCDMV / FMCSA tıbbi sertifikasyon kuralları (dmv.sc.gov); 49 CFR 383.73."},"99":{"q":"Bir Güney Carolina CDL'sini yenilerken, tıbbi öz beyan (Form DL-405A) genellikle hangi durumda yeniden sunulmalıdır?","options":["Daha önce sunulmamışsa veya çalışılan ticaret türü değişmişse","Yalnızca sürücü başka bir eyalete taşınmışsa","Yalnızca sürücü 65 yaşın üzerindeyse","Asla, çünkü bir kerelik bir dosyalamadır"],"explanation":"Güney Carolina, daha önce sunulmamışsa veya sürücünün ticaret türü (öz beyan kategorisi) değişmişse, yenilemede DL-405A öz beyanını şart koşar. Kaynak: SCDMV Renew or Upgrade Your CDL (dmv.sc.gov)."}},"es":{"0":{"q":"En las carreteras de Carolina del Sur, ¿cuál es el ancho exterior total máximo de un vehículo o su carga, sin contar los dispositivos de seguridad aprobados?","options":["96 inches","102 inches","108 inches","120 inches"],"explanation":"El Código de Carolina del Sur 56-5-4030 establece el ancho exterior total máximo de un vehículo o carga en 102 inches (8 feet 6 inches), excluyendo los dispositivos de seguridad aprobados. Esto coincide con el estándar federal adoptado en todo el estado. Fuente: SC Code 56-5-4030 (Ancho de vehículos)."},"1":{"q":"¿Cuál es la altura máxima para la mayoría de los vehículos, vacíos o cargados, en las carreteras de Carolina del Sur?","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"explanation":"El Código de Carolina del Sur 56-5-4060 limita la altura de los vehículos a 13 feet 6 inches. Una excepción limitada permite 14 feet para una unidad transportadora de automóviles o una combinación de montaje tipo saddle-mount con un permiso de ruta válido del SCDOT. Fuente: SC Code 56-5-4060 (Altura de vehículos)."},"2":{"q":"¿Cuál es la longitud máxima para un solo vehículo motorizado (como un camión rígido) en Carolina del Sur, incluyendo los parachoques y la carga?","options":["35 feet","40 feet","45 feet","48 feet"],"explanation":"El Código de Carolina del Sur 56-5-4070 limita un solo vehículo motorizado a 40 feet de longitud total máxima, incluyendo los parachoques delantero y trasero y la carga. Los autobuses y ciertas casas rodantes se tratan por separado. Fuente: SC Code 56-5-4070 (Longitud de vehículos)."},"3":{"q":"En una combinación de dos unidades de tractocamión con semirremolque, ¿cuál es la longitud máxima del remolque o semirremolque (incluyendo la carga) en Carolina del Sur?","options":["48 feet","50 feet","53 feet","57 feet"],"explanation":"El Código de Carolina del Sur 56-5-4070 permite que un remolque o semirremolque en una combinación de tractocamión de dos unidades mida hasta 53 feet, incluyendo la carga. Un remolque de 53 feet debe tener una barra antiempotramiento trasera. Fuente: SC Code 56-5-4070."},"4":{"q":"En Carolina del Sur, ¿cuál es el peso bruto máximo que un solo eje puede imponer sobre la carretera?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"El Código de Carolina del Sur 56-5-4140 limita el peso bruto sobre cualquier eje individual a 20,000 pounds. Esto es igual al límite federal para un solo eje. Fuente: SC Code 56-5-4140 (Peso bruto de vehículos)."},"5":{"q":"¿Cuál es el peso bruto vehicular total máximo permitido en Carolina del Sur sin un permiso especial?","options":["73,280 pounds","76,000 pounds","80,000 pounds","88,000 pounds"],"explanation":"El Código de Carolina del Sur 56-5-4140 limita el peso bruto total a 80,000 pounds, salvo los vehículos a los que el SCDOT emita permisos especiales. Esto refleja el máximo federal para carreteras interestatales. Fuente: SC Code 56-5-4140."},"6":{"q":"En las carreteras interestatales de Carolina del Sur, ¿cuál es el peso bruto máximo permitido sobre un grupo de ejes en tándem (incluyendo la tolerancia de aplicación)?","options":["32,000 pounds","34,000 pounds","35,200 pounds","36,000 pounds"],"explanation":"En el sistema interestatal, Carolina del Sur permite un peso bruto de eje en tándem de 35,200 pounds, lo cual incluye la tolerancia de aplicación del estado por encima de la base federal de 34,000 pounds. Fuente: SC Code 56-5-4140; guía de tamaño y peso del SCDMV/SCDOT."},"7":{"q":"En las carreteras estatales (no interestatales) de Carolina del Sur, ¿cuál es el peso bruto máximo permitido sobre un grupo de ejes en tándem separados entre 40 y 96 inches?","options":["34,000 pounds","35,200 pounds","36,000 pounds","40,000 pounds"],"explanation":"El Código de Carolina del Sur 56-5-4140 permite hasta 36,000 pounds sobre un eje en tándem (dos o más ejes consecutivos separados entre 40 y 96 inches) en carreteras distintas a las interestatales. El límite en tándem en las interestatales es menor, de 35,200 pounds. Fuente: SC Code 56-5-4140."},"8":{"q":"¿Qué fórmula utiliza Carolina del Sur para determinar el peso bruto permitido sobre un grupo de ejes en función del espaciamiento entre ellos?","options":["La Fórmula Federal de Puentes (Fórmula B)","La fórmula de la Calificación de Peso Combinado Bruto (GCWR)","La fórmula de resistencia a la rodadura de Davis","La fórmula de tolerancia para eje individual"],"explanation":"Carolina del Sur aplica la Fórmula Federal de Puentes (Fórmula de Puentes B) para establecer el peso máximo sobre cualquier grupo de dos o más ejes consecutivos, según el espaciamiento de los ejes y el número de ejes, de conformidad con 23 U.S.C. 127. Fuente: SC Code 56-5-4140; Fórmula Federal de Puentes de la FHWA."},"9":{"q":"¿Qué agencia estatal de Carolina del Sur emite los permisos de sobredimensión/sobrepeso (OSOW) para vehículos y cargas que exceden los límites legales?","options":["El Departamento de Vehículos Motorizados de SC (SCDMV)","El Departamento de Seguridad Pública de SC (SCDPS)","El Departamento de Transporte de SC (SCDOT)","El Departamento de Ingresos de SC (SCDOR)"],"explanation":"La Oficina de Permisos de Sobredimensión/Sobrepeso del Departamento de Transporte de Carolina del Sur (SCDOT) emite los permisos OSOW a su discreción para cargas que exceden los límites legales de tamaño o peso. Fuente: programa de Permisos de Sobredimensión/Sobrepeso del SCDOT."},"10":{"q":"¿Cuándo se requiere generalmente un permiso de sobredimensión en Carolina del Sur por el ancho de una carga?","options":["Cuando el ancho excede 96 inches","Cuando el ancho excede 102 inches (8'6\")","Cuando el ancho excede 120 inches (10')","Cuando el ancho excede 144 inches (12')"],"explanation":"Debido a que el límite legal de ancho en Carolina del Sur es de 102 inches (8 feet 6 inches), cualquier carga más ancha que eso requiere un permiso de sobredimensión del SCDOT. Fuente: SC Code 56-5-4030; pautas de permisos OSOW del SCDOT."},"11":{"q":"¿Cómo puede un transportista solicitar un permiso de sobredimensión/sobrepeso de Carolina del Sur?","options":["Solo enviando un formulario en papel por correo al SCDMV","A través del sistema en línea SafeHaul del SCDOT (o por teléfono/correo/email)","Solo en persona en un tribunal del condado","A través del portal nacional de la FMCSA"],"explanation":"Los transportistas obtienen los permisos OSOW a través del sistema en línea SafeHaul (iHaul) del SCDOT, o contactando a la Oficina de Permisos OSOW del SCDOT por teléfono, correo o email. Fuente: página de Permisos de Sobredimensión/Sobrepeso del SCDOT (SafeHaul)."},"12":{"q":"Bajo la exención agrícola/forestal de Carolina del Sur, el equipo agrícola autopropulsado y la maquinaria forestal pueden circular sin un permiso de sobredimensión durante el día siempre que no excedan qué ancho?","options":["8 feet 6 inches","10 feet","12 feet","14 feet"],"explanation":"Carolina del Sur permite que el equipo agrícola, la maquinaria forestal y equipos similares circulen durante el día sin permiso si no exceden 12 feet de ancho, 13 feet 6 inches de alto, ni 90,000 pounds. Fuente: pautas OSOW del SCDOT (exención agrícola/forestal)."},"13":{"q":"En una carretera de dos carriles de Carolina del Sur, ¿a partir de qué ancho una carga con permiso comienza a requerir un vehículo escolta (piloto) delantero?","options":["Más de 10 feet","Más de 12 feet","Más de 14 feet","Más de 16 feet"],"explanation":"En carreteras de dos carriles, Carolina del Sur requiere un escolta delantero para cargas que excedan 12 feet y hasta 14 feet de ancho; las cargas de más de 14 feet y hasta 16 feet requieren escoltas delantero y trasero. Fuente: requisitos de escolta/vehículo piloto OSOW del SCDOT."},"14":{"q":"Para un semirremolque de 53 feet en Carolina del Sur, la distancia desde el pivote (kingpin) hasta el centro del eje trasero (o del conjunto de tándem trasero) no puede exceder qué valor?","options":["37 feet","41 feet","43 feet","46 feet"],"explanation":"El Código de Carolina del Sur 56-5-4070 exige que en un remolque de 53 feet la distancia del pivote al eje trasero (o al centro del tándem trasero) no sea mayor a 41 feet. Fuente: SC Code 56-5-4070."},"15":{"q":"¿Qué tolerancia de aplicación aplica generalmente Carolina del Sur a los límites de peso en carreteras no interestatales?","options":["5 por ciento","10 por ciento","15 por ciento","No se permite ninguna tolerancia"],"explanation":"Carolina del Sur aplica una tolerancia de aplicación del 10% a los límites de peso en carreteras no interestatales (estatales y suplementarias). Los pesos en las interestatales se aplican de forma más estricta dentro de las tolerancias establecidas. Fuente: guía de tamaño y peso del SCDOT/SCDMV; SC Code 56-5-4140."},"16":{"q":"Bajo la excepción de altura de 14 feet en Carolina del Sur, un transportador de automóviles o una combinación de montaje tipo saddle-mount debe contar adicionalmente con qué?","options":["Una exención de la FMCSA","Un permiso de ruta válido emitido por el SCDOT","Un endoso de materiales peligrosos","Aprobación por escrito del sheriff del condado"],"explanation":"El Código de Carolina del Sur 56-5-4060 permite hasta 14 feet para una unidad transportadora de automóviles o una combinación de montaje tipo saddle-mount solo si el propietario/operador posee un permiso de ruta válido emitido por el SCDOT. Fuente: SC Code 56-5-4060."},"17":{"q":"¿Cuál es la longitud máxima permitida para una casa rodante en Carolina del Sur, siempre que su radio de giro sea de 48 feet o menos?","options":["40 feet","42 feet","45 feet","48 feet"],"explanation":"El Código de Carolina del Sur 56-5-4070 permite una casa rodante de hasta 45 feet de longitud si su radio de giro es de 48 feet o menos, una excepción al límite general de 40 feet para un solo vehículo. Fuente: SC Code 56-5-4070."},"18":{"q":"Los accesorios en casas rodantes, remolques de viaje y campers de camión de uso no comercial pueden sobresalir del ancho legal en qué medida en Carolina del Sur?","options":["Hasta 3 inches por cada lado","Hasta 6 inches por un lado y 4 inches por el otro","Hasta 12 inches por un solo lado","No se permite ninguna extensión más allá del ancho legal"],"explanation":"El Código de Carolina del Sur 56-5-4030 permite que los accesorios en casas rodantes, remolques de viaje y campers de camión no comerciales sobresalgan un máximo de 6 inches por un lado y 4 inches por el otro, más allá del límite de ancho de 102 inches. Fuente: SC Code 56-5-4030."},"19":{"q":"Un permiso de sobredimensión/sobrepeso típico de viaje único del SCDOT para una carga ancha estándar cuesta aproximadamente cuánto?","options":["$10","$30","$75","$150"],"explanation":"El SCDOT cobra alrededor de $30 por un permiso OSOW estándar de viaje único, con un permiso anual (de viajes múltiples) de alrededor de $100; se aplican tarifas más altas a anchos extremos de más de 16 feet. Fuente: tabla de tarifas de Permisos de Sobredimensión/Sobrepeso del SCDOT."},"20":{"q":"En Carolina del Sur, ¿qué clase de CDL se requiere para operar una combinación de vehículos con una Calificación de Peso Combinado Bruto (GCWR) de 26,001 pounds o más, donde la unidad remolcada tiene un GVWR de más de 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"explanation":"Carolina del Sur (SCDMV, Clases A, B y C) define una CDL Class A como cualquier combinación de vehículos con un GCWR de 26,001 lbs o más, siempre que el GVWR del vehículo remolcado sea de más de 10,000 lbs. Fuente: SCDMV Licencias Comerciales, Clases A, B y C."},"21":{"q":"Según el SCDMV, un vehículo de una sola unidad con un GVWR de 26,001 pounds o más (que no remolque nada de más de 10,000 lbs) requiere qué clase de CDL?","options":["Class C","Class B","Class A","Class E"],"explanation":"Carolina del Sur define una CDL Class B como cualquier vehículo de una sola unidad con un GVWR de 26,001 lbs o más, o ese mismo vehículo remolcando una unidad que no pese más de 10,000 lbs. Fuente: SCDMV Licencias Comerciales, Clases A, B y C."},"22":{"q":"Según las reglas de Carolina del Sur, un vehículo que no cumple los umbrales de peso de Class A o B pero está diseñado para transportar 16 o más personas (incluyendo al conductor) requiere qué clase de CDL?","options":["Class A","Class B","Class C","No se requiere CDL"],"explanation":"Carolina del Sur define una CDL Class C como cualquier vehículo individual, o combinación, que no sea Class A o B pero esté diseñado para transportar 16 o más personas incluyendo al conductor, o que se use para transportar materiales peligrosos que requieran rótulos (placards). Fuente: SCDMV Licencias Comerciales, Clases A, B y C."},"23":{"q":"En Carolina del Sur, ¿cuál es la edad mínima para obtener una CDL para conducción INTRAESTATAL (operar únicamente dentro del estado)?","options":["16 años","17 años","18 años","21 años"],"explanation":"El SCDMV exige que los solicitantes tengan al menos 18 años para conducir comercialmente dentro de Carolina del Sur (intraestatal). Los conductores menores de 21 años no pueden conducir fuera del estado. Fuente: SCDMV, Obtención de su Primera CDL."},"24":{"q":"¿Cuál es la edad mínima en Carolina del Sur para tener una CDL válida para conducción INTERESTATAL (cruzando líneas estatales)?","options":["18 años","19 años","21 años","25 años"],"explanation":"El SCDMV exige que los conductores tengan al menos 21 años para operar un vehículo comercial fuera de Carolina del Sur (interestatal). Los conductores de 18 a 20 años están restringidos a la operación intraestatal. Fuente: SCDMV, Obtención de su Primera CDL."},"25":{"q":"Antes de que un solicitante de Carolina del Sur pueda tomar el examen de habilidades (de manejo) de la CDL, ¿durante cuánto tiempo debe tener su Permiso de Aprendiz Comercial (CLP)?","options":["Al menos 7 días calendario","Al menos 14 días calendario","Al menos 30 días calendario","Al menos 60 días calendario"],"explanation":"Carolina del Sur sigue la regla federal que exige tener un CLP durante al menos 14 días calendario antes de que el solicitante pueda tomar el examen de habilidades de la CDL. Fuente: SCDMV, Obtención de su Primera CDL (49 CFR 383.25)."},"26":{"q":"¿Qué código de endoso usa Carolina del Sur para la autorización de operar un vehículo que transporta materiales peligrosos con rótulos (placards)?","options":["N","T","H","P"],"explanation":"El endoso H cubre los materiales peligrosos que requieren rótulos (placards). Carolina del Sur usa los códigos de endoso federales estándar: H (HazMat), N (Tanque), T (Dobles/Triples), P (Pasajeros), S (Autobús Escolar). Fuente: SCDMV Licencias Comerciales."},"27":{"q":"En Carolina del Sur, antes de que se pueda emitir o renovar un endoso de HazMat (H), un solicitante debe aprobar qué evaluación adicional?","options":["Una evaluación de amenaza a la seguridad de la TSA (verificación de antecedentes y toma de huellas)","Una prueba de agilidad física y levantamiento","Una certificación de un curso de manejo defensivo","Un examen de la vista administrado por el SCDMV"],"explanation":"Carolina del Sur exige que los solicitantes de HazMat (H) aprueben una evaluación federal de amenaza a la seguridad de la Administración de Seguridad en el Transporte (TSA), que incluye toma de huellas y verificación de antecedentes, tanto para el endoso original como para la renovación. Fuente: SCDMV; 49 CFR 1572."},"28":{"q":"¿Qué endoso se requiere en Carolina del Sur para conducir un vehículo comercial diseñado para transportar líquidos o gases en un tanque a granel?","options":["P (Pasajeros)","N (Vehículo Cisterna)","T (Dobles/Triples)","S (Autobús Escolar)"],"explanation":"El endoso N (Vehículo Cisterna) se requiere para operar un vehículo que transporta líquidos o gases en tanques a granel que cumplan con la definición federal. Fuente: SCDMV Licencias Comerciales; 49 CFR 383.93."},"29":{"q":"En Carolina del Sur, ¿qué endoso se requiere para remolcar remolques dobles o triples?","options":["Endoso T","Endoso N","Endoso H","Endoso X"],"explanation":"El endoso T autoriza la operación de remolques dobles y triples. Carolina del Sur usa los códigos federales estándar. Fuente: SCDMV Licencias Comerciales; 49 CFR 383.93."},"30":{"q":"¿Qué endoso debe obtener un conductor de Carolina del Sur para operar un autobús comercial o una van diseñados para transportar el número de pasajeros que alcanza el umbral requerido?","options":["S (Autobús Escolar)","P (Pasajeros)","N (Tanque)","T (Dobles/Triples)"],"explanation":"El endoso P (Pasajeros) se requiere para operar un vehículo diseñado para transportar 16 o más personas incluyendo al conductor. Se necesita un endoso S por separado para los autobuses escolares. Fuente: SCDMV Licencias Comerciales."},"31":{"q":"En Carolina del Sur, ¿qué necesita un conductor para operar un autobús escolar que requiere una CDL?","options":["Solo el endoso P (Pasajeros)","Tanto el endoso P (Pasajeros) como el S (Autobús Escolar)","Solo el endoso H (HazMat)","Ningún endoso, solo una CDL Class B"],"explanation":"Para conducir un autobús escolar en Carolina del Sur, un conductor debe tener tanto el endoso P (Pasajeros) como el S (Autobús Escolar), y aprobar los exámenes de conocimientos y de habilidades de autobús escolar. Fuente: SCDMV Licencias Comerciales; 49 CFR 383.93."},"32":{"q":"Para un solicitante de CLP/CDL de Carolina del Sur que obtuvo su permiso en o después del 7 de febrero de 2022, ¿qué capacitación debe completarse antes del examen de habilidades para una primera CDL?","options":["Un curso presencial exclusivo del estado del SCDMV","Capacitación de Conductores de Nivel Inicial (ELDT) aprobada por la FMCSA de un proveedor registrado","Un aprendizaje de 160 horas registrado con el SCDMV","No se requiere capacitación, solo el examen de habilidades"],"explanation":"Carolina del Sur exige que los solicitantes que obtuvieron un CLP en o después del 7 de febrero de 2022 completen la Capacitación de Conductores de Nivel Inicial (ELDT) aprobada por la FMCSA con un proveedor incluido en el Registro de Proveedores de Capacitación de la FMCSA antes de tomar el examen de habilidades. Fuente: SCDMV, Obtención de su Primera CDL; regla ELDT de la FMCSA."},"33":{"q":"Bajo la regla federal de ELDT aplicada en Carolina del Sur, la ELDT se requiere para una primera CDL y para qué conjunto de endosos?","options":["H (HazMat), P (Pasajeros) y S (Autobús Escolar)","N (Tanque), T (Dobles/Triples) y H (HazMat)","P (Pasajeros), N (Tanque) y T (Dobles/Triples)","Los cinco endosos (H, N, T, P, S)"],"explanation":"La ELDT se requiere para una CDL inicial Class A o B, una mejora de clase, y para los endosos de HazMat (H), Pasajeros (P) y Autobús Escolar (S). No se requiere para los endosos N (Tanque) ni T (Dobles/Triples). Fuente: regla ELDT de la FMCSA; SCDMV."},"34":{"q":"¿Cuántas categorías de autocertificación médica debe elegir un solicitante de CDL de Carolina del Sur al certificar el tipo de comercio en el que opera?","options":["Dos","Tres","Cuatro","Cinco"],"explanation":"Las reglas federales adoptadas por Carolina del Sur exigen que los titulares de CDL se autocertifiquen en una de cuatro categorías: Interestatal No Exenta, Interestatal Exenta, Intraestatal No Exenta, o Intraestatal Exenta. Fuente: SCDMV; 49 CFR 383.71."},"35":{"q":"Un conductor de CDL de Carolina del Sur que transporta carga cruzando líneas estatales y debe cumplir con los estándares del examen físico federal del DOT debe autocertificarse en qué categoría?","options":["Interestatal Exenta","Interestatal No Exenta","Intraestatal No Exenta","Intraestatal Exenta"],"explanation":"Un conductor que opera en comercio interestatal, que está sujeto a y debe cumplir con los estándares federales de calificación física (49 CFR Part 391), se certifica como Interestatal No Exenta y debe mantener un certificado válido de examinador médico. Fuente: SCDMV; 49 CFR 383.71."},"36":{"q":"¿Cuál de los siguientes documentos NO está entre los que el SCDMV exige que un solicitante de CDL por primera vez presente para la verificación de identidad, Seguro Social, residencia y presencia legal?","options":["Prueba de identidad y fecha de nacimiento","Prueba del número de Seguro Social","Dos pruebas de residencia en Carolina del Sur","Una carta de empleo firmada por una empresa de transporte"],"explanation":"El SCDMV exige prueba de identidad/presencia legal, un número de Seguro Social y residencia en Carolina del Sur (según la lista de verificación de documentos, por ejemplo, el Formulario MV-93). Una carta del empleador no es un documento requerido de identidad/residencia. Fuente: lista de verificación de documentos del SCDMV, Obtención de su Primera CDL."},"37":{"q":"En Carolina del Sur, ¿qué solicitantes son elegibles para solicitar un endoso de HazMat (H) de CDL?","options":["Cualquier titular de CDL sin importar su ciudadanía","Solo ciudadanos estadounidenses y residentes permanentes legales","Solo conductores de 25 años o más","Solo conductores que ya poseen el endoso combinado X"],"explanation":"Debido a la evaluación de amenaza a la seguridad de la TSA, solo los ciudadanos estadounidenses y los residentes permanentes legales son elegibles para un endoso de HazMat (H) de CDL en Carolina del Sur. Fuente: SCDMV; programa HME de la TSA (49 CFR 1572)."},"38":{"q":"¿Qué endosos puede obtener un conductor de Carolina del Sur mientras aún tiene únicamente un Permiso de Aprendiz Comercial (CLP)?","options":["Solo H (HazMat) y T (Dobles/Triples)","Solo N (Tanque), P (Pasajeros) y S (Autobús Escolar)","Los cinco endosos","Ninguno: no se permiten endosos en un CLP"],"explanation":"Un CLP de Carolina del Sur puede tener únicamente los endosos N (Tanque, restringido a tanques vacíos), P (Pasajeros, sin pasajeros aparte de instructores/examinadores) y S (Autobús Escolar). Los endosos H y T no pueden tenerse en un CLP. Fuente: SCDMV, Obtención de su Primera CDL; 49 CFR 383.25."},"39":{"q":"En Carolina del Sur, ¿qué significa el endoso combinado 'X' en una CDL?","options":["Autorización tanto para operaciones de Tanque (N) como de HazMat (H)","Autorización para Dobles/Triples (T) y Pasajeros (P)","Una restricción que prohíbe la conducción interestatal","Una certificación de operador de autobús escolar"],"explanation":"El endoso X es un código combinado que indica que el conductor tiene tanto el endoso de Tanque (N) como el de HazMat (H), lo que permite el transporte de materiales peligrosos en un vehículo cisterna. Fuente: SCDMV Licencias Comerciales; 49 CFR 383.153."},"40":{"q":"En Carolina del Sur, ¿cuál es la concentración máxima de alcohol en sangre (BAC) con la que es legal operar un vehículo motorizado comercial (CMV)?","options":["Menos de 0.04%","Menos de 0.08%","Menos de 0.02%","Menos de 0.05%"],"explanation":"Carolina del Sur sigue el estándar federal para CMV: es ilegal operar un CMV si su BAC es de 0.04% o más, por lo que la operación legal requiere un BAC menor de 0.04%. Fuente: Manual de Licencia de Conducir Comercial del SCDMV, Sección 1.3.2 (49 CFR 383.51)."},"41":{"q":"Bajo la regla de consentimiento implícito de Carolina del Sur para operadores de CMV, ¿qué sucede si un conductor tiene una cantidad detectable de alcohol que está por debajo de 0.04%?","options":["Se le pone fuera de servicio por 24 horas","Se le descalifica por 60 días","Se le descalifica por un año","Se le emite solo una advertencia sin ninguna acción"],"explanation":"Carolina del Sur pone a un conductor de CMV fuera de servicio por 24 horas si se detecta cualquier cantidad de alcohol por debajo de 0.04%. Un BAC de 0.04% o más activa una descalificación en su lugar. Fuente: Manual de CDL del SCDMV, Sección 1.3.2."},"42":{"q":"Al operar un CMV en Carolina del Sur, ¿qué se considera automáticamente que ha hecho un conductor respecto a las pruebas químicas?","options":["Ha dado su consentimiento para las pruebas de alcohol","Ha renunciado al derecho a una audiencia","Ha aceptado un examen anual de drogas","Ha consentido a un registro del vehículo"],"explanation":"Bajo el consentimiento implícito, se considera que cualquier persona que opera un CMV en Carolina del Sur ha dado su consentimiento para las pruebas de alcohol. Fuente: Manual de CDL del SCDMV, Sección 1.3.2."},"43":{"q":"¿Cuál es el período mínimo de descalificación en Carolina del Sur para la primera infracción mayor de un conductor de CMV, como un DUI o conducir un CMV con un BAC de 0.04% o más?","options":["1 año","60 días","6 meses","3 años"],"explanation":"Una primera infracción mayor (DUI, BAC de 0.04% o más en un CMV, negarse a la prueba, abandonar la escena, etc.) conlleva una descalificación mínima de al menos un año en Carolina del Sur. Fuente: Manual de CDL del SCDMV, Sección 1.3.2 (49 CFR 383.51)."},"44":{"q":"En Carolina del Sur, si una infracción mayor (como un DUI) ocurre mientras el conductor opera un CMV con rótulos (placards) de materiales peligrosos, ¿cuál es el período mínimo de descalificación?","options":["3 años","1 año","5 años","18 meses"],"explanation":"Carolina del Sur aumenta la descalificación por primera infracción a al menos tres años cuando la infracción mayor ocurre mientras se opera un CMV con rótulos (placards) de materiales peligrosos. Fuente: Manual de CDL del SCDMV, Sección 1.3.2 (49 CFR 383.51)."},"45":{"q":"¿Cuál es el período de descalificación en Carolina del Sur para la segunda infracción mayor de un conductor de CMV?","options":["De por vida","10 años","5 años","3 años"],"explanation":"Una segunda infracción mayor resulta en la pérdida de la CDL de por vida en Carolina del Sur. Fuente: Manual de CDL del SCDMV, Sección 1.3.2 (49 CFR 383.51)."},"46":{"q":"En Carolina del Sur, negarse a someterse a una prueba de alcohol en sangre como operador de CMV se trata como qué tipo de infracción a efectos de descalificación?","options":["Una infracción mayor (al menos 1 año)","Una infracción de tránsito grave (60 días)","Una infracción de fuera de servicio (90 días)","Una infracción menor sin descalificación"],"explanation":"Negarse a someterse a una prueba de alcohol en sangre está catalogado como una infracción mayor en Carolina del Sur y conlleva una descalificación mínima de un año para una primera infracción, igual que un DUI. Fuente: Manual de CDL del SCDMV, Sección 1.3.2."},"47":{"q":"Según las reglas de Carolina del Sur, un conductor de CMV pierde la CDL de por vida en una primera infracción si se usa un CMV para cometer qué tipo de delito?","options":["Un delito grave (felony) que involucre sustancias controladas","Cualquier delito grave (felony) de cualquier tipo","Un delito grave (felony) que involucre robo","Conducción imprudente que cause lesiones"],"explanation":"Usar un CMV para cometer un delito grave (felony) que involucre sustancias controladas resulta en descalificación de por vida en la primera infracción, sin posibilidad de la reincorporación a los 10 años disponible para otros casos de descalificación de por vida. Fuente: Manual de CDL del SCDMV, Sección 1.3.2."},"48":{"q":"En Carolina del Sur, ¿a qué velocidad por encima del límite señalizado debe ir un conductor de CMV para que la infracción cuente como el tipo de 'exceso de velocidad' de infracción de tránsito grave?","options":["15 mph o más por encima del límite","10 mph o más por encima del límite","20 mph o más por encima del límite","5 mph o más por encima del límite"],"explanation":"Carolina del Sur define el exceso de velocidad como una infracción de tránsito grave cuando el conductor va 15 mph o más por encima del límite de velocidad señalizado. Fuente: Manual de CDL del SCDMV, Sección 1.3.3."},"49":{"q":"¿Cuál de las siguientes se clasifica como una infracción de tránsito grave para un conductor de CMV en Carolina del Sur?","options":["Cambios de carril indebidos o erráticos","Conducir con un BAC de 0.04% o más","Negarse a una prueba química","Violar una orden de fuera de servicio"],"explanation":"Las infracciones de tránsito graves incluyen el exceso de velocidad (15 mph o más por encima), la conducción imprudente, los cambios de carril indebidos o erráticos, seguir demasiado cerca y ciertas infracciones relacionadas con la posesión de la CDL. Las otras opciones son infracciones mayores o de fuera de servicio. Fuente: Manual de CDL del SCDMV, Sección 1.3.3."},"50":{"q":"En Carolina del Sur, ¿cuál es la descalificación mínima por cometer dos infracciones de tránsito graves en un CMV dentro de un período de tres años?","options":["60 días","30 días","120 días","90 días"],"explanation":"Dos infracciones de tránsito graves dentro de tres años que involucren un CMV resultan en una descalificación de al menos 60 días. Fuente: Manual de CDL del SCDMV, Sección 1.3.3 (49 CFR 383.51)."},"51":{"q":"En Carolina del Sur, ¿cuál es la descalificación mínima por tres o más infracciones de tránsito graves en un CMV dentro de un período de tres años?","options":["120 días","60 días","180 días","1 año"],"explanation":"Tres o más infracciones de tránsito graves dentro de tres años que involucren un CMV resultan en una descalificación de al menos 120 días. Fuente: Manual de CDL del SCDMV, Sección 1.3.3 (49 CFR 383.51)."},"52":{"q":"¿Cuál es la descalificación mínima en Carolina del Sur por la primera violación de un conductor de una orden de fuera de servicio?","options":["90 días","60 días","180 días","1 año"],"explanation":"Una primera violación de una orden de fuera de servicio conlleva una descalificación mínima de 90 días en Carolina del Sur. Fuente: Manual de CDL del SCDMV, Sección 1.3.4 (49 CFR 383.51)."},"53":{"q":"En Carolina del Sur, ¿cuál es la descalificación mínima por una segunda violación de una orden de fuera de servicio dentro de un período de diez años?","options":["1 año","90 días","120 días","3 años"],"explanation":"Una segunda violación de una orden de fuera de servicio dentro de un período de diez años resulta en una descalificación de al menos un año. Fuente: Manual de CDL del SCDMV, Sección 1.3.4."},"54":{"q":"En Carolina del Sur, ¿cuál es la descalificación mínima por tres o más violaciones de órdenes de fuera de servicio dentro de un período de diez años?","options":["3 años","1 año","5 años","De por vida"],"explanation":"Tres o más violaciones de órdenes de fuera de servicio dentro de un período de diez años resultan en una descalificación de al menos tres años. Fuente: Manual de CDL del SCDMV, Sección 1.3.4."},"55":{"q":"¿Cuál es la descalificación mínima en Carolina del Sur por la primera infracción de un conductor de CMV en un cruce a nivel de ferrocarril y carretera?","options":["60 días","90 días","30 días","120 días"],"explanation":"Una primera infracción en un cruce a nivel de ferrocarril y carretera resulta en una descalificación de al menos 60 días en Carolina del Sur. Fuente: Manual de CDL del SCDMV, Sección 1.3.5 (49 CFR 383.51)."},"56":{"q":"En Carolina del Sur, ¿cuál es la descalificación mínima por una segunda infracción en un cruce a nivel de ferrocarril y carretera dentro de un período de tres años?","options":["120 días","60 días","90 días","1 año"],"explanation":"Una segunda infracción en un cruce a nivel de ferrocarril y carretera dentro de tres años resulta en una descalificación de al menos 120 días. Fuente: Manual de CDL del SCDMV, Sección 1.3.5."},"57":{"q":"En Carolina del Sur, ¿cuál es la descalificación mínima por una tercera infracción en un cruce a nivel de ferrocarril y carretera dentro de un período de tres años?","options":["1 año","120 días","180 días","3 años"],"explanation":"Una tercera infracción en un cruce a nivel de ferrocarril y carretera dentro de tres años resulta en una descalificación de al menos un año. Fuente: Manual de CDL del SCDMV, Sección 1.3.5."},"58":{"q":"Según las reglas de Carolina del Sur, ¿por cuánto tiempo se descalifica la CDL de un conductor de CMV tras una segunda condena dentro de tres años por enviar mensajes de texto mientras opera un CMV?","options":["60 días","30 días","120 días","1 año"],"explanation":"Dos o más condenas por enviar mensajes de texto mientras se opera un CMV activan la descalificación: 60 días por la segunda infracción dentro de tres años y 120 días por tres o más dentro de tres años. Los conductores también enfrentan sanciones civiles de hasta $2,750. Fuente: Manual de CDL del SCDMV, Secciones 2.9.6 y 2.9.5."},"59":{"q":"Bajo la Ley de Manos Libres y Conducción Distraída de Carolina del Sur, ¿cuál es la multa por una primera infracción de sostener un dispositivo móvil mientras se conduce?","options":["$100 más costos judiciales","$25 más costos judiciales","$200 más costos judiciales","$500 más costos judiciales"],"explanation":"La Ley de Manos Libres y Conducción Distraída de Carolina del Sur (S.C. Code Section 56-5-3890) establece una multa de $100 más costos judiciales por una primera infracción y $200 más dos puntos por una segunda infracción dentro de tres años; para los conductores de CMV, dos condenas dentro de tres años también conllevan una descalificación de 60 días. Fuente: SCDPS Hands Free SC; S.C. Code 56-5-3890."},"60":{"q":"En una autopista interestatal de Carolina del Sur, ¿cuál es el límite de velocidad máximo para un camión comercial cuando no hay señalizado un límite menor?","options":["65 mph, porque los camiones tienen un límite menor que los autos","70 mph, el mismo que para otros vehículos","60 mph en todos los tramos de la autopista interestatal","55 mph para cualquier vehículo de más de 26,001 lbs"],"explanation":"Carolina del Sur NO establece un límite de velocidad menor por separado para camiones. Según el S.C. Code 56-5-1520, el máximo en el sistema de autopistas interestatales es de 70 mph, y los camiones grandes están sujetos al mismo límite señalizado. Fuente: S.C. Code 56-5-1520; Manual CDL del SCDMV."},"61":{"q":"Según la ley de Carolina del Sur, ¿cuál es el límite de velocidad máximo en una carretera primaria dividida de varios carriles (que no sea una interestatal) a menos que se señalice lo contrario?","options":["55 mph","65 mph","60 mph","70 mph"],"explanation":"El S.C. Code 56-5-1520 establece 60 mph como máximo en carreteras primarias divididas de varios carriles, 70 mph en el sistema interestatal y 55 mph en otras carreteras (no divididas). Fuente: S.C. Code 56-5-1520."},"62":{"q":"La ley 'Move Over' de Carolina del Sur (S.C. Code 56-5-1538) exige que un conductor que se acerca a un vehículo de emergencia detenido con luces intermitentes haga PRIMERO ¿qué, si se puede hacer de forma segura?","options":["Detenerse por completo hasta que el vehículo de emergencia se retire","Desocupar el carril más cercano al vehículo de emergencia cambiándose a un carril no adyacente","Tocar la bocina y continuar a la velocidad señalizada","Orillarse hacia el acotamiento detrás del vehículo de emergencia"],"explanation":"Según el S.C. Code 56-5-1538, el conductor debe ceder el paso cambiándose a un carril no adyacente al vehículo de emergencia autorizado detenido (ambulancia, policía, bomberos, rescate, recuperación o grúa) cuando sea seguro hacerlo. Fuente: S.C. Code 56-5-1538; SCDPS."},"63":{"q":"Según la ley Move Over de Carolina del Sur, ¿qué debe hacer un conductor si cambiar de carril para alejarse de un vehículo de emergencia detenido no es posible o no es seguro?","options":["Detenerse por completo en el carril actual","Mantener la velocidad señalizada pero encender las intermitentes de emergencia","Avanzar con precaución y reducir significativamente la velocidad","Salir en la rampa más cercana y tomar una ruta alterna"],"explanation":"El S.C. Code 56-5-1538 exige que un conductor que no pueda cambiar de carril de forma segura avance con la debida precaución y reduzca significativamente la velocidad del vehículo, manteniendo una velocidad segura para las condiciones de la vía. Fuente: S.C. Code 56-5-1538; SCDPS."},"64":{"q":"Cuando un vehículo con placas (de materiales peligrosos) se detiene en un cruce de ferrocarril en Carolina del Sur, ¿dónde debe detenerse en relación con el riel más cercano?","options":["Entre 15 y 50 pies del riel más cercano","Entre 10 y 25 pies del riel más cercano","Entre 50 y 100 pies del riel más cercano","A no más de 15 pies del riel más cercano"],"explanation":"El Manual CDL del SCDMV y el S.C. Code 56-5-2720 exigen que un vehículo con placas se detenga a no más de 50 pies pero no menos de 15 pies del riel más cercano. Fuente: Manual CDL del SCDMV 9.6.12; S.C. Code 56-5-2720."},"65":{"q":"¿Cuál de los siguientes vehículos debe detenerse siempre en cada cruce de ferrocarril en Carolina del Sur (a menos que el cruce esté exento)?","options":["Un camión volquete cargado","Un autobús que transporta pasajeros","Un remolque de plataforma vacío","Una camioneta que jala un remolque utilitario"],"explanation":"Un autobús que transporta pasajeros, un autobús escolar y cualquier vehículo con placas o con carga peligrosa debe detenerse en cada cruce de ferrocarril (de 15 a 50 pies del riel más cercano) y mirar y escuchar. Fuente: Manual CDL del SCDMV; S.C. Code 56-5-2720."},"66":{"q":"Mientras cualquier parte de su vehículo comercial está cruzando las vías del ferrocarril en Carolina del Sur, el Manual CDL le indica que NO haga ¿cuál de las siguientes acciones?","options":["Mantener las manos en el volante","Mirar en ambas direcciones a lo largo de la vía","Cambiar de velocidad (cambiar de marcha)","Estar atento a un segundo tren"],"explanation":"El Manual CDL del SCDMV indica: no se detenga, no cambie de marcha ni cambie de carril mientras cualquier parte de su vehículo esté cruzando las vías. Elija una marcha que le permita librar las vías sin cambiar de velocidad. Fuente: Manual CDL del SCDMV 2.15.4 / 13.1.8."},"67":{"q":"En Carolina del Sur, un conductor que se cruza con un autobús escolar detenido que tiene las luces rojas intermitentes encendidas NO está obligado a detenerse cuando viaja en sentido contrario en ¿qué tipo de vía?","options":["Cualquier camino de dos carriles con un carril central de giro","Una carretera de varios carriles","Cualquier camino con un límite señalizado superior a 45 mph","Un camino con una franja divisoria central pintada (no elevada)"],"explanation":"Según el S.C. Code 56-5-2770, un conductor no necesita detenerse al cruzarse con un autobús escolar detenido cuando viaja en sentido contrario en una carretera de varios carriles. Los conductores que circulan en el mismo sentido, y en caminos de dos carriles, sí deben detenerse. Fuente: S.C. Code 56-5-2770."},"68":{"q":"Un conductor que viaja en el MISMO sentido detrás de un autobús escolar de Carolina del Sur que ha activado sus luces rojas intermitentes y su brazo de alto, ¿qué debe hacer?","options":["Reducir a 15 mph y pasar con precaución","Detenerse y permanecer detenido hasta que el autobús se mueva o las luces rojas dejen de parpadear","Pasar solo por la izquierda si no se ven niños","Detenerse solo si el autobús está en un camino no dividido de dos carriles"],"explanation":"El S.C. Code 56-5-2770 exige que un vehículo que se aproxima desde cualquiera de los dos sentidos (salvo la excepción de sentido contrario en vías de varios carriles) se detenga antes de llegar a un autobús escolar con luces rojas intermitentes y no avance hasta que el autobús reanude la marcha o las luces rojas ya no estén activadas. Fuente: S.C. Code 56-5-2770."},"69":{"q":"Cuando un CMV se detiene en un camino de dos carriles que lleva tráfico en ambos sentidos en Carolina del Sur, ¿dónde deben colocarse los tres triángulos de advertencia?","options":["Los tres a no más de 10 pies de la parte trasera del vehículo","A no más de 10 pies del vehículo, más 100 pies por detrás y 100 pies por delante","A 10 pies, 200 pies y 500 pies por detrás del vehículo","Uno en el vehículo y dos lado a lado a 50 pies por detrás"],"explanation":"En un camino de doble sentido o no dividido, el Manual CDL del SCDMV indica colocar un triángulo a no más de 10 pies del frente o de la parte trasera, y uno a 100 pies por detrás y uno a 100 pies por delante del vehículo. Fuente: Manual CDL del SCDMV 2.5 (Dispositivos de Advertencia)."},"70":{"q":"Cuando un CMV se detiene en una carretera de un solo sentido o dividida en Carolina del Sur, ¿a qué distancias hacia atrás, en dirección al tráfico que se aproxima, deben colocarse los dispositivos de advertencia?","options":["10 pies, 100 pies y 200 pies","10 pies, 50 pies y 100 pies","25 pies, 100 pies y 300 pies","100 pies, 200 pies y 300 pies"],"explanation":"En una carretera de un solo sentido o dividida, el Manual CDL del SCDMV indica colocar los tres triángulos reflectantes a 10 pies, 100 pies y 200 pies en dirección al tráfico que se aproxima. Fuente: Manual CDL del SCDMV 2.5."},"71":{"q":"Después de detenerse en el acotamiento de una carretera de Carolina del Sur, ¿dentro de cuántos minutos debe un conductor de CMV colocar los dispositivos de advertencia de emergencia?","options":["5 minutos","10 minutos","15 minutos","30 minutos"],"explanation":"El Manual CDL del SCDMV indica que si debe detenerse en una vía o en el acotamiento, debe colocar sus dispositivos de advertencia de emergencia dentro de los 10 minutos. Fuente: Manual CDL del SCDMV 2.5."},"72":{"q":"La ley de carril izquierdo ('Move Right') de Carolina del Sur para carreteras de acceso controlado generalmente restringe el carril del extremo izquierdo ¿a qué uso?","options":["Vehículos que circulan al límite señalizado o por encima de él","Rebasar y adelantar a otro vehículo","Solo vehículos de menos de 10,000 lbs","Vehículos compartidos (carpool) y de transporte público"],"explanation":"Según el S.C. Code 56-5-1885, los conductores pueden usar el carril del extremo izquierdo de una carretera de acceso controlado solo al rebasar y adelantar. Fuente: S.C. Code 56-5-1885; Ley Move Right del SCDPS."},"73":{"q":"La ley de carril izquierdo de Carolina del Sur otorga una exención específica a un vehículo motorizado comercial que no puede salir del carril izquierdo de forma segura debido a ¿qué condición?","options":["Un pasajero dormido en la litera (sleeper berth)","Una pendiente de la carretera, u otro vehículo que adelanta por la derecha","Llevar una placa de materiales peligrosos","Operar de noche con visibilidad reducida"],"explanation":"Según el S.C. Code 56-5-1885, un conductor de CMV queda exento de la restricción del carril izquierdo cuando no puede incorporarse a la derecha de forma segura debido a una pendiente de la carretera o porque otro vehículo lo está rebasando/adelantando por la derecha. Fuente: S.C. Code 56-5-1885; SCDPS."},"74":{"q":"Conduciendo un autobús en Carolina del Sur, usted se acerca a un puente levadizo que NO tiene semáforo NI un encargado de control de tráfico. ¿Qué debe hacer?","options":["Cruzar a velocidad reducida sin detenerse","Detenerse al menos 50 pies antes del tramo móvil y confirmar que está completamente cerrado","Detenerse de 15 a 50 pies antes del tramo móvil","Detenerse solo si suena la campana de advertencia"],"explanation":"El Manual CDL del SCDMV (4.3.6) indica a los conductores de autobús detenerse en los puentes levadizos que no tengan semáforo ni encargado, deteniéndose al menos 50 pies antes del tramo móvil y confirmando que está completamente cerrado antes de cruzar. Fuente: Manual CDL del SCDMV 4.3.6."},"75":{"q":"¿Qué lista de infracciones provoca una primera descalificación del CDL en Carolina del Sur de al menos 60 días?","options":["Seguir demasiado de cerca","Una infracción en un cruce a nivel de ferrocarril y carretera","Una citación por exceso de peso por eje","No mostrar una placa requerida"],"explanation":"El Manual CDL del SCDMV indica que un titular de CDL pierde el CDL por al menos 60 días por una primera infracción en un cruce a nivel de ferrocarril y carretera, 120 días por una segunda dentro de tres años, y un año por una tercera. Fuente: Manual CDL del SCDMV 1.3.5; 49 CFR 383.51."},"76":{"q":"En Carolina del Sur, ¿cuál es el ANCHO máximo legal estándar del vehículo/carga antes de que se requiera un permiso de tamaño excesivo?","options":["8 pies 0 pulgadas","8 pies 6 pulgadas","9 pies 0 pulgadas","10 pies 0 pulgadas"],"explanation":"El límite legal de ancho de Carolina del Sur es de 8 pies 6 pulgadas (102 inches); las cargas más anchas que esto requieren un permiso de tamaño excesivo del SCDOT. La altura legal máxima es de 13 pies 6 pulgadas. Fuente: Permisos de Tamaño/Peso Excesivo del SCDOT."},"77":{"q":"Sin un permiso, ¿cuál es la ALTURA máxima legal para un vehículo comercial y su carga en Carolina del Sur?","options":["13 pies 6 pulgadas","14 pies 0 pulgadas","12 pies 6 pulgadas","13 pies 0 pulgadas"],"explanation":"La altura máxima legal de Carolina del Sur es de 13 pies 6 pulgadas; cualquier cosa más alta requiere un permiso de altura excesiva del SCDOT y una revisión de ruta para el gálibo de los pasos a desnivel. Fuente: Permisos de Tamaño/Peso Excesivo del SCDOT."},"78":{"q":"Según las reglas de permisos del SCDOT, ¿durante qué horarios se permite generalmente que las cargas de tamaño excesivo circulen en Carolina del Sur?","options":["24 horas al día, cualquier día","Desde media hora después del amanecer hasta media hora antes del atardecer, de lunes a sábado","Solo entre las 9 p.m. y las 5 a.m. para evitar el tráfico","Solo entre semana, sin permitirse circulación el sábado"],"explanation":"El SCDOT generalmente restringe la circulación de cargas de tamaño excesivo a desde media hora después del amanecer hasta media hora antes del atardecer, de lunes a sábado, sin circulación los domingos ni en días festivos designados, además de restricciones adicionales para cargas muy anchas. Fuente: Permisos de Tamaño/Peso Excesivo del SCDOT."},"79":{"q":"Un conductor que rebasa de forma ilegal un autobús escolar detenido en Carolina del Sur y un conductor que se aproxima a un vehículo de emergencia detenido bajo la ley Move Over están ambos sujetos a sanciones. ¿Qué afirmación es correcta sobre la infracción de la ley Move Over?","options":["Es solo una multa civil de $25 sin costos judiciales","Es un delito menor que conlleva una multa en el rango de $300 a $500","Conlleva una descalificación automática y de por vida del CDL","Es una infracción de solo advertencia durante el primer año"],"explanation":"Una infracción de la ley Move Over de Carolina del Sur (S.C. Code 56-5-1538) es un delito menor castigable con una multa generalmente en el rango de $300-$500; en cambio, la infracción de carril izquierdo 'Move Right' (56-5-1885) es una multa civil de $25. Fuente: S.C. Code 56-5-1538; SCDPS."},"80":{"q":"¿Qué agencia emite las Licencias de Conducir Comercial (CDL) en Carolina del Sur?","options":["El Departamento de Vehículos Motorizados de Carolina del Sur (SCDMV)","El Departamento de Transporte de Carolina del Sur (SCDOT)","La Administración Federal de Seguridad de Autotransportes (FMCSA)","La Patrulla de Caminos de Carolina del Sur"],"explanation":"Las CDL de Carolina del Sur son emitidas por el Departamento de Vehículos Motorizados de Carolina del Sur (SCDMV). La FMCSA establece las normas federales del CDL pero no emite la licencia; el SCDOT se encarga de las carreteras/permisos, no de las licencias. Fuente: página de Licencias Comerciales del SCDMV (dmv.sc.gov)."},"81":{"q":"En Carolina del Sur, ¿cuál es el formulario estándar que se usa para solicitar un Permiso de Aprendiz Comercial (CLP) o un CDL?","options":["Formulario SCDMV 447-CDL","Formulario SCDMV DL-405A","Formulario SCDMV MV-93","Formulario FMCSA MCSA-5876"],"explanation":"La solicitud para un CLP y un CDL en Carolina del Sur es el Formulario SCDMV 447-CDL. El DL-405A es el formulario de autocertificación médica, el MV-93 es la lista de verificación de documentos de identidad, y el MCSA-5876 es el certificado federal del examinador médico. Fuente: SCDMV Getting Your First CDL (dmv.sc.gov)."},"82":{"q":"¿Cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Carolina del Sur antes de que venza?","options":["Un año","180 días","Seis meses","Dos años"],"explanation":"En Carolina del Sur, el CLP tiene una fecha de vencimiento de un año. Fuente: SCDMV Getting Your First CDL (dmv.sc.gov). (La regla federal permite un CLP válido hasta por un año, lo cual Carolina del Sur aplica.)"},"83":{"q":"Después de que se le emite un Permiso de Aprendiz Comercial en Carolina del Sur, ¿cuánto tiempo debe tenerlo antes de ser elegible para presentar el examen de habilidades del CDL?","options":["Al menos 14 días","Al menos 30 días","Al menos 10 días","Al menos 7 días"],"explanation":"Debe tener el CLP por un mínimo de 14 días antes de poder presentar el examen de habilidades. Fuente: SCDMV Getting Your First CDL (dmv.sc.gov); esto refleja el periodo federal de espera de 14 días del CLP (49 CFR 383.25)."},"84":{"q":"Bajo la autocertificación del CDL de Carolina del Sur, ¿entre cuántas categorías de operación debe elegir un conductor?","options":["Cuatro","Dos","Tres","Cinco"],"explanation":"Hay cuatro categorías de autocertificación: interestatal no exceptuada, interestatal exceptuada, intraestatal no exceptuada e intraestatal exceptuada. Los conductores certifican su categoría ante el SCDMV. Fuente: SCDMV / Formulario DL-405A (dmv.sc.gov)."},"85":{"q":"¿Qué formulario de Carolina del Sur se usa para autocertificar su tipo de comercio y presentar el estado de la certificación médica ante el SCDMV?","options":["Formulario DL-405A (Certificación Médica del Titular del CDL)","Formulario 447-CDL (Solicitud de CDL)","Formulario MV-93 (Lista de Verificación del Ciudadano)","Formulario MCSA-5875 (Informe del Examen Médico)"],"explanation":"Carolina del Sur usa el Formulario DL-405A para la autocertificación y la certificación médica del titular del CDL. El Formulario 447-CDL es la solicitud de la licencia, el MV-93 la lista de verificación de identidad, y el MCSA-5875 el informe federal del examen. Fuente: SCDMV Renew or Upgrade Your CDL (dmv.sc.gov)."},"86":{"q":"¿Qué categoría de autocertificación exige que un titular de CDL de Carolina del Sur presente un certificado válido del examinador médico del DOT?","options":["Interestatal no exceptuada","Interestatal exceptuada","Intraestatal exceptuada","Ninguna categoría requiere un certificado médico"],"explanation":"Los conductores interestatales no exceptuados deben mantener un certificado válido del examinador médico del DOT que cumpla con las normas de la FMCSA. Los conductores en las categorías exceptuadas no están obligados a presentar uno. Fuente: SCDMV / Formulario DL-405A (dmv.sc.gov); 49 CFR 391.41."},"87":{"q":"¿Quién está autorizado para realizar el examen físico y emitir el certificado del examinador médico que debe tener un conductor de CDL no exceptuado de Carolina del Sur?","options":["Un profesional médico inscrito en el Registro Nacional de Examinadores Médicos Certificados de la FMCSA","Cualquier médico con licencia que elija el conductor","Un examinador del SCDMV en la oficina sucursal","Un médico aprobado por el Departamento de Transporte de Carolina del Sur"],"explanation":"El examen debe ser realizado y el certificado emitido por un profesional médico inscrito en el Registro Nacional de Examinadores Médicos Certificados de la FMCSA. Fuente: SCDMV Commercial Licenses (dmv.sc.gov); 49 CFR 390.103."},"88":{"q":"Antes de presentar el examen de habilidades del CDL en Carolina del Sur, ¿qué requisito aplica a los solicitantes que recibieron su CLP después del 7 de febrero de 2022?","options":["Completar un programa de Capacitación para Conductores Principiantes (ELDT) aprobado por la FMCSA","Mantener un historial de conducción limpio durante cinco años consecutivos","Completar 160 horas de práctica al volante con el SCDMV","Aprobar un curso de manejo defensivo aparte del SCDMV"],"explanation":"Los solicitantes cuyo CLP se emitió después del 7 de febrero de 2022 deben completar un programa ELDT aprobado por la FMCSA con un proveedor de capacitación registrado antes de presentar el examen de habilidades. Fuente: SCDMV Getting Your First CDL (dmv.sc.gov); 49 CFR Part 380 Subpart F."},"89":{"q":"El examen de habilidades del CDL de Carolina del Sur se divide en tres partes. ¿Qué conjunto enumera correctamente esas tres partes?","options":["Inspección previa al viaje, control básico del vehículo y conducción en carretera","Conocimientos escritos, examen de la vista y conducción en carretera","Inspección previa al viaje, materiales peligrosos y conducción nocturna","Revisión de frenos de aire, estacionamiento en paralelo e incorporación a autopista"],"explanation":"El examen de habilidades del CDL tiene tres componentes: la inspección previa al viaje, el control básico del vehículo (fuera de carretera) y el examen de conducción en carretera. Fuente: SCDMV Getting Your First CDL (dmv.sc.gov); 49 CFR 383.113."},"90":{"q":"¿Cuál es el periodo de validez estándar de un CDL de Carolina del Sur antes de que deba renovarse?","options":["8 años","5 años","4 años","10 años"],"explanation":"Un CDL de Carolina del Sur es válido por 8 años y vence en el cumpleaños del titular en el último año del ciclo. Fuente: SCDMV (dmv.sc.gov). (Un endoso de HazMat está limitado por el ciclo separado de 5 años de la Evaluación de Amenaza a la Seguridad de la TSA.)"},"91":{"q":"Un CDL de Carolina del Sur con un endoso de materiales peligrosos (HazMat) está limitado por ¿qué plazo separado?","options":["El ciclo de 5 años de la Evaluación de Amenaza a la Seguridad de la TSA","Un ciclo de renovación de 2 años solo para HazMat","Una certificación federal de HazMat de 10 años","Una revisión de HazMat de 1 año del SCDMV"],"explanation":"Aunque el CDL en sí es válido por 8 años, el endoso de HazMat está vinculado a la Evaluación de Amenaza a la Seguridad de la TSA, que debe renovarse en un ciclo de 5 años. Fuente: SCDMV Commercial Licenses (dmv.sc.gov); 49 CFR 1572."},"92":{"q":"¿Cuándo debe un titular de CDL de Carolina del Sur presentar comprobante de aptitud médica (autocertificación/certificado médico) ante el SCDMV?","options":["Cada vez que solicita, renueva, mejora, cambia el domicilio o duplica el CDL","Solo una vez, al obtener por primera vez el CDL","Solo en la renovación a los 8 años","Solo al agregar un endoso de HazMat"],"explanation":"Los conductores deben presentar comprobante de aptitud médica cada vez que solicitan un CLP/CDL, lo mejoran, lo renuevan, cambian de domicilio o solicitan un duplicado. Fuente: SCDMV Commercial Licenses (dmv.sc.gov)."},"93":{"q":"¿Cuál es la edad mínima para que se emita un CDL en Carolina del Sur para conducir un vehículo comercial únicamente dentro del estado (intraestatal)?","options":["18 años de edad","19 años de edad","21 años de edad","20 años de edad"],"explanation":"Debe tener al menos 18 años para tener un CDL para conducción intraestatal dentro de Carolina del Sur, y al menos 21 para conducir de forma interestatal. Fuente: SCDMV Getting Your First CDL (dmv.sc.gov)."},"94":{"q":"¿Qué edad mínima exige Carolina del Sur para operar un vehículo motorizado comercial en el comercio interestatal (a través de las fronteras estatales)?","options":["21 años de edad","18 años de edad","19 años de edad","25 años de edad"],"explanation":"Un conductor debe tener al menos 21 años para operar un CMV en el comercio interestatal; las edades de 18 a 20 años están limitadas a la operación intraestatal. Fuente: SCDMV Getting Your First CDL (dmv.sc.gov); 49 CFR 391.11."},"95":{"q":"¿Cómo se verifica típicamente el certificado del examinador médico de un conductor interestatal no exceptuado una vez presentado ante el SCDMV?","options":["Se verifica electrónicamente/se registra en el historial de conducción","Debe ser notariado en la sucursal del SCDMV","Se envía por correo a la FMCSA para su aprobación manual","Lo verifica solo el examinador médico, no el estado"],"explanation":"Para los conductores no exceptuados, la información del certificado médico se verifica electrónicamente y el estado médico se agrega al historial de conducción del CDL. Fuente: SCDMV Commercial Licenses (dmv.sc.gov); 49 CFR 383.71/383.73."},"96":{"q":"Antes de solicitar un CDL o un CLP, Carolina del Sur exige que el solicitante ya tenga ¿qué credencial?","options":["Una licencia de conducir de Carolina del Sur válida y vigente","Un pasaporte válido","Una tarjeta TWIC federal","Una licencia de negocio de Carolina del Sur"],"explanation":"Los solicitantes deben tener una licencia de conducir (regular) de Carolina del Sur válida y vigente antes de solicitar un CLP/CDL. Fuente: SCDMV Getting Your First CDL (dmv.sc.gov)."},"97":{"q":"En una renovación de CDL de Carolina del Sur, ¿qué documento debe presentarse además de la solicitud y la certificación médica/autocertificación?","options":["Información del seguro de responsabilidad civil del automóvil de una compañía con licencia en Carolina del Sur","Una declaración jurada notariada del empleador","Comprobante de haber completado un nuevo curso ELDT","Una nueva verificación de huellas de la TSA para todos los endosos"],"explanation":"Carolina del Sur exige información del seguro de responsabilidad civil del automóvil de una aseguradora con licencia en SC al renovar el CDL, junto con el Formulario 447-CDL y la certificación médica del Formulario DL-405A según corresponda. Fuente: SCDMV Renew or Upgrade Your CDL (dmv.sc.gov)."},"98":{"q":"Si un titular de CDL de Carolina del Sur deja vencer el certificado del examinador médico requerido federalmente mientras está certificado como no exceptuado, ¿cuál es la consecuencia para el CDL?","options":["El CDL se degrada de modo que se pierden los privilegios comerciales hasta que haya un certificado válido en el archivo","Nada cambia hasta la renovación a los 8 años","El CDL se revoca permanentemente sin posibilidad de reinstalación","Solo se ve afectado el endoso de HazMat"],"explanation":"Cuando el certificado médico de un conductor no exceptuado vence o no está en el archivo, el estado debe degradar el CDL (eliminando los privilegios de conducción comercial) hasta que se presente un certificado vigente. Fuente: reglas de certificación médica del SCDMV / FMCSA (dmv.sc.gov); 49 CFR 383.73."},"99":{"q":"Al renovar un CDL de Carolina del Sur, la autocertificación médica (Formulario DL-405A) generalmente debe volver a presentarse ¿en qué situación?","options":["Si aún no se ha presentado o si ha cambiado el tipo de comercio que se está operando","Solo si el conductor se ha mudado a otro estado","Solo si el conductor tiene más de 65 años de edad","Nunca, porque es un trámite que se hace una sola vez"],"explanation":"Carolina del Sur exige la autocertificación DL-405A al renovar si aún no se ha presentado o si ha cambiado el tipo de comercio del conductor (categoría de autocertificación). Fuente: SCDMV Renew or Upgrade Your CDL (dmv.sc.gov)."}},"hi":{"0":{"q":"South Carolina के राजमार्गों पर, स्वीकृत सुरक्षा उपकरणों को छोड़कर, किसी वाहन या उसके भार की अधिकतम कुल बाहरी चौड़ाई कितनी होती है?","options":["96 inches","102 inches","108 inches","120 inches"],"explanation":"South Carolina Code 56-5-4030 किसी वाहन या भार की अधिकतम कुल बाहरी चौड़ाई 102 inches (8 feet 6 inches) निर्धारित करता है, जिसमें स्वीकृत सुरक्षा उपकरण शामिल नहीं हैं। यह राज्यभर में अपनाए गए संघीय मानक के अनुरूप है। स्रोत: SC Code 56-5-4030 (Width of vehicles)।"},"1":{"q":"South Carolina के राजमार्गों पर अधिकांश वाहनों के लिए, खाली या लदे हुए, अधिकतम ऊंचाई कितनी होती है?","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"explanation":"South Carolina Code 56-5-4060 वाहन की ऊंचाई को 13 feet 6 inches तक सीमित करता है। एक संकीर्ण अपवाद के तहत वैध SCDOT रूटिंग परमिट वाले ऑटोमोबाइल ट्रांसपोर्टर यूनिट या सैडल-माउंट संयोजन के लिए 14 feet की अनुमति है। स्रोत: SC Code 56-5-4060 (Height of vehicles)।"},"2":{"q":"South Carolina में किसी एकल मोटर वाहन (जैसे स्ट्रेट ट्रक) की, बंपर और भार सहित, अधिकतम लंबाई कितनी होती है?","options":["35 feet","40 feet","45 feet","48 feet"],"explanation":"South Carolina Code 56-5-4070 किसी एकल मोटर वाहन को आगे और पीछे के बंपर तथा भार सहित अधिकतम कुल लंबाई 40 feet तक सीमित करता है। बसों और कुछ मोटर होम को अलग से माना जाता है। स्रोत: SC Code 56-5-4070 (Length of vehicles)।"},"3":{"q":"दो-यूनिट वाले ट्रक ट्रैक्टर-सेमीट्रेलर संयोजन में, South Carolina में ट्रेलर या सेमीट्रेलर की (भार सहित) अधिकतम लंबाई कितनी होती है?","options":["48 feet","50 feet","53 feet","57 feet"],"explanation":"South Carolina Code 56-5-4070 दो-यूनिट वाले ट्रक ट्रैक्टर संयोजन में ट्रेलर या सेमीट्रेलर को भार सहित 53 feet तक की अनुमति देता है। 53-foot ट्रेलर में पीछे की ओर अंडरराइड गार्ड होना आवश्यक है। स्रोत: SC Code 56-5-4070।"},"4":{"q":"South Carolina में, कोई एकल एक्सल राजमार्ग पर अधिकतम कितना सकल भार डाल सकता है?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"South Carolina Code 56-5-4140 किसी एक एक्सल पर सकल भार को 20,000 pounds तक सीमित करता है। यह संघीय एकल-एक्सल सीमा के समान है। स्रोत: SC Code 56-5-4140 (Gross weight of vehicles)।"},"5":{"q":"South Carolina में विशेष परमिट के बिना अनुमत अधिकतम कुल सकल वाहन भार कितना होता है?","options":["73,280 pounds","76,000 pounds","80,000 pounds","88,000 pounds"],"explanation":"South Carolina Code 56-5-4140 कुल सकल भार को 80,000 pounds तक सीमित करता है, सिवाय उन वाहनों के जिन्हें SCDOT द्वारा विशेष परमिट जारी किए गए हों। यह संघीय अंतरराज्यीय अधिकतम सीमा के अनुरूप है। स्रोत: SC Code 56-5-4140।"},"6":{"q":"South Carolina के Interstate राजमार्गों पर, एक टैंडम एक्सल समूह पर अनुमत अधिकतम सकल भार कितना होता है (प्रवर्तन सहनशीलता सहित)?","options":["32,000 pounds","34,000 pounds","35,200 pounds","36,000 pounds"],"explanation":"Interstate प्रणाली पर, South Carolina टैंडम-एक्सल सकल भार 35,200 pounds की अनुमति देता है, जिसमें 34,000-pound संघीय आधार से ऊपर राज्य की प्रवर्तन सहनशीलता शामिल है। स्रोत: SC Code 56-5-4140; SCDMV/SCDOT size-weight मार्गदर्शन।"},"7":{"q":"South Carolina के गैर-Interstate (राज्य) राजमार्गों पर, 40 से 96 inches की दूरी पर रखे गए टैंडम एक्सल समूह पर अनुमत अधिकतम सकल भार कितना होता है?","options":["34,000 pounds","35,200 pounds","36,000 pounds","40,000 pounds"],"explanation":"South Carolina Code 56-5-4140 Interstate के अलावा अन्य राजमार्गों पर टैंडम एक्सल (40 से 96 inches की दूरी पर रखे गए दो या अधिक लगातार एक्सल) पर 36,000 pounds तक की अनुमति देता है। Interstate की टैंडम सीमा 35,200 pounds पर कम है। स्रोत: SC Code 56-5-4140।"},"8":{"q":"South Carolina एक्सल समूह पर अनुमत सकल भार को उनके बीच की दूरी के आधार पर निर्धारित करने के लिए किस सूत्र का उपयोग करता है?","options":["The Federal Bridge Formula (Formula B)","Gross Combination Weight Rating सूत्र","Davis रोलिंग-प्रतिरोध सूत्र","एकल-एक्सल सहनशीलता सूत्र"],"explanation":"South Carolina किसी भी दो या अधिक लगातार एक्सल के समूह पर अधिकतम भार को एक्सल की दूरी और एक्सल की संख्या के आधार पर निर्धारित करने के लिए Federal Bridge Formula (Bridge Formula B) लागू करता है, जो 23 U.S.C. 127 के अनुरूप है। स्रोत: SC Code 56-5-4140; FHWA Federal Bridge Formula।"},"9":{"q":"South Carolina की कौन-सी राज्य एजेंसी कानूनी सीमाओं से अधिक वाहनों और भारों के लिए oversize/overweight (OSOW) परमिट जारी करती है?","options":["SC Department of Motor Vehicles (SCDMV)","SC Department of Public Safety (SCDPS)","SC Department of Transportation (SCDOT)","SC Department of Revenue (SCDOR)"],"explanation":"South Carolina Department of Transportation (SCDOT) Oversize/Overweight Permit Office उन भारों के लिए अपने विवेक से OSOW परमिट जारी करता है जो कानूनी आकार या भार सीमाओं से अधिक होते हैं। स्रोत: SCDOT Oversize/Overweight Permits कार्यक्रम।"},"10":{"q":"South Carolina में किसी भार की चौड़ाई के लिए oversize परमिट आम तौर पर कब आवश्यक होता है?","options":["जब चौड़ाई 96 inches से अधिक हो","जब चौड़ाई 102 inches (8'6\") से अधिक हो","जब चौड़ाई 120 inches (10') से अधिक हो","जब चौड़ाई 144 inches (12') से अधिक हो"],"explanation":"क्योंकि South Carolina की कानूनी चौड़ाई सीमा 102 inches (8 feet 6 inches) है, उससे चौड़े किसी भी भार के लिए SCDOT oversize परमिट आवश्यक होता है। स्रोत: SC Code 56-5-4030; SCDOT OSOW परमिट दिशानिर्देश।"},"11":{"q":"कोई वाहक South Carolina का oversize/overweight परमिट कैसे प्राप्त कर सकता है?","options":["केवल SCDMV को कागजी फॉर्म डाक से भेजकर","SCDOT की ऑनलाइन SafeHaul प्रणाली के माध्यम से (या फोन/डाक/ईमेल से)","केवल किसी काउंटी कोर्टहाउस में व्यक्तिगत रूप से","FMCSA राष्ट्रीय पोर्टल के माध्यम से"],"explanation":"वाहक SCDOT की ऑनलाइन SafeHaul (iHaul) प्रणाली के माध्यम से, या SCDOT OSOW Permit Office से फोन, डाक या ईमेल द्वारा संपर्क करके OSOW परमिट प्राप्त करते हैं। स्रोत: SCDOT Oversize/Overweight Permits पेज (SafeHaul)।"},"12":{"q":"South Carolina की कृषि/वानिकी छूट के तहत, स्व-चालित कृषि उपकरण और वानिकी मशीनरी दिन के उजाले में oversize परमिट के बिना तभी चल सकती है जब वे किस चौड़ाई से अधिक न हों?","options":["8 feet 6 inches","10 feet","12 feet","14 feet"],"explanation":"South Carolina कृषि उपकरण, वानिकी मशीनरी और समान उपकरणों को दिन के उजाले में बिना परमिट के चलने की अनुमति देता है यदि वे 12 feet चौड़ाई, 13 feet 6 inches ऊंचाई, या 90,000 pounds से अधिक न हों। स्रोत: SCDOT OSOW दिशानिर्देश (कृषि/वानिकी छूट)।"},"13":{"q":"South Carolina के दो-लेन वाले राजमार्ग पर, किस चौड़ाई पर परमिट प्राप्त भार के लिए आगे एस्कॉर्ट (पायलट) वाहन की आवश्यकता शुरू हो जाती है?","options":["10 feet से अधिक","12 feet से अधिक","14 feet से अधिक","16 feet से अधिक"],"explanation":"दो-लेन वाले राजमार्गों पर, South Carolina 12 feet से अधिक और 14 feet चौड़ाई तक के भारों के लिए आगे एस्कॉर्ट की मांग करता है; 14 feet से अधिक और 16 feet तक के भारों के लिए आगे और पीछे दोनों एस्कॉर्ट आवश्यक हैं। स्रोत: SCDOT OSOW एस्कॉर्ट/पायलट-कार आवश्यकताएं।"},"14":{"q":"South Carolina में 53-foot सेमीट्रेलर के लिए, किंगपिन से पीछे के एक्सल (या पीछे के टैंडम असेंबली) के केंद्र तक की दूरी किस मान से अधिक नहीं हो सकती?","options":["37 feet","41 feet","43 feet","46 feet"],"explanation":"South Carolina Code 56-5-4070 के अनुसार 53-foot ट्रेलर पर किंगपिन-से-पीछे-एक्सल (या पीछे के टैंडम केंद्र) की दूरी 41 feet से अधिक नहीं होनी चाहिए। स्रोत: SC Code 56-5-4070।"},"15":{"q":"South Carolina गैर-Interstate राजमार्गों पर भार सीमाओं पर आम तौर पर कितनी प्रवर्तन सहनशीलता लागू करता है?","options":["5 प्रतिशत","10 प्रतिशत","15 प्रतिशत","कोई सहनशीलता अनुमत नहीं है"],"explanation":"South Carolina गैर-Interstate (राज्य और अनुपूरक) राजमार्गों पर भार सीमाओं पर 10% प्रवर्तन सहनशीलता लागू करता है। Interstate भारों को निर्धारित सहनशीलताओं के भीतर अधिक सख्ती से प्रवर्तित किया जाता है। स्रोत: SCDOT/SCDMV size-weight मार्गदर्शन; SC Code 56-5-4140।"},"16":{"q":"South Carolina में 14-foot ऊंचाई के अपवाद के तहत, ऑटोमोबाइल ट्रांसपोर्टर या सैडल-माउंट संयोजन के पास अतिरिक्त रूप से क्या होना चाहिए?","options":["FMCSA से छूट","SCDOT द्वारा जारी एक वैध रूटिंग परमिट","एक हानिकारक सामग्री समर्थन (एंडोर्समेंट)","काउंटी शेरिफ से लिखित अनुमोदन"],"explanation":"South Carolina Code 56-5-4060 ऑटो ट्रांसपोर्टर यूनिट या सैडल-माउंट संयोजन के लिए 14 feet तक की अनुमति केवल तभी देता है जब मालिक/संचालक के पास SCDOT द्वारा जारी एक वैध रूटिंग परमिट हो। स्रोत: SC Code 56-5-4060।"},"17":{"q":"South Carolina में किसी मोटर होम के लिए अनुमत अधिकतम लंबाई कितनी है, बशर्ते उसका टर्निंग रेडियस 48 feet या उससे कम हो?","options":["40 feet","42 feet","45 feet","48 feet"],"explanation":"South Carolina Code 56-5-4070 किसी मोटर होम को 45 feet तक की लंबाई की अनुमति देता है यदि उसका टर्निंग रेडियस 48 feet या उससे कम हो, जो सामान्य 40-foot एकल-वाहन सीमा का एक अपवाद है। स्रोत: SC Code 56-5-4070।"},"18":{"q":"गैर-व्यावसायिक उपयोग में मोटर होम, ट्रैवल ट्रेलर और ट्रक कैंपर पर लगे उपांग (अपर्टिनेंस) South Carolina में कानूनी चौड़ाई से कितना आगे निकल सकते हैं?","options":["प्रत्येक तरफ 3 inches तक","एक तरफ 6 inches और दूसरी तरफ 4 inches तक","केवल एक तरफ 12 inches तक","कानूनी चौड़ाई से कोई विस्तार अनुमत नहीं है"],"explanation":"South Carolina Code 56-5-4030 गैर-व्यावसायिक मोटर होम, ट्रैवल ट्रेलर और ट्रक कैंपर पर लगे उपांगों को 102-inch चौड़ाई सीमा से एक तरफ अधिकतम 6 inches और दूसरी तरफ 4 inches आगे निकलने की अनुमति देता है। स्रोत: SC Code 56-5-4030।"},"19":{"q":"किसी मानक चौड़े भार के लिए एक सामान्य एकल-यात्रा SCDOT oversize/overweight परमिट की लागत लगभग कितनी होती है?","options":["$10","$30","$75","$150"],"explanation":"SCDOT एक मानक एकल-यात्रा OSOW परमिट के लिए लगभग $30 शुल्क लेता है, एक वार्षिक (कई-यात्रा) परमिट लगभग $100 का होता है; 16 feet से अधिक की अत्यधिक चौड़ाइयों पर अधिक शुल्क लागू होते हैं। स्रोत: SCDOT Oversize/Overweight Permits शुल्क सूची।"},"20":{"q":"South Carolina में, 26,001 pounds या उससे अधिक के Gross Combination Weight Rating (GCWR) वाले वाहनों के संयोजन को चलाने के लिए कौन-सा CDL वर्ग आवश्यक है, जहां खींची जा रही यूनिट का GVWR 10,000 pounds से अधिक हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"South Carolina (SCDMV, Classes A, B, और C) एक Class A CDL को वाहनों के किसी भी संयोजन के रूप में परिभाषित करता है जिसका GCWR 26,001 lbs या उससे अधिक हो, बशर्ते खींचे जा रहे वाहन का GVWR 10,000 lbs से अधिक हो। स्रोत: SCDMV Commercial Licenses, Classes A, B, और C।"},"21":{"q":"SCDMV के अनुसार, 26,001 pounds या उससे अधिक GVWR वाले एकल-यूनिट वाहन (जो 10,000 lbs से अधिक कुछ नहीं खींच रहा हो) के लिए कौन-सा CDL वर्ग आवश्यक है?","options":["Class C","Class B","Class A","Class E"],"explanation":"South Carolina एक Class B CDL को 26,001 lbs या उससे अधिक GVWR वाले किसी भी एकल-यूनिट वाहन के रूप में, या ऐसे वाहन के रूप में जो 10,000 lbs से अधिक भार वाली यूनिट न खींच रहा हो, परिभाषित करता है। स्रोत: SCDMV Commercial Licenses, Classes A, B, और C।"},"22":{"q":"South Carolina के नियमों के तहत, ऐसा वाहन जो Class A या B भार सीमाओं को पूरा नहीं करता लेकिन 16 या अधिक व्यक्तियों (चालक सहित) को ले जाने के लिए डिज़ाइन किया गया है, उसके लिए कौन-सा CDL वर्ग आवश्यक है?","options":["Class A","Class B","Class C","किसी CDL की आवश्यकता नहीं है"],"explanation":"South Carolina एक Class C CDL को ऐसे किसी एकल वाहन, या संयोजन, के रूप में परिभाषित करता है जो Class A या B नहीं है लेकिन चालक सहित 16 या अधिक व्यक्तियों को ले जाने के लिए डिज़ाइन किया गया है, या प्लेकार्ड वाली हानिकारक सामग्रियों के परिवहन के लिए उपयोग किया जाता है। स्रोत: SCDMV Commercial Licenses, Classes A, B, और C।"},"23":{"q":"South Carolina में, INTRASTATE ड्राइविंग (केवल राज्य के भीतर संचालन) के लिए CDL प्राप्त करने हेतु न्यूनतम आयु क्या है?","options":["16 वर्ष","17 वर्ष","18 वर्ष","21 वर्ष"],"explanation":"SCDMV आवेदकों को South Carolina के भीतर (intrastate) व्यावसायिक रूप से वाहन चलाने के लिए कम से कम 18 वर्ष का होना आवश्यक करता है। 21 वर्ष से कम आयु के चालक राज्य के बाहर वाहन नहीं चला सकते। स्रोत: SCDMV, Getting Your First CDL।"},"24":{"q":"South Carolina में INTERSTATE ड्राइविंग (राज्य की सीमाओं के पार) के लिए वैध CDL रखने हेतु न्यूनतम आयु क्या है?","options":["18 वर्ष","19 वर्ष","21 वर्ष","25 वर्ष"],"explanation":"SCDMV चालकों को South Carolina के बाहर (interstate) वाणिज्यिक वाहन चलाने के लिए कम से कम 21 वर्ष का होना आवश्यक करता है। 18-20 वर्ष के चालक केवल intrastate संचालन तक सीमित हैं। स्रोत: SCDMV, Getting Your First CDL।"},"25":{"q":"South Carolina का कोई आवेदक CDL कौशल (रोड) परीक्षा देने से पहले, उसे अपना Commercial Learner Permit (CLP) कितने समय तक रखना आवश्यक है?","options":["कम से कम 7 कैलेंडर दिन","कम से कम 14 कैलेंडर दिन","कम से कम 30 कैलेंडर दिन","कम से कम 60 कैलेंडर दिन"],"explanation":"South Carolina संघीय नियम का पालन करता है जिसके लिए आवेदक द्वारा CDL कौशल परीक्षा देने से पहले CLP को कम से कम 14 कैलेंडर दिनों तक रखना आवश्यक है। स्रोत: SCDMV, Getting Your First CDL (49 CFR 383.25)।"},"26":{"q":"प्लेकार्ड वाली हानिकारक सामग्रियों का परिवहन करने वाले वाहन को चलाने के प्राधिकरण के लिए South Carolina किस एंडोर्समेंट कोड का उपयोग करता है?","options":["N","T","H","P"],"explanation":"H एंडोर्समेंट प्लेकार्ड की आवश्यकता वाली हानिकारक सामग्रियों को कवर करता है। South Carolina मानक संघीय एंडोर्समेंट कोड का उपयोग करता है: H (HazMat), N (Tank), T (Doubles/Triples), P (Passenger), S (School Bus)। स्रोत: SCDMV Commercial Licenses।"},"27":{"q":"South Carolina में, HazMat (H) एंडोर्समेंट जारी या नवीनीकृत किए जाने से पहले, आवेदक को किस अतिरिक्त जांच को पास करना होता है?","options":["एक TSA सुरक्षा खतरा आकलन (पृष्ठभूमि जांच और फिंगरप्रिंटिंग)","एक शारीरिक चपलता और उठाने की परीक्षा","एक रक्षात्मक ड्राइविंग पाठ्यक्रम प्रमाणन","SCDMV द्वारा संचालित एक दृष्टि परीक्षा"],"explanation":"South Carolina HazMat (H) आवेदकों को मूल और नवीनीकरण दोनों एंडोर्समेंट के लिए एक संघीय Transportation Security Administration (TSA) सुरक्षा खतरा आकलन पास करना आवश्यक करता है, जिसमें फिंगरप्रिंटिंग और एक पृष्ठभूमि जांच शामिल है। स्रोत: SCDMV; 49 CFR 1572।"},"28":{"q":"South Carolina में बल्क टैंक में तरल या गैस का परिवहन करने के लिए डिज़ाइन किए गए वाणिज्यिक वाहन को चलाने के लिए कौन-सा एंडोर्समेंट आवश्यक है?","options":["P (Passenger)","N (Tank Vehicle)","T (Doubles/Triples)","S (School Bus)"],"explanation":"संघीय परिभाषा को पूरा करने वाले बल्क टैंक में तरल या गैस ढोने वाले वाहन को चलाने के लिए N (Tank Vehicle) एंडोर्समेंट आवश्यक है। स्रोत: SCDMV Commercial Licenses; 49 CFR 383.93।"},"29":{"q":"South Carolina में डबल या ट्रिपल ट्रेलर खींचने के लिए कौन-सा एंडोर्समेंट आवश्यक है?","options":["T एंडोर्समेंट","N एंडोर्समेंट","H एंडोर्समेंट","X एंडोर्समेंट"],"explanation":"T एंडोर्समेंट डबल और ट्रिपल ट्रेलरों के संचालन को प्राधिकृत करता है। South Carolina मानक संघीय कोड का उपयोग करता है। स्रोत: SCDMV Commercial Licenses; 49 CFR 383.93।"},"30":{"q":"आवश्यक सीमा संख्या में यात्रियों को ले जाने के लिए डिज़ाइन की गई वाणिज्यिक बस या वैन को चलाने के लिए South Carolina के चालक को कौन-सा एंडोर्समेंट प्राप्त करना होगा?","options":["S (School Bus)","P (Passenger)","N (Tank)","T (Doubles/Triples)"],"explanation":"चालक सहित 16 या अधिक व्यक्तियों के परिवहन के लिए डिज़ाइन किए गए वाहन को चलाने के लिए P (Passenger) एंडोर्समेंट आवश्यक है। स्कूल बसों के लिए एक अलग S एंडोर्समेंट की आवश्यकता होती है। स्रोत: SCDMV Commercial Licenses।"},"31":{"q":"South Carolina में, ऐसी स्कूल बस को चलाने के लिए जिसके लिए CDL आवश्यक हो, चालक को क्या चाहिए?","options":["केवल P (Passenger) एंडोर्समेंट","P (Passenger) और S (School Bus) दोनों एंडोर्समेंट","केवल H (HazMat) एंडोर्समेंट","कोई एंडोर्समेंट नहीं, बस एक Class B CDL"],"explanation":"South Carolina में स्कूल बस चलाने के लिए, चालक के पास P (Passenger) और S (School Bus) दोनों एंडोर्समेंट होने चाहिए, और उसे स्कूल बस ज्ञान और कौशल परीक्षाएं पास करनी होंगी। स्रोत: SCDMV Commercial Licenses; 49 CFR 383.93।"},"32":{"q":"ऐसे South Carolina CLP/CDL आवेदक के लिए, जिसने अपना परमिट February 7, 2022 को या उसके बाद प्राप्त किया, पहले CDL के लिए कौशल परीक्षा से पहले कौन-सा प्रशिक्षण पूरा करना आवश्यक है?","options":["केवल-राज्य SCDMV कक्षा पाठ्यक्रम","किसी पंजीकृत प्रदाता से FMCSA-अनुमोदित Entry-Level Driver Training (ELDT)","SCDMV के साथ दर्ज 160-घंटे की अप्रेंटिसशिप","किसी प्रशिक्षण की आवश्यकता नहीं, केवल कौशल परीक्षा"],"explanation":"South Carolina उन आवेदकों को, जिन्होंने Feb 7, 2022 को या उसके बाद CLP प्राप्त किया, कौशल परीक्षा देने से पहले FMCSA Training Provider Registry पर सूचीबद्ध किसी प्रदाता से FMCSA-अनुमोदित Entry-Level Driver Training (ELDT) पूरी करना आवश्यक करता है। स्रोत: SCDMV, Getting Your First CDL; FMCSA ELDT नियम।"},"33":{"q":"South Carolina में लागू संघीय ELDT नियम के तहत, ELDT पहले CDL के लिए और किस एंडोर्समेंट समूह के लिए आवश्यक है?","options":["H (HazMat), P (Passenger), और S (School Bus)","N (Tank), T (Doubles/Triples), और H (HazMat)","P (Passenger), N (Tank), और T (Doubles/Triples)","सभी पाँच एंडोर्समेंट (H, N, T, P, S)"],"explanation":"ELDT एक प्रारंभिक Class A या B CDL, एक अपग्रेड, और HazMat (H), Passenger (P), और School Bus (S) एंडोर्समेंट के लिए आवश्यक है। यह N (Tank) या T (Doubles/Triples) एंडोर्समेंट के लिए आवश्यक नहीं है। स्रोत: FMCSA ELDT नियम; SCDMV।"},"34":{"q":"South Carolina के CDL आवेदक को, जिस प्रकार के व्यापार में वे संचालन करते हैं उसे प्रमाणित करते समय, कितनी चिकित्सा स्व-प्रमाणन श्रेणियों में से चुनना होता है?","options":["दो","तीन","चार","पाँच"],"explanation":"South Carolina द्वारा अपनाए गए संघीय नियम CDL धारकों को चार श्रेणियों में से एक में स्व-प्रमाणित करना आवश्यक करते हैं: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, या Excepted Intrastate। स्रोत: SCDMV; 49 CFR 383.71।"},"35":{"q":"ऐसा South Carolina CDL चालक जो राज्य की सीमाओं के पार माल ढोता है और जिसे संघीय DOT शारीरिक मानकों को पूरा करना होता है, उसे किस श्रेणी में स्व-प्रमाणित करना चाहिए?","options":["Excepted Interstate","Non-Excepted Interstate","Non-Excepted Intrastate","Excepted Intrastate"],"explanation":"अंतरराज्यीय वाणिज्य में संचालन करने वाला चालक जो संघीय शारीरिक योग्यता मानकों (49 CFR Part 391) के अधीन है और उन्हें पूरा करना होता है, वह Non-Excepted Interstate के रूप में प्रमाणित होता है और उसे एक वैध मेडिकल एग्जामिनर सर्टिफिकेट रखना होता है। स्रोत: SCDMV; 49 CFR 383.71।"},"36":{"q":"निम्नलिखित में से कौन-सा दस्तावेज़ उन दस्तावेज़ों में शामिल नहीं है जिन्हें SCDMV पहली बार CDL आवेदक से पहचान, सामाजिक सुरक्षा, निवास, और वैध उपस्थिति सत्यापन के लिए मांगता है?","options":["पहचान और जन्म तिथि का प्रमाण","सामाजिक सुरक्षा संख्या का प्रमाण","South Carolina निवास के दो प्रमाण","किसी ट्रकिंग कंपनी से रोजगार का हस्ताक्षरित पत्र"],"explanation":"SCDMV पहचान/वैध उपस्थिति का प्रमाण, एक सामाजिक सुरक्षा संख्या, और South Carolina निवास (दस्तावेज़ चेकलिस्ट के अनुसार, जैसे Form MV-93) मांगता है। एक नियोक्ता पत्र आवश्यक पहचान/निवास दस्तावेज़ नहीं है। स्रोत: SCDMV, Getting Your First CDL दस्तावेज़ चेकलिस्ट।"},"37":{"q":"South Carolina में, कौन-से आवेदक CDL HazMat (H) एंडोर्समेंट के लिए आवेदन करने के पात्र हैं?","options":["कोई भी CDL धारक, नागरिकता की परवाह किए बिना","केवल U.S. नागरिक और वैध स्थायी निवासी","केवल 25 वर्ष और उससे अधिक आयु के चालक","केवल वे चालक जिनके पास पहले से संयुक्त X एंडोर्समेंट है"],"explanation":"TSA सुरक्षा खतरा आकलन के कारण, South Carolina में केवल U.S. नागरिक और वैध स्थायी निवासी ही CDL HazMat (H) एंडोर्समेंट के पात्र हैं। स्रोत: SCDMV; TSA HME कार्यक्रम (49 CFR 1572)।"},"38":{"q":"South Carolina का कोई चालक केवल Commercial Learner Permit (CLP) रखते हुए कौन-से एंडोर्समेंट प्राप्त कर सकता है?","options":["केवल H (HazMat) और T (Doubles/Triples)","केवल N (Tank), P (Passenger), और S (School Bus)","सभी पाँच एंडोर्समेंट","कोई नहीं - CLP पर किसी एंडोर्समेंट की अनुमति नहीं है"],"explanation":"एक South Carolina CLP में केवल N (Tank, खाली टैंकों तक सीमित), P (Passenger, प्रशिक्षकों/परीक्षकों के अलावा कोई यात्री नहीं), और S (School Bus) एंडोर्समेंट हो सकते हैं। H और T एंडोर्समेंट CLP पर नहीं रखे जा सकते। स्रोत: SCDMV, Getting Your First CDL; 49 CFR 383.25।"},"39":{"q":"South Carolina में, CDL पर संयुक्त 'X' एंडोर्समेंट क्या दर्शाता है?","options":["Tank (N) और HazMat (H) दोनों संचालनों के लिए प्राधिकरण","Doubles/Triples (T) और Passenger (P) के लिए प्राधिकरण","अंतरराज्यीय ड्राइविंग को प्रतिबंधित करने वाली एक रोक","एक स्कूल बस संचालक प्रमाणन"],"explanation":"X एंडोर्समेंट एक संयुक्त कोड है जो दर्शाता है कि चालक के पास Tank (N) और HazMat (H) दोनों एंडोर्समेंट हैं, जो टैंक वाहन में हानिकारक सामग्रियों के परिवहन की अनुमति देता है। स्रोत: SCDMV Commercial Licenses; 49 CFR 383.153।"},"40":{"q":"South Carolina में, वह अधिकतम रक्त अल्कोहल सांद्रता (BAC) क्या है जिस पर वाणिज्यिक मोटर वाहन (CMV) चलाना कानूनी है?","options":["0.04% से नीचे","0.08% से नीचे","0.02% से नीचे","0.05% से नीचे"],"explanation":"South Carolina संघीय CMV मानक का पालन करता है: यदि आपका BAC 0.04% या उससे अधिक है तो CMV चलाना अवैध है, इसलिए कानूनी संचालन के लिए 0.04% से नीचे का BAC आवश्यक है। स्रोत: SCDMV Commercial Driver's License Manual, Section 1.3.2 (49 CFR 383.51)।"},"41":{"q":"South Carolina के CMV संचालकों के लिए निहित-सहमति नियम के तहत, यदि किसी चालक में 0.04% से नीचे की पता लगाने योग्य मात्रा में अल्कोहल हो तो क्या होता है?","options":["24 घंटे के लिए सेवा-से-बाहर (out-of-service) रखा जाता है","60 दिनों के लिए अयोग्य","एक वर्ष के लिए अयोग्य","कोई कार्रवाई किए बिना केवल चेतावनी जारी की जाती है"],"explanation":"South Carolina किसी CMV चालक को 24 घंटे के लिए सेवा-से-बाहर रखता है यदि 0.04% से कम कोई भी पता लगाने योग्य मात्रा में अल्कोहल पाया जाता है। 0.04% या उससे अधिक का BAC इसके बजाय अयोग्यता को ट्रिगर करता है। स्रोत: SCDMV CDL Manual, Section 1.3.2।"},"42":{"q":"South Carolina में CMV चलाकर, किसी चालक को रासायनिक परीक्षण के संबंध में स्वचालित रूप से क्या किया हुआ माना जाता है?","options":["अल्कोहल परीक्षण के लिए सहमति दी हुई","सुनवाई के अधिकार का त्याग किया हुआ","वार्षिक ड्रग स्क्रीनिंग पर सहमत हुआ","वाहन की तलाशी के लिए सहमति दी हुई"],"explanation":"निहित सहमति के तहत, South Carolina में CMV चलाने वाले किसी भी व्यक्ति को अल्कोहल परीक्षण के लिए सहमति दिया हुआ माना जाता है। स्रोत: SCDMV CDL Manual, Section 1.3.2।"},"43":{"q":"South Carolina में किसी CMV चालक के पहले गंभीर अपराध के लिए, जैसे DUI या 0.04% या उससे अधिक BAC के साथ CMV चलाना, न्यूनतम अयोग्यता अवधि क्या है?","options":["1 वर्ष","60 दिन","6 महीने","3 वर्ष"],"explanation":"एक पहला गंभीर अपराध (DUI, CMV में 0.04%+ BAC, परीक्षण से इनकार, घटनास्थल छोड़ना, आदि) South Carolina में कम से कम एक वर्ष की न्यूनतम अयोग्यता वहन करता है। स्रोत: SCDMV CDL Manual, Section 1.3.2 (49 CFR 383.51)।"},"44":{"q":"South Carolina में, यदि कोई गंभीर अपराध (जैसे DUI) तब होता है जब चालक हानिकारक सामग्रियों के लिए प्लेकार्ड वाला CMV चला रहा हो, तो न्यूनतम अयोग्यता अवधि क्या है?","options":["3 वर्ष","1 वर्ष","5 वर्ष","18 महीने"],"explanation":"South Carolina पहले-अपराध की अयोग्यता को कम से कम तीन वर्ष तक बढ़ा देता है जब गंभीर अपराध हानिकारक सामग्रियों के लिए प्लेकार्ड वाला CMV चलाते समय होता है। स्रोत: SCDMV CDL Manual, Section 1.3.2 (49 CFR 383.51)।"},"45":{"q":"South Carolina में किसी CMV चालक के दूसरे गंभीर अपराध के लिए अयोग्यता अवधि क्या है?","options":["आजीवन","10 वर्ष","5 वर्ष","3 वर्ष"],"explanation":"एक दूसरे गंभीर अपराध के परिणामस्वरूप South Carolina में आजीवन CDL का नुकसान होता है। स्रोत: SCDMV CDL Manual, Section 1.3.2 (49 CFR 383.51)।"},"46":{"q":"South Carolina में, CMV संचालक के रूप में रक्त अल्कोहल परीक्षण कराने से इनकार करना अयोग्यता के उद्देश्यों के लिए किस प्रकार के अपराध के रूप में माना जाता है?","options":["एक गंभीर अपराध (कम से कम 1 वर्ष)","एक गंभीर यातायात उल्लंघन (60 दिन)","एक सेवा-से-बाहर उल्लंघन (90 दिन)","बिना किसी अयोग्यता वाला एक छोटा अपराध"],"explanation":"रक्त अल्कोहल परीक्षण कराने से इनकार करना South Carolina में एक गंभीर अपराध (major offense) के रूप में सूचीबद्ध है और पहले अपराध के लिए न्यूनतम एक-वर्ष की अयोग्यता वहन करता है, जो DUI के समान है। स्रोत: SCDMV CDL Manual, Section 1.3.2।"},"47":{"q":"South Carolina के नियमों के तहत, यदि किसी अपराध को करने के लिए CMV का उपयोग किया जाता है तो CMV चालक पहले अपराध के लिए आजीवन CDL खो देता है, यह किस प्रकार का अपराध है?","options":["नियंत्रित पदार्थों से जुड़ा एक गुनाह (felony)","किसी भी प्रकार का कोई भी गुनाह","चोरी से जुड़ा एक गुनाह","चोट पहुंचाने वाली लापरवाह ड्राइविंग"],"explanation":"नियंत्रित पदार्थों से जुड़े किसी गुनाह को करने के लिए CMV का उपयोग करने के परिणामस्वरूप पहले अपराध पर आजीवन अयोग्यता होती है, जिसमें अन्य आजीवन मामलों के लिए उपलब्ध 10-वर्ष की पुनर्बहाली की कोई संभावना नहीं होती। स्रोत: SCDMV CDL Manual, Section 1.3.2।"},"48":{"q":"South Carolina में, किसी CMV चालक को पोस्ट की गई गति सीमा से कितना तेज़ चलना चाहिए ताकि उल्लंघन 'अत्यधिक तेज़ गति' प्रकार के गंभीर यातायात उल्लंघन के रूप में गिना जाए?","options":["सीमा से 15 mph या अधिक","सीमा से 10 mph या अधिक","सीमा से 20 mph या अधिक","सीमा से 5 mph या अधिक"],"explanation":"South Carolina अत्यधिक तेज़ गति को एक गंभीर यातायात उल्लंघन के रूप में परिभाषित करता है जब चालक पोस्ट की गई गति सीमा से 15 mph या अधिक ऊपर हो। स्रोत: SCDMV CDL Manual, Section 1.3.3।"},"49":{"q":"South Carolina में किसी CMV चालक के लिए निम्नलिखित में से किसे एक गंभीर यातायात उल्लंघन के रूप में वर्गीकृत किया गया है?","options":["अनुचित या अनियमित लेन परिवर्तन","0.04% या उससे अधिक BAC के साथ ड्राइविंग","रासायनिक परीक्षण से इनकार करना","सेवा-से-बाहर आदेश का उल्लंघन करना"],"explanation":"गंभीर यातायात उल्लंघनों में अत्यधिक तेज़ गति (15+ mph ऊपर), लापरवाह ड्राइविंग, अनुचित या अनियमित लेन परिवर्तन, बहुत निकट से पीछा करना, और कुछ CDL-धारण अपराध शामिल हैं। अन्य विकल्प गंभीर (major) या सेवा-से-बाहर अपराध हैं। स्रोत: SCDMV CDL Manual, Section 1.3.3।"},"50":{"q":"South Carolina में, तीन-वर्ष की अवधि के भीतर CMV में दो गंभीर यातायात उल्लंघन करने के लिए न्यूनतम अयोग्यता क्या है?","options":["60 दिन","30 दिन","120 दिन","90 दिन"],"explanation":"तीन वर्षों के भीतर CMV से जुड़े दो गंभीर यातायात उल्लंघनों के परिणामस्वरूप कम से कम 60 दिनों की अयोग्यता होती है। स्रोत: SCDMV CDL Manual, Section 1.3.3 (49 CFR 383.51)।"},"51":{"q":"South Carolina में, तीन-वर्ष की अवधि के भीतर CMV में तीन या अधिक गंभीर यातायात उल्लंघनों के लिए न्यूनतम अयोग्यता क्या है?","options":["120 दिन","60 दिन","180 दिन","1 वर्ष"],"explanation":"तीन वर्षों के भीतर CMV से जुड़े तीन या अधिक गंभीर यातायात उल्लंघनों के परिणामस्वरूप कम से कम 120 दिनों की अयोग्यता होती है। स्रोत: SCDMV CDL Manual, Section 1.3.3 (49 CFR 383.51)।"},"52":{"q":"South Carolina में किसी चालक द्वारा सेवा-से-बाहर आदेश के पहले उल्लंघन के लिए न्यूनतम अयोग्यता क्या है?","options":["90 दिन","60 दिन","180 दिन","1 वर्ष"],"explanation":"सेवा-से-बाहर आदेश का पहला उल्लंघन South Carolina में न्यूनतम 90-दिन की अयोग्यता वहन करता है। स्रोत: SCDMV CDL Manual, Section 1.3.4 (49 CFR 383.51)।"},"53":{"q":"South Carolina में, दस-वर्ष की अवधि के भीतर सेवा-से-बाहर आदेश के दूसरे उल्लंघन के लिए न्यूनतम अयोग्यता क्या है?","options":["1 वर्ष","90 दिन","120 दिन","3 वर्ष"],"explanation":"दस-वर्ष की अवधि के भीतर सेवा-से-बाहर आदेश के दूसरे उल्लंघन के परिणामस्वरूप कम से कम एक वर्ष की अयोग्यता होती है। स्रोत: SCDMV CDL Manual, Section 1.3.4।"},"54":{"q":"South Carolina में, दस-वर्ष की अवधि के भीतर सेवा-से-बाहर आदेश के तीन या अधिक उल्लंघनों के लिए न्यूनतम अयोग्यता क्या है?","options":["3 वर्ष","1 वर्ष","5 वर्ष","आजीवन"],"explanation":"दस-वर्ष की अवधि के भीतर सेवा-से-बाहर आदेश के तीन या अधिक उल्लंघनों के परिणामस्वरूप कम से कम तीन वर्ष की अयोग्यता होती है। स्रोत: SCDMV CDL Manual, Section 1.3.4।"},"55":{"q":"South Carolina में किसी CMV चालक के पहले रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए न्यूनतम अयोग्यता क्या है?","options":["60 दिन","90 दिन","30 दिन","120 दिन"],"explanation":"एक पहला रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन South Carolina में कम से कम 60 दिनों की अयोग्यता में परिणत होता है। स्रोत: SCDMV CDL Manual, Section 1.3.5 (49 CFR 383.51)।"},"56":{"q":"South Carolina में, तीन-वर्ष की अवधि के भीतर दूसरे रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए न्यूनतम अयोग्यता क्या है?","options":["120 दिन","60 दिन","90 दिन","1 वर्ष"],"explanation":"तीन वर्षों के भीतर एक दूसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन कम से कम 120 दिनों की अयोग्यता में परिणत होता है। स्रोत: SCDMV CDL Manual, Section 1.3.5।"},"57":{"q":"South Carolina में, तीन-वर्ष की अवधि के भीतर तीसरे रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए न्यूनतम अयोग्यता क्या है?","options":["1 वर्ष","120 दिन","180 दिन","3 वर्ष"],"explanation":"तीन वर्षों के भीतर एक तीसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन कम से कम एक वर्ष की अयोग्यता में परिणत होता है। स्रोत: SCDMV CDL Manual, Section 1.3.5।"},"58":{"q":"South Carolina के नियमों के तहत, CMV चलाते समय टेक्स्टिंग के लिए तीन वर्षों के भीतर दूसरी बार दोषी पाए जाने के बाद किसी CMV चालक का CDL कितने समय के लिए अयोग्य घोषित किया जाता है?","options":["60 दिन","30 दिन","120 दिन","1 वर्ष"],"explanation":"CMV चलाते समय टेक्स्टिंग के लिए दो या अधिक दोषसिद्धियां अयोग्यता को ट्रिगर करती हैं: तीन वर्षों के भीतर दूसरे अपराध के लिए 60 दिन और तीन वर्षों के भीतर तीन या अधिक के लिए 120 दिन। चालकों को $2,750 तक के नागरिक दंड का भी सामना करना पड़ता है। स्रोत: SCDMV CDL Manual, Sections 2.9.6 और 2.9.5।"},"59":{"q":"South Carolina के Hands-Free and Distracted Driving Act के तहत, ड्राइविंग के दौरान मोबाइल डिवाइस पकड़ने के पहले अपराध के लिए जुर्माना क्या है?","options":["$100 plus court fees","$25 plus court fees","$200 plus court fees","$500 plus court fees"],"explanation":"South Carolina का Hands-Free and Distracted Driving Act (S.C. Code Section 56-5-3890) पहले अपराध के लिए $100 जुर्माना plus court fees और तीन वर्षों के भीतर दूसरे अपराध के लिए $200 plus दो अंक निर्धारित करता है; CMV चालकों के लिए तीन वर्षों के भीतर दो दोषसिद्धियां 60-दिन की अयोग्यता भी लाती हैं। स्रोत: SCDPS Hands Free SC; S.C. Code 56-5-3890।"},"60":{"q":"साउथ कैरोलिना के इंटरस्टेट पर, ऐसे कमर्शियल ट्रक के लिए अधिकतम गति सीमा क्या है जिसके लिए अन्यथा कोई कम सीमा पोस्ट न की गई हो?","options":["65 mph, क्योंकि ट्रकों की सीमा कारों से कम होती है","70 mph, अन्य वाहनों के समान ही","इंटरस्टेट के सभी हिस्सों पर 60 mph","26,001 lbs से अधिक वजन वाले किसी भी वाहन के लिए 55 mph"],"explanation":"साउथ कैरोलिना ट्रकों के लिए कोई अलग, कम गति सीमा निर्धारित नहीं करता। S.C. Code 56-5-1520 के तहत, इंटरस्टेट हाईवे सिस्टम पर अधिकतम सीमा 70 mph है, और बड़े ट्रक उसी पोस्ट की गई सीमा से बंधे होते हैं। स्रोत: S.C. Code 56-5-1520; SCDMV CDL Manual।"},"61":{"q":"साउथ कैरोलिना कानून के तहत, किसी मल्टीलेन डिवाइडेड प्राइमरी हाईवे (इंटरस्टेट नहीं) पर अधिकतम गति सीमा क्या है, जब तक अन्यथा पोस्ट न की गई हो?","options":["55 mph","65 mph","60 mph","70 mph"],"explanation":"S.C. Code 56-5-1520 मल्टीलेन डिवाइडेड प्राइमरी हाईवे पर अधिकतम 60 mph, इंटरस्टेट सिस्टम पर 70 mph, और अन्य (अनडिवाइडेड) हाईवे पर 55 mph निर्धारित करता है। स्रोत: S.C. Code 56-5-1520।"},"62":{"q":"साउथ कैरोलिना का 'मूव ओवर' कानून (S.C. Code 56-5-1538) फ्लैशिंग लाइट दिखा रहे किसी रुके हुए आपातकालीन वाहन के पास पहुँचने वाले ड्राइवर से सबसे पहले क्या करने की अपेक्षा करता है, यदि इसे सुरक्षित रूप से किया जा सके?","options":["आपातकालीन वाहन के जाने तक पूरी तरह रुक जाना","किसी गैर-निकटवर्ती लेन में बदलकर आपातकालीन वाहन के सबसे नज़दीक वाली लेन को खाली कर देना","हॉर्न बजाना और पोस्ट की गई गति पर चलते रहना","आपातकालीन वाहन के पीछे शोल्डर पर खींच लेना"],"explanation":"S.C. Code 56-5-1538 के तहत, जब सुरक्षित हो तब ड्राइवर को रुके हुए अधिकृत आपातकालीन वाहन (एम्बुलेंस, पुलिस, फायर, रेस्क्यू, रिकवरी, या टोइंग वाहन) से निकटवर्ती न होने वाली लेन में बदलकर रास्ता देना चाहिए। स्रोत: S.C. Code 56-5-1538; SCDPS।"},"63":{"q":"साउथ कैरोलिना के मूव ओवर कानून के तहत, यदि किसी रुके हुए आपातकालीन वाहन से दूर लेन बदलना संभव या सुरक्षित न हो तो ड्राइवर को क्या करना चाहिए?","options":["वर्तमान लेन में पूरी तरह रुक जाना","पोस्ट की गई गति बनाए रखना लेकिन फोर-वे फ्लैशर्स चालू करना","सावधानी से आगे बढ़ना और गति को काफी हद तक कम करना","नज़दीकी रैंप पर निकल जाना और वैकल्पिक मार्ग लेना"],"explanation":"S.C. Code 56-5-1538 के अनुसार, जो ड्राइवर सुरक्षित रूप से लेन नहीं बदल सकता, उसे उचित सावधानी से आगे बढ़ना चाहिए और वाहन की गति को काफी हद तक कम करना चाहिए, सड़क की परिस्थितियों के लिए सुरक्षित गति बनाए रखते हुए। स्रोत: S.C. Code 56-5-1538; SCDPS।"},"64":{"q":"जब साउथ कैरोलिना में कोई प्लैकार्ड वाला वाहन रेलरोड क्रॉसिंग पर रुकता है, तो उसे सबसे नज़दीकी रेल के सापेक्ष कहाँ रुकना चाहिए?","options":["सबसे नज़दीकी रेल से 15 और 50 feet के बीच","सबसे नज़दीकी रेल से 10 और 25 feet के बीच","सबसे नज़दीकी रेल से 50 और 100 feet के बीच","सबसे नज़दीकी रेल के 15 feet के भीतर"],"explanation":"SCDMV CDL Manual और S.C. Code 56-5-2720 के अनुसार प्लैकार्ड वाले वाहन को सबसे नज़दीकी रेल से 50 feet के भीतर लेकिन 15 feet से कम नहीं रुकना चाहिए। स्रोत: SCDMV CDL Manual 9.6.12; S.C. Code 56-5-2720।"},"65":{"q":"साउथ कैरोलिना में निम्नलिखित में से किस वाहन को हर रेलरोड क्रॉसिंग पर हमेशा रुकना चाहिए (जब तक क्रॉसिंग छूट प्राप्त न हो)?","options":["एक लदा हुआ डंप ट्रक","यात्रियों को ले जाने वाली बस","एक खाली फ्लैटबेड ट्रेलर","यूटिलिटी ट्रेलर खींचता हुआ एक पिकअप"],"explanation":"यात्रियों को ले जाने वाली बस, स्कूल बस, और किसी भी प्लैकार्ड वाले/खतरनाक-कार्गो वाहन को हर रेलरोड क्रॉसिंग पर (सबसे नज़दीकी रेल से 15 से 50 feet) रुकना चाहिए और देखना तथा सुनना चाहिए। स्रोत: SCDMV CDL Manual; S.C. Code 56-5-2720।"},"66":{"q":"जब साउथ कैरोलिना में आपके कमर्शियल वाहन का कोई भी हिस्सा रेलरोड ट्रैक पार कर रहा हो, तो CDL Manual आपको निम्नलिखित में से क्या न करने का निर्देश देता है?","options":["अपने हाथ स्टीयरिंग व्हील पर रखना","ट्रैक के साथ दोनों दिशाओं में देखना","गियर शिफ्ट या बदलना","दूसरी ट्रेन के लिए सतर्क रहना"],"explanation":"SCDMV CDL Manual कहता है: जब आपके वाहन का कोई भी हिस्सा ट्रैक पार कर रहा हो तब न रुकें, न गियर बदलें, न लेन बदलें। ऐसा गियर चुनें जो आपको बिना शिफ्ट किए ट्रैक पार करने दे। स्रोत: SCDMV CDL Manual 2.15.4 / 13.1.8।"},"67":{"q":"साउथ कैरोलिना में, फ्लैशिंग लाल बत्तियाँ दिखा रही किसी रुकी हुई स्कूल बस से विपरीत दिशा में चलते हुए मिलने वाले ड्राइवर को किस प्रकार के मार्ग पर रुकने की आवश्यकता नहीं है?","options":["सेंटर टर्न लेन वाली कोई भी दो-लेन सड़क","एक मल्टी-लेन हाईवे","45 mph से ऊपर पोस्ट की गई सीमा वाली कोई भी सड़क","पेंट किए हुए (बिना उठे) मीडियन स्ट्राइप वाली सड़क"],"explanation":"S.C. Code 56-5-2770 के तहत, मल्टी-लेन हाईवे पर विपरीत दिशा में चलते हुए किसी रुकी हुई स्कूल बस से मिलने पर ड्राइवर को रुकने की आवश्यकता नहीं है। समान दिशा में चलने वाले ड्राइवरों को, और दो-लेन सड़कों पर, फिर भी रुकना चाहिए। स्रोत: S.C. Code 56-5-2770।"},"68":{"q":"साउथ कैरोलिना की किसी स्कूल बस के पीछे समान दिशा में चलते हुए ड्राइवर को, जिसने अपनी फ्लैशिंग लाल बत्तियाँ और स्टॉप आर्म सक्रिय कर रखी हो, क्या करना चाहिए?","options":["15 mph तक धीमा होना और सावधानी से गुज़रना","रुकना और तब तक रुके रहना जब तक बस आगे न बढ़े या लाल बत्तियाँ फ्लैश होना बंद न कर दें","केवल बायीं ओर से गुज़रना यदि कोई बच्चा दिखाई न दे","केवल तभी रुकना यदि बस किसी अनडिवाइडेड दो-लेन सड़क पर हो"],"explanation":"S.C. Code 56-5-2770 के अनुसार किसी भी दिशा से (विपरीत-दिशा मल्टी-लेन अपवाद को छोड़कर) आने वाले वाहन को फ्लैशिंग लाल बत्तियों वाली स्कूल बस तक पहुँचने से पहले रुकना चाहिए और तब तक आगे नहीं बढ़ना चाहिए जब तक बस फिर से चलना शुरू न कर दे या लाल बत्तियाँ अब सक्रिय न रहें। स्रोत: S.C. Code 56-5-2770।"},"69":{"q":"जब साउथ कैरोलिना में कोई CMV दोनों दिशाओं में यातायात वाली दो-लेन सड़क पर रुका हो, तो तीन चेतावनी ट्रायंगल कहाँ रखे जाने चाहिए?","options":["तीनों वाहन के पिछले हिस्से के 10 feet के भीतर","वाहन के 10 feet के भीतर, साथ ही 100 feet पीछे और 100 feet आगे","वाहन के पीछे 10 feet, 200 feet, और 500 feet","एक वाहन पर और दो अगल-बगल 50 feet पीछे"],"explanation":"किसी टू-वे/अनडिवाइडेड सड़क पर SCDMV CDL Manual एक ट्रायंगल आगे या पीछे के 10 feet के भीतर, और एक 100 feet पीछे तथा एक 100 feet वाहन के आगे रखने का निर्देश देता है। स्रोत: SCDMV CDL Manual 2.5 (Warning Devices)।"},"70":{"q":"जब साउथ कैरोलिना में कोई CMV किसी वन-वे या डिवाइडेड हाईवे पर रुका हो, तो चेतावनी उपकरण आने वाले यातायात की ओर किन दूरियों पर पीछे रखे जाने चाहिए?","options":["10 feet, 100 feet, और 200 feet","10 feet, 50 feet, और 100 feet","25 feet, 100 feet, और 300 feet","100 feet, 200 feet, और 300 feet"],"explanation":"किसी वन-वे या डिवाइडेड हाईवे पर SCDMV CDL Manual तीनों रिफ्लेक्टिव ट्रायंगल को आने वाले यातायात की ओर 10 feet, 100 feet, और 200 feet पर रखने का निर्देश देता है। स्रोत: SCDMV CDL Manual 2.5।"},"71":{"q":"साउथ कैरोलिना हाईवे के शोल्डर पर रुकने के बाद, किसी CMV ड्राइवर को कितने मिनटों के भीतर आपातकालीन चेतावनी उपकरण लगा देने चाहिए?","options":["5 मिनट","10 मिनट","15 मिनट","30 मिनट"],"explanation":"SCDMV CDL Manual कहता है कि यदि आपको सड़क या शोल्डर पर रुकना पड़े तो आपको 10 मिनट के भीतर अपने आपातकालीन चेतावनी उपकरण लगा देने चाहिए। स्रोत: SCDMV CDL Manual 2.5।"},"72":{"q":"नियंत्रित-पहुँच वाले हाईवे के लिए साउथ कैरोलिना का लेफ्ट-लेन ('मूव राइट') कानून आमतौर पर सबसे बायीं लेन को किस उपयोग तक सीमित करता है?","options":["पोस्ट की गई सीमा पर या उससे ऊपर चलने वाले वाहन","किसी अन्य वाहन को ओवरटेक करना और पास करना","केवल 10,000 lbs से कम वाहन","कारपूल और ट्रांज़िट वाहन"],"explanation":"S.C. Code 56-5-1885 के तहत, ड्राइवर किसी नियंत्रित-पहुँच वाले हाईवे की सबसे बायीं लेन का उपयोग केवल ओवरटेक और पास करते समय कर सकते हैं। स्रोत: S.C. Code 56-5-1885; SCDPS Move Right Law।"},"73":{"q":"साउथ कैरोलिना का लेफ्ट-लेन कानून किसी कमर्शियल मोटर वाहन को किस स्थिति के कारण विशिष्ट छूट देता है जब वह बायीं लेन से सुरक्षित रूप से बाहर नहीं निकल सकता?","options":["स्लीपर बर्थ में सोया हुआ एक यात्री","हाईवे की चढ़ाई, या दायीं ओर से गुज़रता हुआ कोई अन्य वाहन","खतरनाक-सामग्री प्लैकार्ड ले जाना","कम दृश्यता के साथ रात में संचालन करना"],"explanation":"S.C. Code 56-5-1885 के तहत, किसी CMV ड्राइवर को लेफ्ट-लेन प्रतिबंध से छूट दी जाती है जब वह हाईवे की चढ़ाई के कारण या इसलिए कि कोई अन्य वाहन दायीं ओर से ओवरटेक/पास कर रहा है, सुरक्षित रूप से दायीं ओर मर्ज नहीं कर सकता। स्रोत: S.C. Code 56-5-1885; SCDPS।"},"74":{"q":"साउथ कैरोलिना में बस चलाते हुए, आप एक ड्रॉब्रिज के पास पहुँचते हैं जिसमें कोई सिग्नल लाइट नहीं और कोई ट्रैफिक-कंट्रोल अटेंडेंट नहीं है। आपको क्या करना चाहिए?","options":["बिना रुके कम गति पर पार करना","ड्रॉ से कम से कम 50 feet पहले रुकना और पुष्टि करना कि यह पूरी तरह बंद है","ड्रॉ से 15 से 50 feet पहले रुकना","केवल तभी रुकना यदि चेतावनी घंटी बज रही हो"],"explanation":"SCDMV CDL Manual (4.3.6) बस ड्राइवरों को ऐसे ड्रॉब्रिज पर रुकने का निर्देश देता है जिनमें कोई सिग्नल लाइट या अटेंडेंट न हो, ड्रॉ से कम से कम 50 feet पहले रुककर और पार करने से पहले पुष्टि करके कि यह पूरी तरह बंद है। स्रोत: SCDMV CDL Manual 4.3.6।"},"75":{"q":"कौन सी उल्लंघन सूची कम से कम 60 दिनों की पहली साउथ कैरोलिना CDL अयोग्यता को ट्रिगर करती है?","options":["बहुत नज़दीक से पीछा करना","एक रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन","एक ओवरवेट एक्सल चालान","आवश्यक प्लैकार्ड न दिखाना"],"explanation":"SCDMV CDL Manual कहता है कि CDL धारक पहले रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन के लिए कम से कम 60 दिनों, तीन वर्षों के भीतर दूसरे के लिए 120 दिनों, और तीसरे के लिए एक वर्ष के लिए CDL खो देता है। स्रोत: SCDMV CDL Manual 1.3.5; 49 CFR 383.51।"},"76":{"q":"साउथ कैरोलिना में, ओवरसाइज़ परमिट की आवश्यकता होने से पहले मानक अधिकतम कानूनी वाहन/लोड चौड़ाई क्या है?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"साउथ कैरोलिना की कानूनी चौड़ाई सीमा 8 feet 6 inches (102 inches) है; इससे चौड़े लोड के लिए SCDOT ओवरसाइज़ परमिट की आवश्यकता होती है। अधिकतम कानूनी ऊँचाई 13 feet 6 inches है। स्रोत: SCDOT Oversize/Overweight Permits।"},"77":{"q":"परमिट के बिना, साउथ कैरोलिना में किसी कमर्शियल वाहन और लोड के लिए अधिकतम कानूनी ऊँचाई क्या है?","options":["13 feet 6 inches","14 feet 0 inches","12 feet 6 inches","13 feet 0 inches"],"explanation":"साउथ कैरोलिना की कानूनी अधिकतम ऊँचाई 13 feet 6 inches है; इससे ऊँची किसी भी चीज़ के लिए SCDOT ओवर-हाइट परमिट और ओवरपास क्लीयरेंस के लिए रूटिंग समीक्षा की आवश्यकता होती है। स्रोत: SCDOT Oversize/Overweight Permits।"},"78":{"q":"SCDOT परमिट नियमों के तहत, साउथ कैरोलिना में ओवरसाइज़ लोड को आमतौर पर किस समय चलने की अनुमति है?","options":["दिन में 24 घंटे, किसी भी दिन","सूर्योदय के आधे घंटे बाद से सूर्यास्त के आधे घंटे पहले तक, सोमवार से शनिवार","यातायात से बचने के लिए केवल रात 9 बजे से सुबह 5 बजे के बीच","केवल कार्यदिवस, शनिवार को कोई आवाजाही अनुमत नहीं"],"explanation":"SCDOT आमतौर पर ओवरसाइज़-लोड आवाजाही को सूर्योदय के आधे घंटे बाद से सूर्यास्त के आधे घंटे पहले तक, सोमवार से शनिवार तक सीमित करता है, रविवार या निर्दिष्ट-अवकाश यात्रा के बिना, साथ ही बहुत चौड़े लोड के लिए अतिरिक्त प्रतिबंधों के साथ। स्रोत: SCDOT Oversize/Overweight Permits।"},"79":{"q":"जो ड्राइवर साउथ कैरोलिना की किसी रुकी हुई स्कूल बस को गैरकानूनी रूप से पास करता है और जो वाहन मूव ओवर कानून के तहत किसी रुके हुए आपातकालीन वाहन के पास पहुँचता है, दोनों दंड के अधीन हैं। मूव ओवर कानून उल्लंघन के बारे में कौन सा कथन सही है?","options":["यह केवल $25 का सिविल जुर्माना है जिसमें कोई कोर्ट लागत नहीं","यह एक मिसडिमीनर है जिसमें $300 से $500 की सीमा में जुर्माना है","इसमें स्वचालित आजीवन CDL अयोग्यता है","यह पहले वर्ष के लिए केवल-चेतावनी वाला अपराध है"],"explanation":"साउथ कैरोलिना मूव ओवर कानून (S.C. Code 56-5-1538) का उल्लंघन एक मिसडिमीनर है जो आमतौर पर $300-$500 की सीमा में जुर्माने से दंडनीय है; इसके विपरीत, लेफ्ट-लेन 'मूव राइट' उल्लंघन (56-5-1885) $25 का सिविल जुर्माना है। स्रोत: S.C. Code 56-5-1538; SCDPS।"},"80":{"q":"साउथ कैरोलिना में कमर्शियल ड्राइवर लाइसेंस (CDLs) कौन सी एजेंसी जारी करती है?","options":["साउथ कैरोलिना डिपार्टमेंट ऑफ मोटर वीइकल्स (SCDMV)","साउथ कैरोलिना डिपार्टमेंट ऑफ ट्रांसपोर्टेशन (SCDOT)","फेडरल मोटर कैरियर सेफ्टी एडमिनिस्ट्रेशन (FMCSA)","साउथ कैरोलिना हाईवे पैट्रोल"],"explanation":"साउथ कैरोलिना CDLs साउथ कैरोलिना डिपार्टमेंट ऑफ मोटर वीइकल्स (SCDMV) द्वारा जारी किए जाते हैं। FMCSA संघीय CDL मानक निर्धारित करता है लेकिन लाइसेंस जारी नहीं करता; SCDOT सड़कों/परमिट को संभालता है, लाइसेंसिंग को नहीं। स्रोत: SCDMV Commercial Licenses page (dmv.sc.gov)।"},"81":{"q":"साउथ कैरोलिना में, कमर्शियल लर्नर्स परमिट (CLP) या CDL के लिए आवेदन करने के लिए इस्तेमाल किया जाने वाला मानक फॉर्म कौन सा है?","options":["SCDMV Form 447-CDL","SCDMV Form DL-405A","SCDMV Form MV-93","FMCSA Form MCSA-5876"],"explanation":"साउथ कैरोलिना में CLP और CDL के लिए आवेदन SCDMV Form 447-CDL है। DL-405A चिकित्सा स्व-प्रमाणन फॉर्म है, MV-93 पहचान-दस्तावेज़ चेकलिस्ट है, और MCSA-5876 संघीय चिकित्सा परीक्षक का प्रमाणपत्र है। स्रोत: SCDMV Getting Your First CDL (dmv.sc.gov)।"},"82":{"q":"साउथ कैरोलिना कमर्शियल लर्नर्स परमिट (CLP) समाप्त होने से पहले कितने समय तक वैध रहता है?","options":["एक वर्ष","180 दिन","छह महीने","दो वर्ष"],"explanation":"साउथ कैरोलिना में CLP की समाप्ति तिथि एक वर्ष की होती है। स्रोत: SCDMV Getting Your First CDL (dmv.sc.gov)। (संघीय नियम एक वर्ष तक वैध CLP की अनुमति देता है, जिसे साउथ कैरोलिना लागू करता है।)"},"83":{"q":"साउथ कैरोलिना में कमर्शियल लर्नर्स परमिट जारी होने के बाद, CDL स्किल्स टेस्ट देने के योग्य होने से पहले आपको इसे कितने समय तक धारण करना होगा?","options":["कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 10 दिन","कम से कम 7 दिन"],"explanation":"स्किल्स टेस्ट देने से पहले आपको CLP को न्यूनतम 14 दिनों तक धारण करना होगा। स्रोत: SCDMV Getting Your First CDL (dmv.sc.gov); यह संघीय 14-दिन CLP होल्ड (49 CFR 383.25) का अनुसरण करता है।"},"84":{"q":"साउथ कैरोलिना के CDL स्व-प्रमाणन के तहत, किसी ड्राइवर को संचालन की कितनी श्रेणियों में से चुनना होगा?","options":["चार","दो","तीन","पाँच"],"explanation":"चार स्व-प्रमाणन श्रेणियाँ हैं: नॉन-एक्सेप्टेड इंटरस्टेट, एक्सेप्टेड इंटरस्टेट, नॉन-एक्सेप्टेड इंट्रास्टेट, और एक्सेप्टेड इंट्रास्टेट। ड्राइवर SCDMV को अपनी श्रेणी प्रमाणित करते हैं। स्रोत: SCDMV / Form DL-405A (dmv.sc.gov)।"},"85":{"q":"साउथ कैरोलिना का कौन सा फॉर्म आपके वाणिज्य के प्रकार को स्व-प्रमाणित करने और SCDMV को चिकित्सा प्रमाणन स्थिति जमा करने के लिए इस्तेमाल किया जाता है?","options":["Form DL-405A (CDL Holder's Medical Certification)","Form 447-CDL (CDL Application)","Form MV-93 (Citizen's Checklist)","Form MCSA-5875 (Medical Examination Report)"],"explanation":"साउथ कैरोलिना CDL धारक के स्व-प्रमाणन और चिकित्सा प्रमाणन के लिए Form DL-405A का उपयोग करता है। Form 447-CDL लाइसेंस आवेदन है, MV-93 ID चेकलिस्ट है, और MCSA-5875 संघीय परीक्षा रिपोर्ट है। स्रोत: SCDMV Renew or Upgrade Your CDL (dmv.sc.gov)।"},"86":{"q":"किस स्व-प्रमाणन श्रेणी में किसी साउथ कैरोलिना CDL धारक को एक वैध DOT चिकित्सा परीक्षक का प्रमाणपत्र प्रदान करना आवश्यक है?","options":["नॉन-एक्सेप्टेड इंटरस्टेट","एक्सेप्टेड इंटरस्टेट","एक्सेप्टेड इंट्रास्टेट","किसी भी श्रेणी में चिकित्सा प्रमाणपत्र आवश्यक नहीं है"],"explanation":"नॉन-एक्सेप्टेड इंटरस्टेट ड्राइवरों को एक वैध DOT चिकित्सा परीक्षक का प्रमाणपत्र बनाए रखना होगा जो FMCSA मानकों को पूरा करता हो। एक्सेप्टेड श्रेणियों के ड्राइवरों को इसे जमा करना आवश्यक नहीं है। स्रोत: SCDMV / Form DL-405A (dmv.sc.gov); 49 CFR 391.41।"},"87":{"q":"किसी साउथ कैरोलिना नॉन-एक्सेप्टेड CDL ड्राइवर को जो चिकित्सा परीक्षक का प्रमाणपत्र धारण करना होता है, उसकी शारीरिक जाँच करने और प्रमाणपत्र जारी करने के लिए कौन अधिकृत है?","options":["FMCSA के नेशनल रजिस्ट्री ऑफ सर्टिफाइड मेडिकल एग्ज़ामिनर्स पर सूचीबद्ध एक चिकित्सा पेशेवर","ड्राइवर की पसंद का कोई भी लाइसेंस प्राप्त चिकित्सक","ब्रांच ऑफिस पर एक SCDMV परीक्षक","साउथ कैरोलिना डिपार्टमेंट ऑफ ट्रांसपोर्टेशन द्वारा अनुमोदित एक चिकित्सक"],"explanation":"जाँच की जानी चाहिए और प्रमाणपत्र FMCSA के नेशनल रजिस्ट्री ऑफ सर्टिफाइड मेडिकल एग्ज़ामिनर्स पर सूचीबद्ध एक चिकित्सा पेशेवर द्वारा जारी किया जाना चाहिए। स्रोत: SCDMV Commercial Licenses (dmv.sc.gov); 49 CFR 390.103।"},"88":{"q":"साउथ कैरोलिना में CDL स्किल्स टेस्ट देने से पहले, उन आवेदकों पर कौन सी आवश्यकता लागू होती है जिन्होंने अपना CLP 7 फरवरी, 2022 के बाद प्राप्त किया?","options":["एक FMCSA-अनुमोदित एंट्री-लेवल ड्राइवर ट्रेनिंग (ELDT) कार्यक्रम पूरा करना","लगातार पाँच वर्षों तक एक साफ़ ड्राइविंग रिकॉर्ड बनाए रखना","SCDMV के साथ 160 घंटे का बिहाइंड-द-व्हील समय पूरा करना","एक अलग SCDMV डिफेंसिव ड्राइविंग कोर्स पास करना"],"explanation":"जिन आवेदकों का CLP 7 फरवरी, 2022 के बाद जारी किया गया, उन्हें स्किल्स टेस्ट देने से पहले किसी पंजीकृत प्रशिक्षण प्रदाता के साथ एक FMCSA-अनुमोदित ELDT कार्यक्रम पूरा करना होगा। स्रोत: SCDMV Getting Your First CDL (dmv.sc.gov); 49 CFR Part 380 Subpart F।"},"89":{"q":"साउथ कैरोलिना CDL स्किल्स टेस्ट तीन भागों में विभाजित है। कौन सा सेट उन तीन भागों को सही ढंग से सूचीबद्ध करता है?","options":["प्री-ट्रिप इंस्पेक्शन, बेसिक वीइकल कंट्रोल, और ऑन-रोड ड्राइविंग","लिखित ज्ञान, दृष्टि स्क्रीनिंग, और ऑन-रोड ड्राइविंग","प्री-ट्रिप इंस्पेक्शन, खतरनाक सामग्री, और रात की ड्राइविंग","एयर ब्रेक चेक, पैरेलल पार्किंग, और फ्रीवे मर्जिंग"],"explanation":"CDL स्किल्स टेस्ट के तीन घटक हैं: प्री-ट्रिप इंस्पेक्शन, बेसिक वीइकल (ऑफ-रोड) कंट्रोल, और ऑन-रोड ड्राइविंग टेस्ट। स्रोत: SCDMV Getting Your First CDL (dmv.sc.gov); 49 CFR 383.113।"},"90":{"q":"साउथ कैरोलिना CDL के नवीनीकरण की आवश्यकता होने से पहले उसकी मानक वैधता अवधि क्या है?","options":["8 वर्ष","5 वर्ष","4 वर्ष","10 वर्ष"],"explanation":"साउथ कैरोलिना CDL 8 वर्षों के लिए वैध है और चक्र के अंतिम वर्ष में धारक के जन्मदिन पर समाप्त होता है। स्रोत: SCDMV (dmv.sc.gov)। (HazMat एंडोर्समेंट अलग 5-वर्षीय TSA Security Threat Assessment चक्र द्वारा सीमित है।)"},"91":{"q":"खतरनाक सामग्री (HazMat) एंडोर्समेंट वाला एक साउथ कैरोलिना CDL किस अलग समय-सीमा द्वारा सीमित है?","options":["5-वर्षीय TSA Security Threat Assessment चक्र","एक 2-वर्षीय केवल-HazMat नवीनीकरण चक्र","एक 10-वर्षीय संघीय HazMat प्रमाणन","एक 1-वर्षीय SCDMV HazMat समीक्षा"],"explanation":"भले ही CDL स्वयं 8 वर्षों के लिए वैध हो, HazMat एंडोर्समेंट TSA Security Threat Assessment से जुड़ा है, जिसे 5-वर्षीय चक्र पर नवीनीकृत किया जाना चाहिए। स्रोत: SCDMV Commercial Licenses (dmv.sc.gov); 49 CFR 1572।"},"92":{"q":"किसी साउथ कैरोलिना CDL धारक को चिकित्सा योग्यता (स्व-प्रमाणन/चिकित्सा प्रमाणपत्र) का प्रमाण SCDMV को कब जमा करना होगा?","options":["हर बार जब वे CDL के लिए आवेदन करते हैं, नवीनीकरण करते हैं, अपग्रेड करते हैं, पता बदलते हैं, या डुप्लिकेट लेते हैं","केवल एक बार, जब पहली बार CDL प्राप्त करते हैं","केवल 8-वर्षीय नवीनीकरण पर","केवल जब HazMat एंडोर्समेंट जोड़ते हैं"],"explanation":"ड्राइवरों को हर बार जब वे CLP/CDL के लिए आवेदन करते हैं, अपग्रेड करते हैं, नवीनीकरण करते हैं, पता बदलते हैं, या डुप्लिकेट का अनुरोध करते हैं, तब चिकित्सा योग्यता का प्रमाण जमा करना होगा। स्रोत: SCDMV Commercial Licenses (dmv.sc.gov)।"},"93":{"q":"साउथ कैरोलिना में केवल राज्य के भीतर (इंट्रास्टेट) किसी कमर्शियल वाहन को चलाने के लिए CDL जारी होने की न्यूनतम आयु क्या है?","options":["18 वर्ष","19 वर्ष","21 वर्ष","20 वर्ष"],"explanation":"साउथ कैरोलिना के भीतर इंट्रास्टेट ड्राइविंग के लिए CDL धारण करने हेतु आपकी आयु कम से कम 18 वर्ष होनी चाहिए, और इंटरस्टेट ड्राइविंग के लिए कम से कम 21 वर्ष। स्रोत: SCDMV Getting Your First CDL (dmv.sc.gov)।"},"94":{"q":"इंटरस्टेट कॉमर्स (राज्य सीमाओं के पार) में किसी कमर्शियल मोटर वाहन को संचालित करने के लिए साउथ कैरोलिना किस न्यूनतम आयु की आवश्यकता रखता है?","options":["21 वर्ष","18 वर्ष","19 वर्ष","25 वर्ष"],"explanation":"इंटरस्टेट कॉमर्स में किसी CMV को संचालित करने के लिए ड्राइवर की आयु कम से कम 21 वर्ष होनी चाहिए; 18-20 वर्ष की आयु इंट्रास्टेट संचालन तक सीमित है। स्रोत: SCDMV Getting Your First CDL (dmv.sc.gov); 49 CFR 391.11।"},"95":{"q":"किसी नॉन-एक्सेप्टेड इंटरस्टेट ड्राइवर के चिकित्सा परीक्षक के प्रमाणपत्र को SCDMV को जमा किए जाने के बाद आमतौर पर कैसे सत्यापित किया जाता है?","options":["इसे इलेक्ट्रॉनिक रूप से सत्यापित किया जाता है/ड्राइविंग रिकॉर्ड पर पोस्ट किया जाता है","इसे SCDMV ब्रांच पर नोटरीकृत किया जाना चाहिए","इसे मैनुअल अनुमोदन के लिए FMCSA को मेल किया जाता है","इसे केवल चिकित्सा परीक्षक द्वारा सत्यापित किया जाता है, राज्य द्वारा नहीं"],"explanation":"नॉन-एक्सेप्टेड ड्राइवरों के लिए चिकित्सा प्रमाणपत्र की जानकारी इलेक्ट्रॉनिक रूप से सत्यापित की जाती है और चिकित्सा स्थिति को CDL ड्राइविंग रिकॉर्ड में जोड़ा जाता है। स्रोत: SCDMV Commercial Licenses (dmv.sc.gov); 49 CFR 383.71/383.73।"},"96":{"q":"CDL या CLP के लिए आवेदन करने से पहले, साउथ कैरोलिना किसी आवेदक से पहले से ही कौन सा क्रेडेंशियल धारण करने की आवश्यकता रखता है?","options":["एक वैध, अनएक्सपायर्ड साउथ कैरोलिना ड्राइवर्स लाइसेंस","एक वैध पासपोर्ट","एक संघीय TWIC कार्ड","एक साउथ कैरोलिना बिज़नेस लाइसेंस"],"explanation":"आवेदकों को CLP/CDL के लिए आवेदन करने से पहले एक वैध, अनएक्सपायर्ड साउथ कैरोलिना (नियमित) ड्राइवर्स लाइसेंस धारण करना होगा। स्रोत: SCDMV Getting Your First CDL (dmv.sc.gov)।"},"97":{"q":"किसी साउथ कैरोलिना CDL नवीनीकरण पर, आवेदन और चिकित्सा/स्व-प्रमाणन के अतिरिक्त कौन सी वस्तु प्रस्तुत की जानी चाहिए?","options":["साउथ कैरोलिना में लाइसेंस प्राप्त किसी कंपनी से ऑटोमोबाइल लायबिलिटी इंश्योरेंस की जानकारी","एक नोटरीकृत नियोक्ता शपथपत्र","एक नए ELDT कोर्स को पूरा करने का प्रमाण","सभी एंडोर्समेंट के लिए एक नई TSA फिंगरप्रिंट जाँच"],"explanation":"साउथ कैरोलिना CDL नवीनीकरण पर किसी SC-लाइसेंस प्राप्त बीमाकर्ता से ऑटोमोबाइल लायबिलिटी इंश्योरेंस की जानकारी की आवश्यकता रखता है, साथ ही लागू होने पर Form 447-CDL और Form DL-405A चिकित्सा प्रमाणन। स्रोत: SCDMV Renew or Upgrade Your CDL (dmv.sc.gov)।"},"98":{"q":"यदि कोई साउथ कैरोलिना CDL धारक नॉन-एक्सेप्टेड प्रमाणित रहते हुए संघीय रूप से आवश्यक चिकित्सा परीक्षक के प्रमाणपत्र को समाप्त होने देता है, तो CDL पर क्या परिणाम होता है?","options":["CDL को डाउनग्रेड कर दिया जाता है ताकि एक वैध प्रमाणपत्र फाइल पर आने तक कमर्शियल विशेषाधिकार खो जाएँ","8-वर्षीय नवीनीकरण तक कुछ नहीं बदलता","CDL को बिना किसी पुनर्बहाली के मार्ग के स्थायी रूप से रद्द कर दिया जाता है","केवल HazMat एंडोर्समेंट प्रभावित होता है"],"explanation":"जब किसी नॉन-एक्सेप्टेड ड्राइवर का चिकित्सा प्रमाणपत्र समाप्त हो जाता है या फाइल पर नहीं होता, तो राज्य को एक वर्तमान प्रमाणपत्र जमा होने तक CDL को डाउनग्रेड करना होगा (कमर्शियल ड्राइविंग विशेषाधिकार हटाते हुए)। स्रोत: SCDMV / FMCSA medical certification rules (dmv.sc.gov); 49 CFR 383.73।"},"99":{"q":"किसी साउथ कैरोलिना CDL का नवीनीकरण करते समय, चिकित्सा स्व-प्रमाणन (Form DL-405A) को आमतौर पर किस स्थिति में फिर से जमा करना होगा?","options":["यदि इसे पहले से जमा नहीं किया गया है या यदि संचालित किए जा रहे वाणिज्य का प्रकार बदल गया है","केवल यदि ड्राइवर किसी अन्य राज्य में चला गया है","केवल यदि ड्राइवर की आयु 65 वर्ष से अधिक है","कभी नहीं, क्योंकि यह एक बार की फाइलिंग है"],"explanation":"साउथ कैरोलिना नवीनीकरण पर DL-405A स्व-प्रमाणन की आवश्यकता रखता है यदि इसे पहले से जमा नहीं किया गया है या यदि ड्राइवर के वाणिज्य का प्रकार (स्व-प्रमाणन श्रेणी) बदल गया है। स्रोत: SCDMV Renew or Upgrade Your CDL (dmv.sc.gov)।"}},"ar":{"0":{"q":"على الطرق السريعة في ساوث كارولينا، ما هو الحد الأقصى للعرض الخارجي الإجمالي للمركبة أو حمولتها، باستثناء أجهزة السلامة المعتمدة؟","options":["96 inches","102 inches","108 inches","120 inches"],"explanation":"تحدد مدونة ساوث كارولينا 56-5-4030 الحد الأقصى للعرض الخارجي الإجمالي للمركبة أو الحمولة بـ 102 inches (8 feet 6 inches)، باستثناء أجهزة السلامة المعتمدة. وهذا يطابق المعيار الفيدرالي المعتمد على مستوى الولاية. المصدر: SC Code 56-5-4030 (عرض المركبات)."},"1":{"q":"ما هو الحد الأقصى للارتفاع بالنسبة لمعظم المركبات، فارغة أو محملة، على الطرق السريعة في ساوث كارولينا؟","options":["13 feet","13 feet 6 inches","14 feet","14 feet 6 inches"],"explanation":"تحدد مدونة ساوث كارولينا 56-5-4060 ارتفاع المركبة بـ 13 feet 6 inches. ويسمح استثناء ضيق بـ 14 feet لوحدة ناقلة سيارات أو تركيبة سرج-تركيب مع تصريح توجيه صالح من SCDOT. المصدر: SC Code 56-5-4060 (ارتفاع المركبات)."},"2":{"q":"ما هو الحد الأقصى لطول مركبة آلية مفردة (مثل شاحنة مستقيمة) في ساوث كارولينا، بما في ذلك المصدات والحمولة؟","options":["35 feet","40 feet","45 feet","48 feet"],"explanation":"تحدد مدونة ساوث كارولينا 56-5-4070 الطول الإجمالي الأقصى لمركبة آلية مفردة بـ 40 feet، بما في ذلك المصدات الأمامية والخلفية والحمولة. وتُعامل الحافلات وبعض المنازل المتنقلة بشكل منفصل. المصدر: SC Code 56-5-4070 (طول المركبات)."},"3":{"q":"في تركيبة من وحدتين تتكون من جرار شاحنة ونصف مقطورة، ما هو الحد الأقصى لطول المقطورة أو نصف المقطورة (بما في ذلك الحمولة) في ساوث كارولينا؟","options":["48 feet","50 feet","53 feet","57 feet"],"explanation":"تسمح مدونة ساوث كارولينا 56-5-4070 بأن تصل المقطورة أو نصف المقطورة في تركيبة جرار شاحنة من وحدتين إلى 53 feet، بما في ذلك الحمولة. ويجب أن تكون المقطورة بطول 53-foot مزودة بحاجز خلفي مانع للانزلاق السفلي. المصدر: SC Code 56-5-4070."},"4":{"q":"في ساوث كارولينا، ما هو الحد الأقصى للوزن الإجمالي الذي يمكن أن يفرضه محور مفرد على الطريق السريع؟","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"تحدد مدونة ساوث كارولينا 56-5-4140 الوزن الإجمالي على أي محور واحد بـ 20,000 pounds. وهذا مماثل لحد المحور المفرد الفيدرالي. المصدر: SC Code 56-5-4140 (الوزن الإجمالي للمركبات)."},"5":{"q":"ما هو الحد الأقصى للوزن الإجمالي للمركبة المسموح به في ساوث كارولينا دون تصريح خاص؟","options":["73,280 pounds","76,000 pounds","80,000 pounds","88,000 pounds"],"explanation":"تحدد مدونة ساوث كارولينا 56-5-4140 الوزن الإجمالي الكلي بـ 80,000 pounds باستثناء المركبات التي تصدر لها تصاريح خاصة من SCDOT. وهذا يعكس الحد الأقصى الفيدرالي بين الولايات. المصدر: SC Code 56-5-4140."},"6":{"q":"على الطرق السريعة بين الولايات في ساوث كارولينا، ما هو الحد الأقصى للوزن الإجمالي المسموح به على مجموعة محاور ترادفية (بما في ذلك هامش التسامح في الإنفاذ)؟","options":["32,000 pounds","34,000 pounds","35,200 pounds","36,000 pounds"],"explanation":"على نظام الطرق بين الولايات، تسمح ساوث كارولينا بوزن إجمالي للمحور الترادفي يبلغ 35,200 pounds، والذي يشمل هامش التسامح في الإنفاذ للولاية فوق الأساس الفيدرالي البالغ 34,000-pound. المصدر: SC Code 56-5-4140؛ إرشادات الحجم والوزن من SCDMV/SCDOT."},"7":{"q":"على الطرق السريعة غير المشتركة بين الولايات (طرق الولاية) في ساوث كارولينا، ما هو الحد الأقصى للوزن الإجمالي المسموح به على مجموعة محاور ترادفية متباعدة بمسافة 40 to 96 inches؟","options":["34,000 pounds","35,200 pounds","36,000 pounds","40,000 pounds"],"explanation":"تسمح مدونة ساوث كارولينا 56-5-4140 بما يصل إلى 36,000 pounds على محور ترادفي (محوران متتاليان أو أكثر متباعدان بمسافة 40 to 96 inches) على الطرق السريعة بخلاف الطرق بين الولايات. وحد المحور الترادفي بين الولايات أقل، عند 35,200 pounds. المصدر: SC Code 56-5-4140."},"8":{"q":"ما هي الصيغة التي تستخدمها ساوث كارولينا لتحديد الوزن الإجمالي المسموح به على مجموعة من المحاور بناءً على التباعد بينها؟","options":["صيغة الجسر الفيدرالية (Formula B)","صيغة معدل وزن التركيبة الإجمالي","صيغة مقاومة دحرجة Davis","صيغة هامش تسامح المحور المفرد"],"explanation":"تطبق ساوث كارولينا صيغة الجسر الفيدرالية (Bridge Formula B) لتحديد الوزن الأقصى على أي مجموعة من محورين متتاليين أو أكثر بناءً على تباعد المحاور وعدد المحاور، بما يتوافق مع 23 U.S.C. 127. المصدر: SC Code 56-5-4140؛ صيغة الجسر الفيدرالية من FHWA."},"9":{"q":"أي وكالة حكومية في ساوث كارولينا تصدر تصاريح المركبات والحمولات الزائدة الحجم/الزائدة الوزن (OSOW) التي تتجاوز الحدود القانونية؟","options":["وزارة المركبات الآلية في ساوث كارولينا (SCDMV)","وزارة السلامة العامة في ساوث كارولينا (SCDPS)","وزارة النقل في ساوث كارولينا (SCDOT)","وزارة الإيرادات في ساوث كارولينا (SCDOR)"],"explanation":"يصدر مكتب تصاريح الحجم الزائد/الوزن الزائد التابع لوزارة النقل في ساوث كارولينا (SCDOT) تصاريح OSOW وفقًا لتقديره للحمولات التي تتجاوز حدود الحجم أو الوزن القانونية. المصدر: برنامج تصاريح الحجم الزائد/الوزن الزائد لـ SCDOT."},"10":{"q":"متى يُطلب عمومًا تصريح للحجم الزائد في ساوث كارولينا فيما يتعلق بعرض الحمولة؟","options":["عندما يتجاوز العرض 96 inches","عندما يتجاوز العرض 102 inches (8'6\")","عندما يتجاوز العرض 120 inches (10')","عندما يتجاوز العرض 144 inches (12')"],"explanation":"نظرًا لأن حد العرض القانوني في ساوث كارولينا هو 102 inches (8 feet 6 inches)، فإن أي حمولة أعرض من ذلك تتطلب تصريح حجم زائد من SCDOT. المصدر: SC Code 56-5-4030؛ إرشادات تصاريح OSOW من SCDOT."},"11":{"q":"كيف يمكن للناقل التقدم بطلب للحصول على تصريح الحجم الزائد/الوزن الزائد في ساوث كارولينا؟","options":["فقط عن طريق إرسال نموذج ورقي بالبريد إلى SCDMV","من خلال نظام SafeHaul عبر الإنترنت التابع لـ SCDOT (أو عبر الهاتف/البريد/البريد الإلكتروني)","فقط شخصيًا في محكمة المقاطعة","من خلال البوابة الوطنية لـ FMCSA"],"explanation":"يحصل الناقلون على تصاريح OSOW من خلال نظام SafeHaul (iHaul) عبر الإنترنت التابع لـ SCDOT، أو عن طريق الاتصال بمكتب تصاريح OSOW التابع لـ SCDOT عبر الهاتف أو البريد أو البريد الإلكتروني. المصدر: صفحة تصاريح الحجم الزائد/الوزن الزائد لـ SCDOT (SafeHaul)."},"12":{"q":"بموجب إعفاء المزارع/الغابات في ساوث كارولينا، يجوز للمعدات الزراعية ذاتية الدفع وآلات الغابات التحرك دون تصريح حجم زائد أثناء النهار شريطة ألا تتجاوز أي عرض؟","options":["8 feet 6 inches","10 feet","12 feet","14 feet"],"explanation":"تسمح ساوث كارولينا للمعدات الزراعية وآلات الغابات والمعدات المماثلة بالتحرك أثناء النهار دون تصريح إذا لم تتجاوز 12 feet عرضًا، أو 13 feet 6 inches ارتفاعًا، أو 90,000 pounds. المصدر: إرشادات OSOW من SCDOT (الإعفاء الزراعي/الغابات)."},"13":{"q":"على طريق سريع ذي مسارين في ساوث كارولينا، عند أي عرض تبدأ الحمولة المرخصة في طلب مركبة مرافقة (مرشدة) أمامية؟","options":["أكثر من 10 feet","أكثر من 12 feet","أكثر من 14 feet","أكثر من 16 feet"],"explanation":"على الطرق السريعة ذات المسارين، تتطلب ساوث كارولينا مرافقة أمامية للحمولات التي تتجاوز 12 feet حتى 14 feet عرضًا؛ والحمولات التي تزيد عن 14 feet حتى 16 feet تتطلب مرافقة أمامية وخلفية. المصدر: متطلبات المرافقة/سيارة الإرشاد لـ OSOW من SCDOT."},"14":{"q":"بالنسبة لنصف مقطورة بطول 53-foot في ساوث كارولينا، يجب ألا تتجاوز المسافة من مسمار الملك إلى مركز المحور الخلفي (أو مجموعة المحاور الترادفية الخلفية) أي قيمة؟","options":["37 feet","41 feet","43 feet","46 feet"],"explanation":"تشترط مدونة ساوث كارولينا 56-5-4070 أن تكون المسافة من مسمار الملك إلى المحور الخلفي (أو مركز المحور الترادفي الخلفي) في مقطورة بطول 53-foot لا تزيد عن 41 feet. المصدر: SC Code 56-5-4070."},"15":{"q":"ما هو هامش التسامح في الإنفاذ الذي تطبقه ساوث كارولينا عمومًا على حدود الوزن على الطرق السريعة غير المشتركة بين الولايات؟","options":["5 percent","10 percent","15 percent","لا يُسمح بأي هامش تسامح"],"explanation":"تطبق ساوث كارولينا هامش تسامح في الإنفاذ بنسبة 10% على حدود الوزن للطرق السريعة غير المشتركة بين الولايات (طرق الولاية والطرق التكميلية). ويتم إنفاذ أوزان الطرق بين الولايات بشكل أكثر صرامة ضمن هوامش التسامح المحددة. المصدر: إرشادات الحجم والوزن من SCDOT/SCDMV؛ SC Code 56-5-4140."},"16":{"q":"بموجب استثناء الارتفاع البالغ 14-foot في ساوث كارولينا، يجب أن يكون لدى ناقلة السيارات أو تركيبة السرج-تركيب بالإضافة إلى ذلك ماذا؟","options":["إعفاء من FMCSA","تصريح توجيه صالح صادر عن SCDOT","تصديق لنقل المواد الخطرة","موافقة خطية من مأمور المقاطعة"],"explanation":"تسمح مدونة ساوث كارولينا 56-5-4060 بما يصل إلى 14 feet لوحدة ناقلة سيارات أو تركيبة سرج-تركيب فقط إذا كان المالك/المشغل يحمل تصريح توجيه صالح صادر عن SCDOT. المصدر: SC Code 56-5-4060."},"17":{"q":"ما هو الحد الأقصى للطول المسموح به لمنزل متنقل في ساوث كارولينا، شريطة أن يكون نصف قطر دورانه 48 feet أو أقل؟","options":["40 feet","42 feet","45 feet","48 feet"],"explanation":"تسمح مدونة ساوث كارولينا 56-5-4070 بمنزل متنقل يصل طوله إلى 45 feet إذا كان نصف قطر دورانه 48 feet أو أقل، وهو استثناء من الحد العام البالغ 40-foot للمركبة المفردة. المصدر: SC Code 56-5-4070."},"18":{"q":"يجوز أن تمتد الملحقات على المنازل المتنقلة ومقطورات السفر وكبائن الشاحنات في الاستخدام غير التجاري إلى ما بعد العرض القانوني بمقدار كم في ساوث كارولينا؟","options":["حتى 3 inches على كل جانب","حتى 6 inches على جانب واحد و 4 inches على الجانب الآخر","حتى 12 inches على جانب واحد فقط","لا يُسمح بأي امتداد إلى ما بعد العرض القانوني"],"explanation":"تسمح مدونة ساوث كارولينا 56-5-4030 بأن تمتد الملحقات على المنازل المتنقلة ومقطورات السفر وكبائن الشاحنات غير التجارية بحد أقصى 6 inches على جانب واحد و 4 inches على الجانب الآخر إلى ما بعد حد العرض البالغ 102-inch. المصدر: SC Code 56-5-4030."},"19":{"q":"يكلف تصريح SCDOT النموذجي للرحلة الواحدة للحجم الزائد/الوزن الزائد لحمولة عريضة قياسية حوالي كم؟","options":["$10","$30","$75","$150"],"explanation":"تفرض SCDOT حوالي $30 لتصريح OSOW قياسي للرحلة الواحدة، مع تصريح سنوي (متعدد الرحلات) بحوالي $100؛ وتُطبق رسوم أعلى على العروض الزائدة التي تتجاوز 16 feet. المصدر: جدول رسوم تصاريح الحجم الزائد/الوزن الزائد لـ SCDOT."},"20":{"q":"في ساوث كارولينا، أي فئة من فئات CDL مطلوبة لتشغيل تركيبة من المركبات بمعدل وزن تركيبة إجمالي (GCWR) يبلغ 26,001 pounds أو أكثر حيث يكون للوحدة المقطورة معدل وزن إجمالي للمركبة (GVWR) يزيد عن 10,000 pounds؟","options":["Class A","Class B","Class C","Class D"],"explanation":"تُعرّف ساوث كارولينا (SCDMV، الفئات A و B و C) رخصة CDL من Class A بأنها أي تركيبة من المركبات بمعدل GCWR يبلغ 26,001 lbs أو أكثر، شريطة أن يكون معدل GVWR للمركبة المقطورة أكثر من 10,000 lbs. المصدر: الرخص التجارية من SCDMV، الفئات A و B و C."},"21":{"q":"وفقًا لـ SCDMV، تتطلب المركبة أحادية الوحدة بمعدل GVWR يبلغ 26,001 pounds أو أكثر (لا تقطر شيئًا يزيد عن 10,000 lbs) أي فئة من فئات CDL؟","options":["Class C","Class B","Class A","Class E"],"explanation":"تُعرّف ساوث كارولينا رخصة CDL من Class B بأنها أي مركبة أحادية الوحدة بمعدل GVWR يبلغ 26,001 lbs أو أكثر، أو مثل هذه المركبة وهي تقطر وحدة لا يزيد وزنها عن 10,000 lbs. المصدر: الرخص التجارية من SCDMV، الفئات A و B و C."},"22":{"q":"بموجب قواعد ساوث كارولينا، تتطلب المركبة التي لا تستوفي عتبات الوزن للفئة A أو B ولكنها مصممة لنقل 16 شخصًا أو أكثر (بما في ذلك السائق) أي فئة من فئات CDL؟","options":["Class A","Class B","Class C","لا يلزم CDL"],"explanation":"تُعرّف ساوث كارولينا رخصة CDL من Class C بأنها أي مركبة مفردة، أو تركيبة، ليست من Class A أو B ولكنها مصممة لنقل 16 شخصًا أو أكثر بما في ذلك السائق، أو تُستخدم لنقل مواد خطرة تحمل لافتات. المصدر: الرخص التجارية من SCDMV، الفئات A و B و C."},"23":{"q":"في ساوث كارولينا، ما هو الحد الأدنى للعمر للحصول على رخصة CDL للقيادة داخل الولاية (التشغيل داخل الولاية فقط)؟","options":["16 years old","17 years old","18 years old","21 years old"],"explanation":"تشترط SCDMV أن يكون عمر المتقدمين 18 على الأقل للقيادة تجاريًا داخل ساوث كارولينا (داخل الولاية). ولا يجوز للسائقين دون سن 21 القيادة خارج الولاية. المصدر: SCDMV، الحصول على أول CDL لك."},"24":{"q":"ما هو الحد الأدنى للعمر في ساوث كارولينا لحمل رخصة CDL صالحة للقيادة بين الولايات (عبر حدود الولايات)؟","options":["18 years old","19 years old","21 years old","25 years old"],"explanation":"تشترط SCDMV أن يكون عمر السائقين 21 على الأقل لتشغيل مركبة تجارية خارج ساوث كارولينا (بين الولايات). ويقتصر السائقون من سن 18-20 على التشغيل داخل الولاية. المصدر: SCDMV، الحصول على أول CDL لك."},"25":{"q":"قبل أن يتمكن المتقدم في ساوث كارولينا من إجراء اختبار مهارات CDL (الاختبار على الطريق)، كم من الوقت يجب أن يحمل تصريح المتعلم التجاري (CLP)؟","options":["7 أيام تقويمية على الأقل","14 يومًا تقويميًا على الأقل","30 يومًا تقويميًا على الأقل","60 يومًا تقويميًا على الأقل"],"explanation":"تتبع ساوث كارولينا القاعدة الفيدرالية التي تشترط حمل CLP لمدة 14 يومًا تقويميًا على الأقل قبل أن يتمكن المتقدم من إجراء اختبار مهارات CDL. المصدر: SCDMV، الحصول على أول CDL لك (49 CFR 383.25)."},"26":{"q":"أي رمز تصديق تستخدمه ساوث كارولينا للترخيص بتشغيل مركبة تنقل مواد خطرة تحمل لافتات؟","options":["N","T","H","P"],"explanation":"يغطي تصديق H المواد الخطرة التي تتطلب لافتات. وتستخدم ساوث كارولينا رموز التصديق الفيدرالية القياسية: H (المواد الخطرة)، N (الصهريج)، T (المزدوجة/الثلاثية)، P (الركاب)، S (حافلة المدرسة). المصدر: الرخص التجارية من SCDMV."},"27":{"q":"في ساوث كارولينا، قبل أن يتم إصدار أو تجديد تصديق المواد الخطرة (H)، يجب على المتقدم أن يجتاز أي فحص إضافي؟","options":["تقييم تهديد أمني من TSA (فحص الخلفية وأخذ البصمات)","اختبار رشاقة بدنية ورفع الأثقال","شهادة دورة القيادة الدفاعية","فحص النظر الذي تجريه SCDMV"],"explanation":"تشترط ساوث كارولينا أن يجتاز المتقدمون لتصديق المواد الخطرة (H) تقييم تهديد أمني فيدرالي من إدارة أمن النقل (TSA)، والذي يشمل أخذ البصمات وفحص الخلفية، لكل من التصديق الأصلي والتجديد. المصدر: SCDMV؛ 49 CFR 1572."},"28":{"q":"أي تصديق مطلوب في ساوث كارولينا لقيادة مركبة تجارية مصممة لنقل السوائل أو الغازات في صهريج سائب؟","options":["P (الركاب)","N (مركبة الصهريج)","T (المزدوجة/الثلاثية)","S (حافلة المدرسة)"],"explanation":"تصديق N (مركبة الصهريج) مطلوب لتشغيل مركبة تنقل السوائل أو الغازات في صهاريج سائبة تستوفي التعريف الفيدرالي. المصدر: الرخص التجارية من SCDMV؛ 49 CFR 383.93."},"29":{"q":"في ساوث كارولينا، أي تصديق مطلوب لقطر مقطورات مزدوجة أو ثلاثية؟","options":["تصديق T","تصديق N","تصديق H","تصديق X"],"explanation":"يرخص تصديق T بتشغيل المقطورات المزدوجة والثلاثية. وتستخدم ساوث كارولينا الرموز الفيدرالية القياسية. المصدر: الرخص التجارية من SCDMV؛ 49 CFR 383.93."},"30":{"q":"أي تصديق يجب على السائق في ساوث كارولينا الحصول عليه لتشغيل حافلة تجارية أو شاحنة صغيرة مصممة لنقل العدد العتبي المطلوب من الركاب؟","options":["S (حافلة المدرسة)","P (الركاب)","N (الصهريج)","T (المزدوجة/الثلاثية)"],"explanation":"تصديق P (الركاب) مطلوب لتشغيل مركبة مصممة لنقل 16 شخصًا أو أكثر بما في ذلك السائق. ويلزم تصديق S منفصل لحافلات المدارس. المصدر: الرخص التجارية من SCDMV."},"31":{"q":"في ساوث كارولينا، ماذا يحتاج السائق لتشغيل حافلة مدرسية تتطلب رخصة CDL؟","options":["فقط تصديق P (الركاب)","كل من تصديق P (الركاب) وتصديق S (حافلة المدرسة)","فقط تصديق H (المواد الخطرة)","لا يلزم تصديق، فقط رخصة CDL من Class B"],"explanation":"لقيادة حافلة مدرسية في ساوث كارولينا، يجب على السائق أن يحمل كلاً من تصديق P (الركاب) وتصديق S (حافلة المدرسة)، وأن يجتاز اختبارات المعرفة والمهارات الخاصة بحافلة المدرسة. المصدر: الرخص التجارية من SCDMV؛ 49 CFR 383.93."},"32":{"q":"بالنسبة للمتقدم لـ CLP/CDL في ساوث كارولينا الذي حصل على تصريحه في أو بعد February 7, 2022، ما هو التدريب الذي يجب إكماله قبل اختبار المهارات لأول CDL؟","options":["دورة دراسية في الفصل خاصة بـ SCDMV فقط على مستوى الولاية","تدريب سائق المستوى المبتدئ المعتمد من FMCSA (ELDT) من مزود مسجل","تدريب مهني لمدة 160 ساعة مسجل لدى SCDMV","لا يلزم تدريب، فقط اختبار المهارات"],"explanation":"تشترط ساوث كارولينا على المتقدمين الذين حصلوا على CLP في أو بعد Feb 7, 2022 إكمال تدريب سائق المستوى المبتدئ المعتمد من FMCSA (ELDT) من مزود مدرج في سجل مزودي التدريب لـ FMCSA قبل إجراء اختبار المهارات. المصدر: SCDMV، الحصول على أول CDL لك؛ قاعدة ELDT من FMCSA."},"33":{"q":"بموجب قاعدة ELDT الفيدرالية المطبقة في ساوث كارولينا، يُطلب ELDT لأول CDL ولأي مجموعة من التصديقات؟","options":["H (المواد الخطرة)، و P (الركاب)، و S (حافلة المدرسة)","N (الصهريج)، و T (المزدوجة/الثلاثية)، و H (المواد الخطرة)","P (الركاب)، و N (الصهريج)، و T (المزدوجة/الثلاثية)","جميع التصديقات الخمسة (H، N، T، P، S)"],"explanation":"يُطلب ELDT لرخصة CDL أولية من Class A أو B، ولترقية، ولتصديقات المواد الخطرة (H) والركاب (P) وحافلة المدرسة (S). ولا يُطلب لتصديق N (الصهريج) أو T (المزدوجة/الثلاثية). المصدر: قاعدة ELDT من FMCSA؛ SCDMV."},"34":{"q":"كم عدد فئات التصديق الذاتي الطبي التي يجب على المتقدم لرخصة CDL في ساوث كارولينا الاختيار من بينها عند التصديق على نوع التجارة التي يعمل فيها؟","options":["اثنتان","ثلاث","أربع","خمس"],"explanation":"تشترط القواعد الفيدرالية المعتمدة من قبل ساوث كارولينا على حاملي رخصة CDL التصديق الذاتي على إحدى الفئات الأربع: غير المستثناة بين الولايات، أو المستثناة بين الولايات، أو غير المستثناة داخل الولاية، أو المستثناة داخل الولاية. المصدر: SCDMV؛ 49 CFR 383.71."},"35":{"q":"السائق الحامل لرخصة CDL في ساوث كارولينا الذي ينقل البضائع عبر حدود الولايات ويجب أن يستوفي معايير الفحص الطبي الفيدرالي لـ DOT ينبغي أن يصدّق ذاتيًا في أي فئة؟","options":["المستثناة بين الولايات","غير المستثناة بين الولايات","غير المستثناة داخل الولاية","المستثناة داخل الولاية"],"explanation":"السائق الذي يعمل في التجارة بين الولايات والذي يخضع لمعايير التأهيل البدني الفيدرالية ويجب أن يستوفيها (49 CFR Part 391) يصدّق على أنه غير مستثنى بين الولايات ويجب أن يحتفظ بشهادة طبية صالحة من الفاحص الطبي. المصدر: SCDMV؛ 49 CFR 383.71."},"36":{"q":"أي مستند ليس من بين المستندات التي تشترط SCDMV على المتقدم لأول مرة لرخصة CDL تقديمها للتحقق من الهوية والضمان الاجتماعي والإقامة والوجود القانوني؟","options":["إثبات الهوية وتاريخ الميلاد","إثبات رقم الضمان الاجتماعي","إثباتان للإقامة في ساوث كارولينا","خطاب توظيف موقّع من شركة شحن"],"explanation":"تشترط SCDMV إثبات الهوية/الوجود القانوني، ورقم الضمان الاجتماعي، والإقامة في ساوث كارولينا (وفقًا لقائمة المستندات، مثل Form MV-93). وليس خطاب صاحب العمل مستندًا مطلوبًا للهوية/الإقامة. المصدر: قائمة مستندات SCDMV، الحصول على أول CDL لك."},"37":{"q":"في ساوث كارولينا، أي المتقدمين مؤهلون للتقدم بطلب للحصول على تصديق المواد الخطرة (H) لرخصة CDL؟","options":["أي حامل لرخصة CDL بغض النظر عن الجنسية","فقط المواطنون الأمريكيون والمقيمون الدائمون بشكل قانوني","فقط السائقون الذين تبلغ أعمارهم 25 عامًا فأكثر","فقط السائقون الذين يحملون بالفعل التصديق المجمّع X"],"explanation":"بسبب تقييم التهديد الأمني من TSA، فإن المواطنين الأمريكيين والمقيمين الدائمين بشكل قانوني فقط مؤهلون للحصول على تصديق المواد الخطرة (H) لرخصة CDL في ساوث كارولينا. المصدر: SCDMV؛ برنامج HME من TSA (49 CFR 1572)."},"38":{"q":"أي التصديقات يمكن للسائق في ساوث كارولينا الحصول عليها وهو لا يزال يحمل فقط تصريح المتعلم التجاري (CLP)؟","options":["H (المواد الخطرة) و T (المزدوجة/الثلاثية) فقط","N (الصهريج)، و P (الركاب)، و S (حافلة المدرسة) فقط","جميع التصديقات الخمسة","لا شيء - لا يُسمح بأي تصديقات على CLP"],"explanation":"يجوز أن يحمل CLP في ساوث كارولينا فقط تصديقات N (الصهريج، مقيدة بالصهاريج الفارغة)، و P (الركاب، بدون ركاب باستثناء المدربين/الممتحنين)، و S (حافلة المدرسة). ولا يمكن حمل تصديقي H و T على CLP. المصدر: SCDMV، الحصول على أول CDL لك؛ 49 CFR 383.25."},"39":{"q":"في ساوث كارولينا، ماذا يعني التصديق المجمّع 'X' على رخصة CDL؟","options":["الترخيص لكل من عمليات الصهريج (N) والمواد الخطرة (H)","الترخيص للمزدوجة/الثلاثية (T) والركاب (P)","قيد يحظر القيادة بين الولايات","شهادة مشغل حافلة مدرسية"],"explanation":"تصديق X هو رمز مجمّع يشير إلى أن السائق يحمل كلاً من تصديق الصهريج (N) وتصديق المواد الخطرة (H)، مما يسمح بنقل المواد الخطرة في مركبة صهريج. المصدر: الرخص التجارية من SCDMV؛ 49 CFR 383.153."},"40":{"q":"في ساوث كارولينا، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يكون عنده تشغيل مركبة آلية تجارية (CMV) قانونيًا؟","options":["أقل من 0.04%","أقل من 0.08%","أقل من 0.02%","أقل من 0.05%"],"explanation":"تتبع ساوث كارولينا المعيار الفيدرالي لـ CMV: من غير القانوني تشغيل CMV إذا كان BAC لديك 0.04% أو أكثر، لذا يتطلب التشغيل القانوني أن يكون BAC أقل من 0.04%. المصدر: دليل رخصة القيادة التجارية من SCDMV، القسم 1.3.2 (49 CFR 383.51)."},"41":{"q":"بموجب قاعدة الموافقة الضمنية في ساوث كارولينا لمشغلي CMV، ماذا يحدث إذا كان لدى السائق كمية قابلة للاكتشاف من الكحول أقل من 0.04%؟","options":["يوضع خارج الخدمة لمدة 24 ساعة","يُحرم لمدة 60 يومًا","يُحرم لمدة عام واحد","يُصدر له تحذير فقط دون اتخاذ أي إجراء"],"explanation":"تضع ساوث كارولينا سائق CMV خارج الخدمة لمدة 24 ساعة إذا تم العثور على أي كمية قابلة للاكتشاف من الكحول أقل من 0.04%. ويؤدي BAC بنسبة 0.04% أو أعلى إلى الحرمان بدلاً من ذلك. المصدر: دليل CDL من SCDMV، القسم 1.3.2."},"42":{"q":"من خلال تشغيل CMV في ساوث كارولينا، يُعتبر السائق تلقائيًا أنه قام بماذا فيما يتعلق بالفحص الكيميائي؟","options":["أعطى موافقته على فحص الكحول","تنازل عن الحق في جلسة استماع","وافق على فحص المخدرات السنوي","وافق على تفتيش المركبة"],"explanation":"بموجب الموافقة الضمنية، يُعتبر أي شخص يشغّل CMV في ساوث كارولينا أنه أعطى موافقته على فحص الكحول. المصدر: دليل CDL من SCDMV، القسم 1.3.2."},"43":{"q":"ما هو الحد الأدنى لفترة الحرمان في ساوث كارولينا لأول مخالفة كبرى لسائق CMV، مثل القيادة تحت تأثير الكحول (DUI) أو قيادة CMV بمعدل BAC يبلغ 0.04% أو أعلى؟","options":["1 year","60 days","6 months","3 years"],"explanation":"تحمل أول مخالفة كبرى (DUI، أو BAC بنسبة 0.04%+ في CMV، أو رفض الفحص، أو ترك مكان الحادث، إلخ) حدًا أدنى للحرمان لا يقل عن عام واحد في ساوث كارولينا. المصدر: دليل CDL من SCDMV، القسم 1.3.2 (49 CFR 383.51)."},"44":{"q":"في ساوث كارولينا، إذا وقعت مخالفة كبرى (مثل DUI) أثناء تشغيل السائق لـ CMV تحمل لافتات للمواد الخطرة، فما هو الحد الأدنى لفترة الحرمان؟","options":["3 years","1 year","5 years","18 months"],"explanation":"ترفع ساوث كارولينا حرمان المخالفة الأولى إلى ثلاث سنوات على الأقل عندما تقع المخالفة الكبرى أثناء تشغيل CMV تحمل لافتات للمواد الخطرة. المصدر: دليل CDL من SCDMV، القسم 1.3.2 (49 CFR 383.51)."},"45":{"q":"ما هي فترة الحرمان في ساوث كارولينا لثاني مخالفة كبرى لسائق CMV؟","options":["مدى الحياة","10 years","5 years","3 years"],"explanation":"تؤدي ثاني مخالفة كبرى إلى فقدان رخصة CDL مدى الحياة في ساوث كارولينا. المصدر: دليل CDL من SCDMV، القسم 1.3.2 (49 CFR 383.51)."},"46":{"q":"في ساوث كارولينا، يُعامل رفض الخضوع لفحص الكحول في الدم كمشغّل لـ CMV على أنه أي نوع من المخالفات لأغراض الحرمان؟","options":["مخالفة كبرى (سنة واحدة على الأقل)","مخالفة مرورية خطيرة (60 يومًا)","مخالفة الخروج من الخدمة (90 يومًا)","مخالفة بسيطة دون حرمان"],"explanation":"يُدرج رفض الخضوع لفحص الكحول في الدم كمخالفة كبرى في ساوث كارولينا ويحمل حدًا أدنى للحرمان لمدة عام واحد للمخالفة الأولى، تمامًا مثل DUI. المصدر: دليل CDL من SCDMV، القسم 1.3.2."},"47":{"q":"بموجب قواعد ساوث كارولينا، يفقد سائق CMV رخصة CDL مدى الحياة لأول مخالفة إذا استُخدمت CMV لارتكاب أي نوع من الجرائم؟","options":["جناية تتعلق بالمواد الخاضعة للرقابة","أي جناية من أي نوع","جناية تتعلق بالسرقة","القيادة المتهورة التي تسبب إصابة"],"explanation":"يؤدي استخدام CMV لارتكاب جناية تتعلق بالمواد الخاضعة للرقابة إلى الحرمان مدى الحياة في المخالفة الأولى، دون إمكانية إعادة التأهيل بعد 10 سنوات المتاحة لحالات الحرمان مدى الحياة الأخرى. المصدر: دليل CDL من SCDMV، القسم 1.3.2."},"48":{"q":"في ساوث كارولينا، ما مدى السرعة التي يجب أن يتجاوز بها سائق CMV حد السرعة المعلن لكي تُحتسب المخالفة على أنها نوع 'السرعة المفرطة' من المخالفات المرورية الخطيرة؟","options":["15 mph أو أكثر فوق الحد","10 mph أو أكثر فوق الحد","20 mph أو أكثر فوق الحد","5 mph أو أكثر فوق الحد"],"explanation":"تُعرّف ساوث كارولينا السرعة المفرطة على أنها مخالفة مرورية خطيرة عندما يكون السائق 15 mph أو أكثر فوق حد السرعة المعلن. المصدر: دليل CDL من SCDMV، القسم 1.3.3."},"49":{"q":"أي مما يلي يُصنف على أنه مخالفة مرورية خطيرة لسائق CMV في ساوث كارولينا؟","options":["تغيير المسارات بشكل غير سليم أو غير منتظم","القيادة بمعدل BAC يبلغ 0.04% أو أعلى","رفض فحص كيميائي","انتهاك أمر الخروج من الخدمة"],"explanation":"تشمل المخالفات المرورية الخطيرة السرعة المفرطة (15+ mph فوق الحد)، والقيادة المتهورة، وتغيير المسارات بشكل غير سليم أو غير منتظم، والاقتراب الشديد من المركبة الأمامية، وبعض مخالفات حيازة CDL. والخيارات الأخرى هي مخالفات كبرى أو مخالفات الخروج من الخدمة. المصدر: دليل CDL من SCDMV، القسم 1.3.3."},"50":{"q":"في ساوث كارولينا، ما هو الحد الأدنى للحرمان لارتكاب مخالفتين مروريتين خطيرتين في CMV خلال فترة ثلاث سنوات؟","options":["60 days","30 days","120 days","90 days"],"explanation":"تؤدي مخالفتان مروريتان خطيرتان خلال ثلاث سنوات تشملان CMV إلى حرمان لا يقل عن 60 يومًا. المصدر: دليل CDL من SCDMV، القسم 1.3.3 (49 CFR 383.51)."},"51":{"q":"في ساوث كارولينا، ما هو الحد الأدنى للحرمان لثلاث مخالفات مرورية خطيرة أو أكثر في CMV خلال فترة ثلاث سنوات؟","options":["120 days","60 days","180 days","1 year"],"explanation":"تؤدي ثلاث مخالفات مرورية خطيرة أو أكثر خلال ثلاث سنوات تشمل CMV إلى حرمان لا يقل عن 120 يومًا. المصدر: دليل CDL من SCDMV، القسم 1.3.3 (49 CFR 383.51)."},"52":{"q":"ما هو الحد الأدنى للحرمان في ساوث كارولينا لأول انتهاك من السائق لأمر الخروج من الخدمة؟","options":["90 days","60 days","180 days","1 year"],"explanation":"يحمل أول انتهاك لأمر الخروج من الخدمة حدًا أدنى للحرمان لمدة 90 يومًا في ساوث كارولينا. المصدر: دليل CDL من SCDMV، القسم 1.3.4 (49 CFR 383.51)."},"53":{"q":"في ساوث كارولينا، ما هو الحد الأدنى للحرمان لثاني انتهاك لأمر الخروج من الخدمة خلال فترة عشر سنوات؟","options":["1 year","90 days","120 days","3 years"],"explanation":"يؤدي ثاني انتهاك لأمر الخروج من الخدمة خلال فترة عشر سنوات إلى حرمان لا يقل عن عام واحد. المصدر: دليل CDL من SCDMV، القسم 1.3.4."},"54":{"q":"في ساوث كارولينا، ما هو الحد الأدنى للحرمان لثلاثة انتهاكات أو أكثر لأمر الخروج من الخدمة خلال فترة عشر سنوات؟","options":["3 years","1 year","5 years","مدى الحياة"],"explanation":"تؤدي ثلاثة انتهاكات أو أكثر لأمر الخروج من الخدمة خلال فترة عشر سنوات إلى حرمان لا يقل عن ثلاث سنوات. المصدر: دليل CDL من SCDMV، القسم 1.3.4."},"55":{"q":"ما هو الحد الأدنى للحرمان في ساوث كارولينا لأول مخالفة لسائق CMV عند تقاطع السكك الحديدية مع الطريق السريع؟","options":["60 days","90 days","30 days","120 days"],"explanation":"تؤدي أول مخالفة عند تقاطع السكك الحديدية مع الطريق السريع إلى حرمان لا يقل عن 60 يومًا في ساوث كارولينا. المصدر: دليل CDL من SCDMV، القسم 1.3.5 (49 CFR 383.51)."},"56":{"q":"في ساوث كارولينا، ما هو الحد الأدنى للحرمان لثاني مخالفة عند تقاطع السكك الحديدية مع الطريق السريع خلال فترة ثلاث سنوات؟","options":["120 days","60 days","90 days","1 year"],"explanation":"تؤدي ثاني مخالفة عند تقاطع السكك الحديدية مع الطريق السريع خلال ثلاث سنوات إلى حرمان لا يقل عن 120 يومًا. المصدر: دليل CDL من SCDMV، القسم 1.3.5."},"57":{"q":"في ساوث كارولينا، ما هو الحد الأدنى للحرمان لثالث مخالفة عند تقاطع السكك الحديدية مع الطريق السريع خلال فترة ثلاث سنوات؟","options":["1 year","120 days","180 days","3 years"],"explanation":"تؤدي ثالث مخالفة عند تقاطع السكك الحديدية مع الطريق السريع خلال ثلاث سنوات إلى حرمان لا يقل عن عام واحد. المصدر: دليل CDL من SCDMV، القسم 1.3.5."},"58":{"q":"بموجب قواعد ساوث كارولينا، يُحرم سائق CMV من رخصة CDL لمدة كم بعد الإدانة الثانية خلال ثلاث سنوات بتهمة إرسال الرسائل النصية أثناء تشغيل CMV؟","options":["60 days","30 days","120 days","1 year"],"explanation":"تؤدي إدانتان أو أكثر بتهمة إرسال الرسائل النصية أثناء تشغيل CMV إلى الحرمان: 60 يومًا للمخالفة الثانية خلال ثلاث سنوات و 120 يومًا لثلاث مخالفات أو أكثر خلال ثلاث سنوات. كما يواجه السائقون عقوبات مدنية تصل إلى $2,750. المصدر: دليل CDL من SCDMV، القسمان 2.9.6 و 2.9.5."},"59":{"q":"بموجب قانون القيادة بدون استخدام اليدين والقيادة المشتتة في ساوث كارولينا، ما هي الغرامة لأول مخالفة لحمل جهاز محمول أثناء القيادة؟","options":["$100 بالإضافة إلى رسوم المحكمة","$25 بالإضافة إلى رسوم المحكمة","$200 بالإضافة إلى رسوم المحكمة","$500 بالإضافة إلى رسوم المحكمة"],"explanation":"يحدد قانون القيادة بدون استخدام اليدين والقيادة المشتتة في ساوث كارولينا (S.C. Code Section 56-5-3890) غرامة قدرها $100 بالإضافة إلى رسوم المحكمة لأول مخالفة و $200 بالإضافة إلى نقطتين للمخالفة الثانية خلال ثلاث سنوات؛ وبالنسبة لسائقي CMV، تؤدي إدانتان خلال ثلاث سنوات أيضًا إلى حرمان لمدة 60 يومًا. المصدر: Hands Free SC من SCDPS؛ S.C. Code 56-5-3890."},"60":{"q":"على طريق سريع بين الولايات في ساوث كارولينا، ما هو الحد الأقصى للسرعة المسموح بها لشاحنة تجارية إذا لم يكن هناك حد أدنى منصوب بخلاف ذلك؟","options":["65 mph، لأن الشاحنات لها حد أقل من السيارات","70 mph، وهو نفس الحد المطبق على المركبات الأخرى","60 mph على جميع أقسام الطريق السريع بين الولايات","55 mph لأي مركبة يزيد وزنها عن 26,001 lbs"],"explanation":"ساوث كارولينا لا تحدد حداً منفصلاً وأقل لسرعة الشاحنات. بموجب S.C. Code 56-5-1520، الحد الأقصى على نظام الطرق السريعة بين الولايات هو 70 mph، وتخضع الشاحنات الكبيرة لنفس الحد المنصوب. المصدر: S.C. Code 56-5-1520؛ دليل CDL الخاص بـ SCDMV."},"61":{"q":"بموجب قانون ساوث كارولينا، ما هو الحد الأقصى للسرعة على طريق رئيسي مقسّم متعدد الحارات (وليس طريقاً سريعاً بين الولايات) ما لم يُنصب خلاف ذلك؟","options":["55 mph","65 mph","60 mph","70 mph"],"explanation":"يحدد S.C. Code 56-5-1520 سرعة 60 mph كحد أقصى على الطرق الرئيسية المقسّمة متعددة الحارات، و70 mph على نظام الطرق السريعة بين الولايات، و55 mph على الطرق الأخرى (غير المقسّمة). المصدر: S.C. Code 56-5-1520."},"62":{"q":"قانون 'التنحّي جانباً' (Move Over) في ساوث كارولينا (S.C. Code 56-5-1538) يُلزم السائق الذي يقترب من مركبة طوارئ متوقفة تعرض أضواءً وامضة بأن يفعل ماذا أولاً، إذا كان ذلك ممكناً بأمان؟","options":["التوقف توقفاً كاملاً حتى تغادر مركبة الطوارئ","إخلاء الحارة الأقرب إلى مركبة الطوارئ بالانتقال إلى حارة غير متاخمة","إطلاق المنبّه والاستمرار بالسرعة المنصوبة","التوجّه إلى الكتف خلف مركبة الطوارئ"],"explanation":"بموجب S.C. Code 56-5-1538، يجب على السائق أن يفسح المجال بالانتقال إلى حارة غير متاخمة لمركبة الطوارئ المرخّصة المتوقفة (سيارة إسعاف، شرطة، إطفاء، إنقاذ، استرداد، أو مركبة قطر) عندما يكون من الآمن فعل ذلك. المصدر: S.C. Code 56-5-1538؛ SCDPS."},"63":{"q":"بموجب قانون Move Over في ساوث كارولينا، ماذا يجب على السائق أن يفعل إذا كان تغيير الحارة بعيداً عن مركبة طوارئ متوقفة غير ممكن أو غير آمن؟","options":["التوقف توقفاً كاملاً في الحارة الحالية","الحفاظ على السرعة المنصوبة مع تشغيل أضواء التحذير الرباعية","المتابعة بحذر وتخفيض السرعة بشكل كبير","الخروج عند أقرب منحدر وسلوك طريق بديل"],"explanation":"يُلزم S.C. Code 56-5-1538 السائق الذي لا يستطيع تغيير الحارة بأمان بأن يتابع بحذر واجب وأن يخفّض سرعة المركبة بشكل كبير، مع الحفاظ على سرعة آمنة وفق ظروف الطريق. المصدر: S.C. Code 56-5-1538؛ SCDPS."},"64":{"q":"عندما تتوقف مركبة تحمل لافتات (placarded) عند معبر سكة حديدية في ساوث كارولينا، أين يجب أن تتوقف بالنسبة لأقرب قضيب سكة؟","options":["بين 15 و50 قدماً من أقرب قضيب سكة","بين 10 و25 قدماً من أقرب قضيب سكة","بين 50 و100 قدم من أقرب قضيب سكة","ضمن 15 قدماً من أقرب قضيب سكة"],"explanation":"يُلزم دليل CDL الخاص بـ SCDMV وS.C. Code 56-5-2720 المركبة التي تحمل لافتات بأن تتوقف ضمن مسافة 50 قدماً ولكن ليس أقل من 15 قدماً من أقرب قضيب سكة. المصدر: SCDMV CDL Manual 9.6.12؛ S.C. Code 56-5-2720."},"65":{"q":"أي من المركبات التالية يجب أن تتوقف دائماً عند كل معبر سكة حديدية في ساوث كارولينا (ما لم يكن المعبر معفى)؟","options":["شاحنة قلّابة محمّلة","حافلة تقلّ ركاباً","مقطورة مسطّحة فارغة","بيك أب يجرّ مقطورة خدمات"],"explanation":"يجب على الحافلة التي تنقل ركاباً، والحافلة المدرسية، وأي مركبة تحمل لافتات/شحنة خطرة أن تتوقف عند كل معبر سكة حديدية (15 إلى 50 قدماً من أقرب قضيب سكة) وأن تنظر وتستمع. المصدر: دليل CDL الخاص بـ SCDMV؛ S.C. Code 56-5-2720."},"66":{"q":"أثناء عبور أي جزء من مركبتك التجارية لقضبان السكة الحديدية في ساوث كارولينا، يوجّهك دليل CDL بأن لا تفعل أياً مما يلي؟","options":["إبقاء يديك على المقود","النظر في كلا الاتجاهين على طول السكة","تبديل أو تغيير التروس","مراقبة قطار ثانٍ"],"explanation":"ينص دليل CDL الخاص بـ SCDMV على: لا تتوقف، أو تغيّر التروس، أو تغيّر الحارة أثناء عبور أي جزء من مركبتك للقضبان. اختر تُرساً يتيح لك تجاوز القضبان دون تبديل. المصدر: SCDMV CDL Manual 2.15.4 / 13.1.8."},"67":{"q":"في ساوث كارولينا، لا يُلزَم السائق الذي يقابل حافلة مدرسية متوقفة تعرض أضواءً حمراء وامضة بالتوقف عند سيره في الاتجاه المعاكس على أي نوع من الطرق؟","options":["أي طريق بحارتين فيه حارة انعطاف وسطى","طريق سريع متعدد الحارات","أي طريق بحد منصوب يتجاوز 45 mph","طريق بشريط فاصل مرسوم (غير مرتفع)"],"explanation":"بموجب S.C. Code 56-5-2770، لا يحتاج السائق إلى التوقف عند مقابلته حافلة مدرسية متوقفة أثناء سيره في الاتجاه المعاكس على طريق سريع متعدد الحارات. أما السائقون في الاتجاه نفسه، وعلى الطرق ذات الحارتين، فيجب عليهم التوقف. المصدر: S.C. Code 56-5-2770."},"68":{"q":"السائق الذي يسير في الاتجاه نفسه خلف حافلة مدرسية في ساوث كارولينا قامت بتفعيل أضوائها الحمراء الوامضة وذراع التوقف، ماذا يجب أن يفعل؟","options":["التباطؤ إلى 15 mph والتجاوز بحذر","التوقف والبقاء متوقفاً حتى تتحرك الحافلة أو تتوقف الأضواء الحمراء عن الوميض","التجاوز من اليسار فقط إذا لم يكن هناك أطفال ظاهرون","التوقف فقط إذا كانت الحافلة على طريق غير مقسّم بحارتين"],"explanation":"يُلزم S.C. Code 56-5-2770 المركبة المقتربة من أي من الاتجاهين (باستثناء حالة الاتجاه المعاكس متعدد الحارات) بأن تتوقف قبل بلوغها حافلة مدرسية بأضواء حمراء وامضة، وألا تتابع حتى تستأنف الحافلة حركتها أو لم تعد الأضواء الحمراء مفعّلة. المصدر: S.C. Code 56-5-2770."},"69":{"q":"عندما تتوقف مركبة تجارية (CMV) على طريق بحارتين يحمل المرور في كلا الاتجاهين في ساوث كارولينا، أين ينبغي وضع مثلثات التحذير الثلاثة؟","options":["الثلاثة جميعها ضمن 10 أقدام من مؤخرة المركبة","ضمن 10 أقدام من المركبة، بالإضافة إلى 100 قدم خلفها و100 قدم أمامها","10 أقدام، و200 قدم، و500 قدم خلف المركبة","واحد عند المركبة واثنان جنباً إلى جنب على بعد 50 قدماً خلفها"],"explanation":"على طريق ثنائي الاتجاه/غير مقسّم، يوجّه دليل CDL الخاص بـ SCDMV بوضع مثلث واحد ضمن 10 أقدام من الأمام أو الخلف، وواحد على بعد 100 قدم خلف المركبة وواحد على بعد 100 قدم أمامها. المصدر: SCDMV CDL Manual 2.5 (أجهزة التحذير)."},"70":{"q":"عندما تتوقف مركبة تجارية (CMV) على طريق باتجاه واحد أو طريق مقسّم في ساوث كارولينا، على أي مسافات يجب وضع أجهزة التحذير باتجاه المرور المقترب؟","options":["10 أقدام، و100 قدم، و200 قدم","10 أقدام، و50 قدماً، و100 قدم","25 قدماً، و100 قدم، و300 قدم","100 قدم، و200 قدم، و300 قدم"],"explanation":"على طريق باتجاه واحد أو طريق مقسّم، يوجّه دليل CDL الخاص بـ SCDMV بوضع المثلثات العاكسة الثلاثة على بعد 10 أقدام، و100 قدم، و200 قدم باتجاه المرور المقترب. المصدر: SCDMV CDL Manual 2.5."},"71":{"q":"بعد التوقف على كتف طريق سريع في ساوث كارولينا، خلال كم دقيقة يجب على سائق المركبة التجارية (CMV) وضع أجهزة التحذير من الطوارئ؟","options":["5 دقائق","10 دقائق","15 دقيقة","30 دقيقة"],"explanation":"ينص دليل CDL الخاص بـ SCDMV على أنه إذا اضطررت للتوقف على طريق أو كتف فيجب عليك وضع أجهزة التحذير من الطوارئ خلال 10 دقائق. المصدر: SCDMV CDL Manual 2.5."},"72":{"q":"قانون الحارة اليسرى ('التحرّك يميناً' Move Right) في ساوث كارولينا للطرق ذات الوصول المتحكَّم به يقيّد عموماً استخدام أقصى الحارة اليسرى لأي غرض؟","options":["المركبات التي تسير عند الحد المنصوب أو فوقه","تجاوز ومرور مركبة أخرى","المركبات التي يقل وزنها عن 10,000 lbs فقط","مركبات النقل المشترك ومركبات النقل العام"],"explanation":"بموجب S.C. Code 56-5-1885، يجوز للسائقين استخدام أقصى الحارة اليسرى لطريق ذي وصول متحكَّم به فقط عند التجاوز والمرور. المصدر: S.C. Code 56-5-1885؛ قانون Move Right الخاص بـ SCDPS."},"73":{"q":"يمنح قانون الحارة اليسرى في ساوث كارولينا استثناءً محدداً للمركبة التجارية التي لا تستطيع الخروج من الحارة اليسرى بأمان بسبب أي ظرف؟","options":["وجود راكب نائم في حجيرة النوم","انحدار في الطريق، أو مركبة أخرى تتجاوز من اليمين","حملها لافتة مواد خطرة","التشغيل ليلاً مع انخفاض الرؤية"],"explanation":"بموجب S.C. Code 56-5-1885، يُعفى سائق المركبة التجارية من قيد الحارة اليسرى عندما يتعذّر عليه الاندماج يميناً بأمان بسبب انحدار في الطريق أو لأن مركبة أخرى تتجاوزه/تمرّ من اليمين. المصدر: S.C. Code 56-5-1885؛ SCDPS."},"74":{"q":"أثناء قيادتك حافلة في ساوث كارولينا، تقترب من جسر متحرك ليس فيه إشارة ضوئية ولا مراقب لتنظيم المرور. ماذا يجب أن تفعل؟","options":["العبور بسرعة مخفّضة دون توقف","التوقف على بعد 50 قدماً على الأقل قبل الجزء المتحرك والتأكد من أنه مغلق تماماً","التوقف على بعد 15 إلى 50 قدماً قبل الجزء المتحرك","التوقف فقط إذا كان جرس التحذير يرنّ"],"explanation":"يوجّه دليل CDL الخاص بـ SCDMV (4.3.6) سائقي الحافلات بالتوقف عند الجسور المتحركة التي ليس فيها إشارة ضوئية أو مراقب، بالتوقف على بعد 50 قدماً على الأقل قبل الجزء المتحرك والتأكد من أنه مغلق تماماً قبل العبور. المصدر: SCDMV CDL Manual 4.3.6."},"75":{"q":"أي قائمة مخالفات تُفعّل أول إيقاف لرخصة CDL في ساوث كارولينا لمدة لا تقل عن 60 يوماً؟","options":["السير على مسافة قريبة جداً","مخالفة عند معبر سكة حديدية متقاطع مع طريق","مخالفة تجاوز وزن المحور","عدم عرض لافتة مطلوبة"],"explanation":"ينص دليل CDL الخاص بـ SCDMV على أن حامل رخصة CDL يفقد الرخصة لمدة لا تقل عن 60 يوماً عن أول مخالفة عند معبر سكة حديدية متقاطع مع طريق، و120 يوماً للمخالفة الثانية خلال ثلاث سنوات، وسنة واحدة للثالثة. المصدر: SCDMV CDL Manual 1.3.5؛ 49 CFR 383.51."},"76":{"q":"في ساوث كارولينا، ما هو الحد الأقصى القانوني المعياري لعرض (WIDTH) المركبة/الحمولة قبل أن يُطلب تصريح للأحجام الزائدة؟","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"الحد القانوني للعرض في ساوث كارولينا هو 8 feet 6 inches (102 inches)؛ والحمولات الأعرض من ذلك تتطلب تصريح أحجام زائدة من SCDOT. والحد القانوني الأقصى للارتفاع هو 13 feet 6 inches. المصدر: تصاريح SCDOT للأحجام/الأوزان الزائدة."},"77":{"q":"بدون تصريح، ما هو الحد الأقصى القانوني لارتفاع (HEIGHT) مركبة تجارية وحمولتها في ساوث كارولينا؟","options":["13 feet 6 inches","14 feet 0 inches","12 feet 6 inches","13 feet 0 inches"],"explanation":"الحد القانوني الأقصى للارتفاع في ساوث كارولينا هو 13 feet 6 inches؛ وأي شيء أعلى من ذلك يتطلب تصريح ارتفاع زائد من SCDOT ومراجعة لمسار السير من أجل خلوص الجسور العلوية. المصدر: تصاريح SCDOT للأحجام/الأوزان الزائدة."},"78":{"q":"بموجب قواعد تصاريح SCDOT، يُسمح عموماً لحمولات الأحجام الزائدة في ساوث كارولينا بالتحرك خلال أي أوقات؟","options":["24 ساعة في اليوم، أي يوم","من نصف ساعة بعد شروق الشمس إلى نصف ساعة قبل غروبها، من الإثنين إلى السبت","فقط بين الساعة 9 مساءً و5 صباحاً لتجنّب الزحام","أيام الأسبوع فقط، دون السماح بأي تحرك يوم السبت"],"explanation":"تقيّد SCDOT عموماً حركة حمولات الأحجام الزائدة إلى الفترة من نصف ساعة بعد شروق الشمس إلى نصف ساعة قبل غروبها، من الإثنين إلى السبت، دون سفر يوم الأحد أو في العطلات المحددة، مع قيود إضافية للحمولات شديدة العرض. المصدر: تصاريح SCDOT للأحجام/الأوزان الزائدة."},"79":{"q":"السائق الذي يتجاوز بشكل غير قانوني حافلة مدرسية متوقفة في ساوث كارولينا، والمركبة التي تقترب من مركبة طوارئ متوقفة بموجب قانون Move Over، كلاهما يخضع لعقوبات. أي عبارة صحيحة بشأن مخالفة قانون Move Over؟","options":["إنها مجرد غرامة مدنية قدرها $25 دون رسوم محكمة","إنها جنحة تحمل غرامة في نطاق $300 إلى $500","إنها تحمل إيقافاً تلقائياً لرخصة CDL مدى الحياة","إنها مخالفة بإنذار فقط خلال السنة الأولى"],"explanation":"تُعد مخالفة قانون Move Over في ساوث كارولينا (S.C. Code 56-5-1538) جنحة يُعاقب عليها بغرامة في نطاق $300-$500 عموماً؛ في المقابل، مخالفة الحارة اليسرى 'Move Right' (56-5-1885) هي غرامة مدنية قدرها $25. المصدر: S.C. Code 56-5-1538؛ SCDPS."},"80":{"q":"أي جهة تُصدر رخص القيادة التجارية (CDLs) في ساوث كارولينا؟","options":["دائرة المركبات الآلية في ساوث كارولينا (SCDMV)","دائرة النقل في ساوث كارولينا (SCDOT)","الإدارة الفيدرالية لسلامة الناقلين بالشاحنات (FMCSA)","دورية الطرق السريعة في ساوث كارولينا"],"explanation":"تُصدر رخص CDL في ساوث كارولينا من قبل دائرة المركبات الآلية في ساوث كارولينا (SCDMV). تضع FMCSA المعايير الفيدرالية لرخص CDL لكنها لا تُصدر الرخصة؛ وتتولى SCDOT الطرق/التصاريح وليس إصدار الرخص. المصدر: صفحة الرخص التجارية لـ SCDMV (dmv.sc.gov)."},"81":{"q":"في ساوث كارولينا، ما هو النموذج المعياري المستخدم للتقديم على تصريح المتعلّم التجاري (CLP) أو رخصة CDL؟","options":["نموذج SCDMV Form 447-CDL","نموذج SCDMV Form DL-405A","نموذج SCDMV Form MV-93","نموذج FMCSA Form MCSA-5876"],"explanation":"نموذج التقديم على CLP وCDL في ساوث كارولينا هو SCDMV Form 447-CDL. وDL-405A هو نموذج التصديق الذاتي الطبي، وMV-93 هو قائمة التحقق من وثائق الهوية، وMCSA-5876 هو شهادة الفاحص الطبي الفيدرالية. المصدر: SCDMV Getting Your First CDL (dmv.sc.gov)."},"82":{"q":"كم تبلغ مدة صلاحية تصريح المتعلّم التجاري (CLP) في ساوث كارولينا قبل انتهائه؟","options":["سنة واحدة","180 يوماً","ستة أشهر","سنتان"],"explanation":"في ساوث كارولينا يحمل تصريح CLP تاريخ انتهاء بعد سنة واحدة. المصدر: SCDMV Getting Your First CDL (dmv.sc.gov). (تسمح القاعدة الفيدرالية بتصريح CLP صالح لمدة تصل إلى سنة واحدة، وهو ما تطبّقه ساوث كارولينا.)"},"83":{"q":"بعد إصدار تصريح المتعلّم التجاري في ساوث كارولينا، كم يجب أن تحتفظ به قبل أن تصبح مؤهلاً لاجتياز اختبار مهارات CDL؟","options":["14 يوماً على الأقل","30 يوماً على الأقل","10 أيام على الأقل","7 أيام على الأقل"],"explanation":"يجب أن تحتفظ بتصريح CLP لمدة لا تقل عن 14 يوماً قبل أن يحق لك اجتياز اختبار المهارات. المصدر: SCDMV Getting Your First CDL (dmv.sc.gov)؛ وهذا يماثل مدة الاحتفاظ الفيدرالية بـ CLP لمدة 14 يوماً (49 CFR 383.25)."},"84":{"q":"بموجب التصديق الذاتي لرخصة CDL في ساوث كارولينا، كم عدد فئات التشغيل التي يجب على السائق الاختيار منها؟","options":["أربع","اثنتان","ثلاث","خمس"],"explanation":"هناك أربع فئات للتصديق الذاتي: بين الولايات غير معفاة، بين الولايات معفاة، داخل الولاية غير معفاة، وداخل الولاية معفاة. يصدّق السائقون على فئتهم لدى SCDMV. المصدر: SCDMV / Form DL-405A (dmv.sc.gov)."},"85":{"q":"أي نموذج في ساوث كارولينا يُستخدم للتصديق الذاتي على نوع تجارتك وتقديم حالة التصديق الطبي إلى SCDMV؟","options":["Form DL-405A (التصديق الطبي لحامل CDL)","Form 447-CDL (طلب CDL)","Form MV-93 (قائمة تحقق المواطن)","Form MCSA-5875 (تقرير الفحص الطبي)"],"explanation":"تستخدم ساوث كارولينا Form DL-405A للتصديق الذاتي والتصديق الطبي لحامل CDL. وForm 447-CDL هو طلب الرخصة، وMV-93 قائمة التحقق من الهوية، وMCSA-5875 تقرير الفحص الفيدرالي. المصدر: SCDMV Renew or Upgrade Your CDL (dmv.sc.gov)."},"86":{"q":"أي فئة من فئات التصديق الذاتي تتطلب من حامل رخصة CDL في ساوث كارولينا تقديم شهادة فاحص طبي DOT سارية؟","options":["بين الولايات غير معفاة","بين الولايات معفاة","داخل الولاية معفاة","لا توجد فئة تتطلب شهادة طبية"],"explanation":"يجب على السائقين في فئة بين الولايات غير المعفاة الاحتفاظ بشهادة فاحص طبي DOT سارية تستوفي معايير FMCSA. أما السائقون في الفئات المعفاة فغير ملزمين بتقديمها. المصدر: SCDMV / Form DL-405A (dmv.sc.gov)؛ 49 CFR 391.41."},"87":{"q":"من المخوّل بإجراء الفحص البدني وإصدار شهادة الفاحص الطبي التي يجب أن يحملها سائق CDL في فئة غير معفاة في ساوث كارولينا؟","options":["مهني طبي مدرج في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA","أي طبيب مرخّص يختاره السائق","فاحص SCDMV في مكتب الفرع","طبيب معتمد من دائرة النقل في ساوث كارولينا"],"explanation":"يجب أن يُجري الفحص وتُصدر الشهادة من قبل مهني طبي مدرج في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA. المصدر: SCDMV Commercial Licenses (dmv.sc.gov)؛ 49 CFR 390.103."},"88":{"q":"قبل اجتياز اختبار مهارات CDL في ساوث كارولينا، أي شرط ينطبق على المتقدمين الذين حصلوا على تصريح CLP بعد 7 فبراير 2022؟","options":["إكمال برنامج تدريب السائقين للمستوى المبتدئ (ELDT) المعتمد من FMCSA","الاحتفاظ بسجل قيادة نظيف لمدة خمس سنوات متتالية","إكمال 160 ساعة من القيادة الفعلية مع SCDMV","اجتياز دورة قيادة دفاعية منفصلة من SCDMV"],"explanation":"يجب على المتقدمين الذين صدر تصريح CLP الخاص بهم بعد 7 فبراير 2022 إكمال برنامج ELDT معتمد من FMCSA مع مزوّد تدريب مسجّل قبل اجتياز اختبار المهارات. المصدر: SCDMV Getting Your First CDL (dmv.sc.gov)؛ 49 CFR Part 380 Subpart F."},"89":{"q":"ينقسم اختبار مهارات CDL في ساوث كارولينا إلى ثلاثة أجزاء. أي مجموعة تسرد تلك الأجزاء الثلاثة بشكل صحيح؟","options":["فحص ما قبل الرحلة، والتحكم الأساسي بالمركبة، والقيادة على الطريق","الاختبار النظري التحريري، وفحص النظر، والقيادة على الطريق","فحص ما قبل الرحلة، والمواد الخطرة، والقيادة الليلية","فحص الفرامل الهوائية، والركن الموازي، والاندماج في الطريق السريع"],"explanation":"يتكوّن اختبار مهارات CDL من ثلاثة مكوّنات: فحص ما قبل الرحلة، والتحكم الأساسي بالمركبة (خارج الطريق)، واختبار القيادة على الطريق. المصدر: SCDMV Getting Your First CDL (dmv.sc.gov)؛ 49 CFR 383.113."},"90":{"q":"ما هي مدة الصلاحية المعيارية لرخصة CDL في ساوث كارولينا قبل أن يلزم تجديدها؟","options":["8 سنوات","5 سنوات","4 سنوات","10 سنوات"],"explanation":"رخصة CDL في ساوث كارولينا صالحة لمدة 8 سنوات وتنتهي في عيد ميلاد حاملها في السنة الأخيرة من الدورة. المصدر: SCDMV (dmv.sc.gov). (يخضع تظهير HazMat لدورة تقييم تهديد أمني منفصلة من TSA مدتها 5 سنوات.)"},"91":{"q":"رخصة CDL في ساوث كارولينا التي تحمل تظهير المواد الخطرة (HazMat) مقيّدة بأي إطار زمني منفصل؟","options":["دورة تقييم التهديد الأمني من TSA ومدتها 5 سنوات","دورة تجديد خاصة بـ HazMat فقط مدتها سنتان","شهادة HazMat فيدرالية مدتها 10 سنوات","مراجعة HazMat من SCDMV مدتها سنة واحدة"],"explanation":"رغم أن رخصة CDL نفسها صالحة لمدة 8 سنوات، فإن تظهير HazMat مرتبط بتقييم التهديد الأمني من TSA، الذي يجب تجديده في دورة مدتها 5 سنوات. المصدر: SCDMV Commercial Licenses (dmv.sc.gov)؛ 49 CFR 1572."},"92":{"q":"متى يجب على حامل رخصة CDL في ساوث كارولينا تقديم إثبات الأهلية الطبية (التصديق الذاتي/الشهادة الطبية) إلى SCDMV؟","options":["في كل مرة يتقدم فيها لطلب الرخصة، أو يجددها، أو يرفع مستواها، أو يغيّر العنوان عليها، أو يستخرج نسخة منها","مرة واحدة فقط، عند الحصول على CDL لأول مرة","فقط عند التجديد بعد 8 سنوات","فقط عند إضافة تظهير HazMat"],"explanation":"يجب على السائقين تقديم إثبات الأهلية الطبية في كل مرة يتقدمون فيها لطلب CLP/CDL، أو يرفعون مستواها، أو يجددونها، أو يغيّرون العنوان، أو يطلبون نسخة. المصدر: SCDMV Commercial Licenses (dmv.sc.gov)."},"93":{"q":"ما هو الحد الأدنى للسن للحصول على رخصة CDL في ساوث كارولينا لقيادة مركبة تجارية داخل الولاية فقط (intrastate)؟","options":["18 عاماً","19 عاماً","21 عاماً","20 عاماً"],"explanation":"يجب أن يكون عمرك 18 عاماً على الأقل لحمل رخصة CDL للقيادة داخل ساوث كارولينا، و21 عاماً على الأقل للقيادة بين الولايات. المصدر: SCDMV Getting Your First CDL (dmv.sc.gov)."},"94":{"q":"ما هو الحد الأدنى للسن الذي تتطلبه ساوث كارولينا لتشغيل مركبة آلية تجارية في التجارة بين الولايات (عبر حدود الولايات)؟","options":["21 عاماً","18 عاماً","19 عاماً","25 عاماً"],"explanation":"يجب أن يكون عمر السائق 21 عاماً على الأقل لتشغيل مركبة تجارية في التجارة بين الولايات؛ وتقتصر الأعمار من 18 إلى 20 على التشغيل داخل الولاية. المصدر: SCDMV Getting Your First CDL (dmv.sc.gov)؛ 49 CFR 391.11."},"95":{"q":"كيف يتم عادةً التحقق من شهادة الفاحص الطبي لسائق بين الولايات غير معفى بعد تقديمها إلى SCDMV؟","options":["يتم التحقق منها إلكترونياً/تُسجّل في سجل القيادة","يجب توثيقها لدى كاتب عدل في فرع SCDMV","تُرسل بالبريد إلى FMCSA للموافقة اليدوية","يتم التحقق منها فقط من قبل الفاحص الطبي، وليس الولاية"],"explanation":"بالنسبة للسائقين غير المعفيين، يتم التحقق من معلومات الشهادة الطبية إلكترونياً وتُضاف الحالة الطبية إلى سجل قيادة CDL. المصدر: SCDMV Commercial Licenses (dmv.sc.gov)؛ 49 CFR 383.71/383.73."},"96":{"q":"قبل التقديم على رخصة CDL أو CLP، تتطلب ساوث كارولينا من المتقدم أن يكون حاملاً بالفعل لأي وثيقة؟","options":["رخصة قيادة سارية وغير منتهية من ساوث كارولينا","جواز سفر ساري","بطاقة TWIC فيدرالية","رخصة عمل تجارية من ساوث كارولينا"],"explanation":"يجب أن يحمل المتقدمون رخصة قيادة (عادية) سارية وغير منتهية من ساوث كارولينا قبل التقديم على CLP/CDL. المصدر: SCDMV Getting Your First CDL (dmv.sc.gov)."},"97":{"q":"عند تجديد رخصة CDL في ساوث كارولينا، أي عنصر يجب تقديمه بالإضافة إلى الطلب والتصديق الطبي/الذاتي؟","options":["معلومات تأمين المسؤولية على السيارة من شركة مرخّصة في ساوث كارولينا","إفادة موثّقة من صاحب العمل","إثبات إكمال دورة ELDT جديدة","فحص بصمات جديد من TSA لجميع التظهيرات"],"explanation":"تتطلب ساوث كارولينا معلومات تأمين المسؤولية على السيارة من شركة تأمين مرخّصة في الولاية عند تجديد CDL، إلى جانب Form 447-CDL وForm DL-405A للتصديق الطبي حسب الاقتضاء. المصدر: SCDMV Renew or Upgrade Your CDL (dmv.sc.gov)."},"98":{"q":"إذا ترك حامل رخصة CDL في ساوث كارولينا شهادة الفاحص الطبي المطلوبة فيدرالياً تنتهي بينما هو مصدّق كغير معفى، ما هي العاقبة على رخصة CDL؟","options":["تُخفّض رتبة رخصة CDL فتُفقد الامتيازات التجارية حتى تُودَع شهادة سارية في الملف","لا يتغيّر شيء حتى التجديد بعد 8 سنوات","تُلغى رخصة CDL نهائياً دون أي سبيل لإعادة الإصدار","يتأثر تظهير HazMat فقط"],"explanation":"عندما تنقضي شهادة سائق غير معفى الطبية أو لا تكون في الملف، يجب على الولاية تخفيض رتبة رخصة CDL (بإزالة امتيازات القيادة التجارية) حتى يُقدَّم شهادة سارية. المصدر: قواعد التصديق الطبي لـ SCDMV / FMCSA (dmv.sc.gov)؛ 49 CFR 383.73."},"99":{"q":"عند تجديد رخصة CDL في ساوث كارولينا، يجب عموماً إعادة تقديم التصديق الذاتي الطبي (Form DL-405A) في أي حالة؟","options":["إذا لم يكن قد قُدّم بالفعل أو إذا تغيّر نوع التجارة التي يتم تشغيلها","فقط إذا انتقل السائق إلى ولاية أخرى","فقط إذا كان عمر السائق فوق 65 عاماً","أبداً، لأنه إيداع لمرة واحدة"],"explanation":"تتطلب ساوث كارولينا التصديق الذاتي DL-405A عند التجديد إذا لم يكن قد قُدّم بالفعل أو إذا تغيّر نوع تجارة السائق (فئة التصديق الذاتي). المصدر: SCDMV Renew or Upgrade Your CDL (dmv.sc.gov)."}}};
